import { TILLY_FOOTLOOSE } from '../../data/mercenaries';
import { MONSTERS } from '../../data/monsters';

const generateManualGrid = (width: number, height: number, locked: boolean, dungeonId: string, knownMercs: any[]) => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));
    const visited: boolean[][] = Array.from({ length: height }, () => Array(width).fill(false));

    // 1. Entrance
    const startX = Math.floor(Math.random() * width);
    const startY = Math.floor(Math.random() * height);
    grid[startY][startX] = 'ENTRANCE';
    visited[startY][startX] = true;

    // 2. Boss
    let bossX, bossY;
    do {
        bossX = Math.floor(Math.random() * width);
        bossY = Math.floor(Math.random() * height);
    } while (Math.abs(bossX - startX) + Math.abs(bossY - startY) < 2);
    grid[bossY][bossX] = 'BOSS';

    // 3. Key (if locked)
    if (locked) {
        let keyX, keyY;
        do {
            keyX = Math.floor(Math.random() * width);
            keyY = Math.floor(Math.random() * height);
        } while (grid[keyY][keyX] !== 'EMPTY');
        grid[keyY][keyX] = 'KEY';
    }

    // 4. Hidden NPC (Tilly in Rat Cellar)
    if (dungeonId === 'dungeon_t1_rats' && !knownMercs.some(m => m.id === 'tilly_footloose')) {
        let npcX, npcY;
        do {
            npcX = Math.floor(Math.random() * width);
            npcY = Math.floor(Math.random() * height);
        } while (grid[npcY][npcX] !== 'EMPTY');
        grid[npcY][npcX] = 'NPC';
    }

    // 5. Random Gold Piles & Traps
    const totalTiles = width * height;
    const goldSpawnChance = 1 / totalTiles;
    const trapSpawnChance = 1 / totalTiles;

    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const roll = Math.random();
                if (roll < goldSpawnChance) {
                    grid[y][x] = 'GOLD';
                } else if (roll < goldSpawnChance + trapSpawnChance) {
                    grid[y][x] = 'TRAP';
                }
            }
        }
    }

    return { grid, visited, playerPos: { x: startX, y: startY } };
};

export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string, partyIds: string[] }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const { grid, visited, playerPos } = generateManualGrid(
        dungeon.gridWidth, 
        dungeon.gridHeight, 
        !!dungeon.isBossLocked,
        dungeon.id,
        state.knownMercenaries
    );

    let bossEntity = undefined;
    if (dungeon.id === 'dungeon_t1_rats') {
        bossEntity = { ...MONSTERS.plague_rat_king };
    }

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos,
        hasKey: false,
        isBossLocked: !!dungeon.isBossLocked,
        isBossDefeated: false,
        bossEntity,
        goldCollected: 0,
        encounterStatus: 'NONE'
    };

    const updatedMercenaries = state.knownMercenaries.map(m => {
        if (payload.partyIds.includes(m.id)) {
            return { ...m, status: 'ON_EXPEDITION' as const };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercenaries,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`Squad has entered ${dungeon.name}. Tread carefully.`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus === 'ENCOUNTERED' || session.encounterStatus === 'BATTLE') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) return state;

    const targetRoom = session.grid[newY][newX];
    const isAlreadyVisited = session.visited[newY][newX];

    const cost = isAlreadyVisited ? -1 : (targetRoom === 'BOSS' ? dungeon.bossEnergy : dungeon.moveEnergy);

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    const canMove = cost < 0 || party.every(m => (m.expeditionEnergy || 0) >= cost);

    if (!canMove) {
        return {
            ...state,
            logs: [`Your squad is too exhausted to move.`, ...state.logs]
        };
    }

    if (targetRoom === 'BOSS' && session.isBossLocked && !session.hasKey) {
        return {
            ...state,
            logs: [`The Boss chamber is sealed. You need a key.`, ...state.logs]
        };
    }

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextEnergy = Math.max(0, Math.min(100, (m.expeditionEnergy || 0) - cost));
            let nextHp = m.currentHp;
            if (targetRoom === 'TRAP' && !isAlreadyVisited) {
                nextHp = Math.max(0, m.currentHp - 25);
            }
            return { ...m, expeditionEnergy: nextEnergy, currentHp: nextHp };
        }
        return m;
    });

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let logMsg = '';
    let encounterStatus: ManualDungeonSession['encounterStatus'] = 'NONE';

    if (targetRoom === 'GOLD') {
        const tier = dungeon.tier || 1;
        const roll = Math.random();
        if (roll < 0.65) extraGold = tier * 25;
        else if (roll < 0.90) extraGold = tier * 50;
        else extraGold = tier * 75;
        newGrid[newY][newX] = 'EMPTY';
        logMsg = `Looted gold from the sector. (+${extraGold} G)`;
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        logMsg = `IT'S A TRAP! The squad took heavy damage. (-25 HP)`;
    } else if (targetRoom === 'KEY') {
        logMsg = `Found a rusted key!`;
        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'NPC' && !session.npcFound) {
        logMsg = `Spotted a survivor hiding in the shadows!`;
    } else if (targetRoom === 'BOSS' && !session.isBossDefeated) {
        encounterStatus = 'ENCOUNTERED';
        logMsg = `CRITICAL ALERT: Enemy signature detected. ${session.bossEntity?.name} is blocking the path.`;
    }

    const newSession: ManualDungeonSession = {
        ...session,
        grid: newGrid,
        playerPos: { x: newX, y: newY },
        visited: newVisited,
        hasKey: targetRoom === 'KEY' ? true : session.hasKey,
        encounterStatus,
        goldCollected: session.goldCollected + extraGold
    };

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: newSession,
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const dummyExpId = `manual_clear_${Date.now()}`;
    const tempState: GameState = {
        ...state,
        activeExpeditions: [{
            id: dummyExpId,
            dungeonId: session.dungeonId,
            partyIds: session.partyIds,
            startTime: Date.now(),
            endTime: Date.now(),
            status: 'COMPLETED' as const
        }]
    };

    const finalState = handleClaimExpedition(tempState, { 
        expeditionId: dummyExpId, 
        rescuedNpcId: session.rescuedNpcId 
    });

    const totalManualGold = session.goldCollected;

    return { 
        ...finalState, 
        stats: {
            ...finalState.stats,
            gold: finalState.stats.gold + totalManualGold,
            dailyFinancials: {
                ...finalState.stats.dailyFinancials,
                incomeDungeon: finalState.stats.dailyFinancials.incomeDungeon + totalManualGold
            }
        },
        dungeonResult: null, 
        activeManualDungeon: null, 
        showManualDungeonOverlay: false 
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    // 패배나 포기 시 용병 부상/사망 체크 로직
    const isDefeat = session.encounterStatus === 'DEFEAT';

    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextStatus: any = 'HIRED';
            if (isDefeat) {
                const roll = Math.random();
                if (roll < 0.15) nextStatus = 'DEAD';
                else if (roll < 0.6) nextStatus = 'INJURED';
            }
            return { ...m, status: nextStatus };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: [isDefeat ? 'CRITICAL FAILURE: The squad was overrun.' : 'The squad retreated from the area.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    if (state.knownMercenaries.some(m => m.id === payload.npcId)) return state;
    if (state.activeManualDungeon?.rescuedNpcId === payload.npcId) return state;

    const currentSession = state.activeManualDungeon;
    let newGrid = currentSession ? [...currentSession.grid.map(row => [...row])] : null;
    if (newGrid && currentSession) {
        newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';
    }

    const newSession = currentSession ? {
        ...currentSession,
        grid: newGrid as RoomType[][],
        npcFound: true,
        rescuedNpcId: payload.npcId
    } : null;

    return {
        ...state,
        activeManualDungeon: newSession,
        logs: [`Rescue initiated for survivor. Secure the objective to escort them out.`, ...state.logs]
    };
};

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';
import { ManualDungeonSession, RoomType } from '../types/game-state';

export type CameraMode = 'LOCKED' | 'ADAPTIVE' | 'FREE';

export interface DungeonSceneData {
    session: ManualDungeonSession;
    moveEnergy: number;
    bossEnergy: number;
    onMove: (dx: number, dy: number) => void;
    cameraMode: CameraMode;
}

export default class DungeonScene extends Phaser.Scene {
    public add!: Phaser.GameObjects.GameObjectFactory;
    public tweens!: Phaser.Tweens.TweenManager;
    public scale!: Phaser.Scale.ScaleManager;
    public cameras!: Phaser.Cameras.Scene2D.CameraManager;
    public input!: Phaser.Input.InputPlugin;
    public time!: Phaser.Time.Clock;
    public events!: Phaser.Events.EventEmitter;
    public load!: Phaser.Loader.LoaderPlugin;
    public textures!: Phaser.Textures.TextureManager;
    public anims!: Phaser.Animations.AnimationManager;

    private session!: ManualDungeonSession;
    private onMoveCallback!: (dx: number, dy: number) => void;
    private cameraMode: CameraMode = 'LOCKED';

    private root!: Phaser.GameObjects.Container;
    private mapLayer!: Phaser.GameObjects.Container;
    private contentLayer!: Phaser.GameObjects.Container;
    private playerLayer!: Phaser.GameObjects.Container;
    private fxLayer!: Phaser.GameObjects.Container;

    private playerMarker!: Phaser.GameObjects.Container;
    private revealedTiles: Set<string> = new Set();
    private contentByCoord: Map<string, Phaser.GameObjects.Text> = new Map();

    private sprayEmitter!: Phaser.GameObjects.Particles.ParticleEmitter;
    private vignette!: Phaser.GameObjects.Graphics;

    private tileWidth = 84;
    private tileGap = 8;
    private isMoving = false;

    private isDragging = false;
    private dragStartX = 0;
    private dragStartY = 0;

    private cameraTrackTimer: Phaser.Time.TimerEvent | null = null;
    private cameraTrackTween: Phaser.Tweens.Tween | null = null;

    constructor() {
        super('DungeonScene');
    }

    init(data: DungeonSceneData) {
        this.session = data.session;
        this.onMoveCallback = data.onMove;
        this.cameraMode = data.cameraMode ?? 'LOCKED';
    }

    preload() {
        this.load.image('sparkle', getAssetUrl('particle_spark1.png'));
        this.load.image('red_mist', getAssetUrl('particle_spark2.png'));
    }

    create() {
        this.cameras.main.setBackgroundColor(0x000000);

        this.root = this.add.container(0, 0);

        this.mapLayer = this.add.container(0, 0);
        this.contentLayer = this.add.container(0, 0);
        this.playerLayer = this.add.container(0, 0);
        this.fxLayer = this.add.container(0, 0).setDepth(100);

        this.root.add([this.mapLayer, this.contentLayer, this.playerLayer]);

        this.vignette = this.add.graphics().setDepth(200).setScrollFactor(0);

        this.sprayEmitter = this.add.particles(0, 0, 'sparkle', {
            speed: { min: 60, max: 140 },
            scale: { start: 0.6, end: 0 },
            alpha: { start: 1, end: 0 },
            lifespan: 800,
            gravityY: 80,
            blendMode: 'ADD',
            emitting: false
        });
        this.root.add(this.sprayEmitter);

        this.initialRender();
        this.createPlayer();
        this.alignViewToPlayer(); 

        this.scale.on('resize', () => {
            this.alignViewToPlayer();
            this.drawVignette();
        }, this);
        this.setupDragControls();

        this.drawVignette();
    }

    public setCameraMode(mode: CameraMode) {
        this.cameraMode = mode;
        if (mode === 'LOCKED' && !this.isMoving) {
            this.alignViewToPlayer(); 
        }
    }

    private drawVignette() {
        const { width, height } = this.scale;
        this.vignette.clear();

        const isEncountered = this.session.encounterStatus !== 'NONE' && this.session.encounterStatus !== 'VICTORY';
        if (!isEncountered) return;

        // 적 조우 시 붉은계열 스프레이 포커싱 효과
        this.vignette.fillStyle(0x7f1d1d, 0.3);

        // 외곽 영역을 가늘게 칠함 (포커싱 효과)
        const thickness = 40;
        this.vignette.fillRect(0, 0, width, thickness);
        this.vignette.fillRect(0, height - thickness, width, thickness);
        this.vignette.fillRect(0, thickness, thickness, height - (thickness * 2));
        this.vignette.fillRect(width - thickness, thickness, thickness, height - (thickness * 2));

        // 입자 효과 추가 (외곽선 주변)
        if (Math.random() > 0.8) {
            const side = Math.floor(Math.random() * 4);
            let rx, ry;
            if (side === 0) { rx = Math.random() * width; ry = 10; }
            else if (side === 1) { rx = Math.random() * width; ry = height - 10; }
            else if (side === 2) { rx = 10; ry = Math.random() * height; }
            else { rx = width - 10; ry = Math.random() * height; }

            this.add.particles(rx, ry, 'red_mist', {
                speed: { min: 20, max: 50 },
                scale: { start: 0.8, end: 0 },
                alpha: { start: 0.5, end: 0 },
                lifespan: 1500,
                tint: 0xef4444,
                blendMode: 'ADD'
            }).explode(5);
        }
    }

    private setupDragControls() {
        this.input.on('pointerdown', (pointer: Phaser.Input.Pointer) => {
            if (this.session.encounterStatus === 'BATTLE') return;
            this.isDragging = true;
            this.dragStartX = pointer.x - this.root.x;
            this.dragStartY = pointer.y - this.root.y;

            if (this.cameraTrackTween) {
                this.cameraTrackTween.stop();
                this.cameraTrackTween = null;
            }
            if (this.cameraTrackTimer) {
                this.cameraTrackTimer.remove();
                this.cameraTrackTimer = null;
            }
        });

        this.input.on('pointermove', (pointer: Phaser.Input.Pointer) => {
            if (!this.isDragging) return;
            this.root.setPosition(pointer.x - this.dragStartX, pointer.y - this.dragStartY);
        });

        this.input.on('pointerup', () => {
            this.isDragging = false;
        });

        this.input.on('pointerout', () => {
            this.isDragging = false;
        });
    }

    private initialRender() {
        const { grid, visited } = this.session;
        const rows = grid.length;
        const cols = grid[0].length;

        this.mapLayer.removeAll(true);
        this.contentLayer.removeAll(true);
        this.revealedTiles.clear();
        this.contentByCoord.clear();

        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
                if (visited[y][x]) {
                    this.drawRevealedTile(x, y, grid[y][x], false);
                }
            }
        }
    }

    private drawRevealedTile(x: number, y: number, type: RoomType, animate: boolean) {
        const key = `${x},${y}`;
        const tx = x * (this.tileWidth + this.tileGap);
        const ty = y * (this.tileWidth + this.tileGap);

        if (!this.revealedTiles.has(key)) {
            const tile = this.add.rectangle(tx, ty, this.tileWidth, this.tileWidth, 0x1c1917)
                .setStrokeStyle(2, 0x44403c)
                .setOrigin(0.5);
            this.mapLayer.add(tile);

            if (animate) {
                this.sprayEmitter.emitParticleAt(tx, ty, 15);
                tile.setAlpha(0).setScale(0.7);
                this.tweens.add({
                    targets: tile,
                    alpha: 1,
                    scale: 1,
                    duration: 600,
                    ease: 'Back.easeOut'
                });
            }
            this.revealedTiles.add(key);
        }

        if (this.contentByCoord.has(key)) {
            this.contentByCoord.get(key)!.destroy();
            this.contentByCoord.delete(key);
        }

        const content = this.createRoomContents(type, tx, ty);
        if (content) {
            this.contentByCoord.set(key, content);
            if (animate) {
                content.setAlpha(0).setScale(0.5);
                this.tweens.add({
                    targets: content,
                    alpha: 1,
                    scale: 1,
                    duration: 500,
                    delay: 200,
                    ease: 'Cubic.easeOut'
                });
            }
        }
    }

    private createRoomContents(type: RoomType, x: number, y: number) {
        let content: Phaser.GameObjects.Text | null = null;
        switch (type) {
            case 'BOSS':
                content = this.add.text(x, y, '💀', { fontSize: '32px' }).setOrigin(0.5);
                if (this.session.isBossLocked && !this.session.hasKey) content.setAlpha(0.3);
                break;
            case 'KEY':
                content = this.add.text(x, y, '🔑', { fontSize: '28px' }).setOrigin(0.5);
                break;
            case 'ENTRANCE':
                content = this.add.text(x, y, '🚪', { fontSize: '28px' }).setOrigin(0.5);
                break;
            case 'GOLD':
                content = this.add.text(x, y, '💰', { fontSize: '28px' }).setOrigin(0.5);
                this.tweens.add({
                    targets: content,
                    y: y - 5,
                    duration: 1200,
                    yoyo: true,
                    repeat: -1,
                    ease: 'Sine.easeInOut'
                });
                break;
            case 'TRAP':
                content = this.add.text(x, y, '🕸️', { fontSize: '28px' }).setOrigin(0.5);
                this.tweens.add({
                    targets: content,
                    angle: 15,
                    duration: 500,
                    yoyo: true,
                    repeat: -1,
                    ease: 'Sine.easeInOut'
                });
                break;
            case 'NPC':
                if (this.session.npcFound) return null;
                content = this.add.text(x, y, '👤', { fontSize: '30px' }).setOrigin(0.5);
                this.tweens.add({
                    targets: content,
                    alpha: 0.5,
                    duration: 1000,
                    yoyo: true,
                    repeat: -1
                });
                break;
        }
        if (content) {
            this.contentLayer.add(content);
        }
        return content;
    }

    private createPlayer() {
        const { x, y } = this.session.playerPos;
        const px = x * (this.tileWidth + this.tileGap);
        const py = y * (this.tileWidth + this.tileGap);

        const visual = this.add.container(0, 0);
        const circle = this.add.circle(0, 0, 26, 0x6366f1, 0.9).setStrokeStyle(3, 0xffffff);
        const icon = this.add.text(0, 0, '👤', { fontSize: '24px' }).setOrigin(0.5);
        visual.add([circle, icon]);

        this.playerMarker = this.add.container(px, py, [visual]);
        this.playerLayer.add(this.playerMarker);

        this.tweens.add({
            targets: visual,
            y: -8,
            duration: 800,
            yoyo: true,
            repeat: -1,
            ease: 'Sine.easeInOut'
        });
    }

    private alignViewToPlayer() {
        const { width, height } = this.scale;
        const { x, y } = this.session.playerPos;

        const yOffset = height * 0.05;
        const currentScale = 1.0;
        this.root.setScale(currentScale);

        const targetX = x * (this.tileWidth + this.tileGap);
        const targetY = y * (this.tileWidth + this.tileGap);

        this.root.setPosition((width / 2) - (targetX * currentScale), (height / 2 + yOffset) - (targetY * currentScale));
    }

    public updateSession(newSession: ManualDungeonSession) {
        const oldStatus = this.session.encounterStatus;
        this.session = newSession;

        if (oldStatus !== newSession.encounterStatus) {
            this.drawVignette();
        }

        const { width, height } = this.scale;
        const { x, y } = newSession.playerPos;
        const yOffset = height * 0.05;

        const targetLocalX = x * (this.tileWidth + this.tileGap);
        const targetLocalY = y * (this.tileWidth + this.tileGap);

        this.isMoving = true;

        this.tweens.add({
            targets: this.playerMarker,
            x: targetLocalX,
            y: targetLocalY,
            duration: 300,
            ease: 'Cubic.out',
            onComplete: () => {
                this.isMoving = false;
                this.initialRender();
            }
        });

        if (this.cameraMode !== 'FREE') {
            let shouldTrack = this.cameraMode === 'LOCKED';

            if (this.cameraMode === 'ADAPTIVE') {
                const currentViewX = (width / 2) - this.root.x;
                const currentViewY = (height / 2 + yOffset) - this.root.y;

                const distH = Math.abs(targetLocalX - currentViewX);
                const distV = Math.abs(targetLocalY - currentViewY);

                if (distH > width * 0.45 || distV > height * 0.45) {
                    shouldTrack = true;
                }
            }

            if (shouldTrack) {
                if (this.cameraTrackTimer) this.cameraTrackTimer.remove();

                this.cameraTrackTimer = this.time.delayedCall(1000, () => {
                    const targetRootX = (width / 2) - targetLocalX;
                    const targetRootY = (height / 2 + yOffset) - targetLocalY;

                    if (this.cameraTrackTween) this.cameraTrackTween.stop();

                    this.cameraTrackTween = this.tweens.add({
                        targets: this.root,
                        x: targetRootX,
                        y: targetRootY,
                        duration: 600, 
                        ease: 'Cubic.out'
                    });
                });
            }
        }
    }

    public move(dx: number, dy: number) {
        if (this.isMoving) return;
        this.onMoveCallback(dx, dy);
    }
}

import React, { useEffect, useRef, useState, useMemo, useCallback } from 'react';
import Phaser from 'phaser';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import DungeonScene from '../../../game/DungeonScene';
import DialogueBox from '../../DialogueBox';
import { 
    Key, Zap, LogOut, X, Trophy, Sparkles, Coins, ArrowRight, Package, ChevronUp, ChevronDown, CheckCircle, AlertTriangle, Shield, ChevronLeft, ChevronRight, Lock, Unlock, Target, Sword, Wind, Skull
} from 'lucide-react';
import ConfirmationModal from '../../modals/ConfirmationModal';
import { getAssetUrl } from '../../../utils';
import { calculateCombatPower, calculateMercenaryPower, calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, mergePrimaryStats, applyEquipmentBonuses } from '../../../models/Stats';

type CameraMode = 'LOCKED' | 'ADAPTIVE' | 'FREE';

const AssaultNavigator = () => {
    const { state, actions } = useGame();
    const session = state.activeManualDungeon;
    const gameRef = useRef<Phaser.Game | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isReady, setIsReady] = useState(false);
    const [showAbortConfirm, setShowAbortConfirm] = useState(false);
    const [showRetreatAtEntranceConfirm, setShowRetreatAtEntranceConfirm] = useState(false);
    const [cameraMode, setCameraMode] = useState<CameraMode>('LOCKED');

    const [isSquadStatusExpanded, setIsSquadStatusExpanded] = useState(true);
    const [showResultPopup, setShowResultPopup] = useState(false);
    const [hasTriggeredVictory, setHasTriggeredVictory] = useState(false);
    const [lastDiscoveryMessage, setLastDiscoveryMessage] = useState<string>('');
    const [rescueStep, setRescueStep] = useState<'NONE' | 'DIALOGUE' | 'DONE'>('NONE');

    const [isCombatProcessing, setIsCombatProcessing] = useState(false);
    const [currentLog, setCurrentLog] = useState<string>('');

    const dungeon = session ? DUNGEONS.find(d => d.id === session.dungeonId) : null;
    const party = session ? state.knownMercenaries.filter(m => session.partyIds.includes(m.id)) : [];
    const avgEnergy = party.length > 0 ? party.reduce((sum, m) => sum + (m.expeditionEnergy || 0), (party.length || 1)) / (party.length || 1) : 0;

    const currentRoomType = (session && dungeon) ? session.grid[session.playerPos.y][session.playerPos.x] : null;
    const isNPCNode = currentRoomType === 'NPC';
    const isEntranceNode = currentRoomType === 'ENTRANCE';
    const isBossNode = currentRoomType === 'BOSS';

    const encounterActive = session?.encounterStatus === 'ENCOUNTERED' || session?.encounterStatus === 'BATTLE';

    const handleDpadMove = (dx: number, dy: number) => {
        if (encounterActive) return; // 전투 중 이동 불가
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.move(dx, dy);
    };

    // 도주 확률 계산
    const fleeChance = useMemo(() => {
        if (!session?.bossEntity) return 0;
        const monsterCP = calculateCombatPower(session.bossEntity.stats, 'Fighter' as any, 'PHYSICAL'); // 임시 직업 할당
        const partyCP = party.reduce((sum, m) => sum + calculateMercenaryPower(m), 0);
        return Math.max(10, Math.min(90, Math.round(50 + (partyCP - monsterCP) / 10)));
    }, [session?.bossEntity, party]);

    const runCombatTurn = useCallback(async () => {
        if (!session || !session.bossEntity) return;

        setIsCombatProcessing(true);
        setCurrentLog("Engagement protocols initialized. Exchanging fire...");

        // 간이 시뮬레이션 (SimulationTab의 로직 차용)
        let bossHp = session.currentEnemyHp ?? session.bossEntity.stats.maxHp;
        const bossStats = session.bossEntity.stats;

        // 전투 루프 (순식간에 처리하거나 턴마다 딜레이 부여 가능)
        // 여기서는 몰입감을 위해 단계별 처리
        await new Promise(r => setTimeout(r, 800));

        // 파티의 총 공격
        const partyTotalDmg = party.reduce((sum, m) => {
            const p = mergePrimaryStats(m.stats, m.allocatedStats);
            const d = applyEquipmentBonuses(calculateDerivedStats(p, m.level), Object.values(m.equipment).map(e=>e?.stats).filter(Boolean) as any);
            const res = calculateCombatResult(d, bossStats, m.job, p.int > p.str ? 'MAGICAL' : 'PHYSICAL');
            return sum + (res.isHit ? res.damage : 0);
        }, 0);

        bossHp -= partyTotalDmg;
        gameRef.current?.scene.getScene('DungeonScene').cameras.main.shake(300, 0.01);
        setCurrentLog(`Squad dealt ${partyTotalDmg} damage to ${session.bossEntity.name}.`);

        await new Promise(r => setTimeout(r, 800));

        if (bossHp <= 0) {
            // 승리
            actions.moveInManualDungeon(0, 0); // 상태 갱신 (isBossDefeated 등)
            // 실제 상태 업데이트는 리듀서에서 하지만, 로컬 피드백을 위해 encounterStatus 변경 필요
            // 여기서는 actions에 위임
            actions.startManualAssault(session.dungeonId, session.partyIds); // 재호출로 상태 리프레시 유도
            setIsCombatProcessing(false);
            setHasTriggeredVictory(true);
            setShowResultPopup(true);
            return;
        }

        // 적의 반격 (랜덤 대상 1명)
        const targetMerc = party[Math.floor(Math.random() * party.length)];
        const targetIdx = state.knownMercenaries.findIndex(m => m.id === targetMerc.id);

        const bossAtkRes = calculateCombatResult(bossStats, bossStats, 'Fighter' as any, 'PHYSICAL'); // 적 데이터 기반
        if (bossAtkRes.isHit) {
            const nextHp = Math.max(0, targetMerc.currentHp - bossAtkRes.damage);
            actions.updateMercenaryStats(targetMerc.id, targetMerc.allocatedStats); // HP 업데이트를 위한 액션 (실제로는 currentHp 업데이트 필요)
            // TODO: Reducer에 HP 데미지 처리 액션 추가 필요하나 현재는 기존 액션 활용
            setCurrentLog(`${session.bossEntity.name} countered! ${targetMerc.name.split(' ')[0]} took ${bossAtkRes.damage} damage.`);

            // 파티원 전멸 체크
            if (party.every(m => m.currentHp <= bossAtkRes.damage && m.id === targetMerc.id)) {
                setIsCombatProcessing(false);
                actions.retreatFromManualDungeon(); // 전멸 시 퇴출
                return;
            }
        } else {
            setCurrentLog(`${targetMerc.name.split(' ')[0]} successfully evaded the counter-attack!`);
        }

        // 보스 HP 업데이트를 위해 세션 갱신 로직 필요 (현재는 UI에서만 추적)
        // 실제 게임 환경에서는 Reducer에서 이 모든 시뮬레이션을 처리하는 것이 정석
        setIsCombatProcessing(false);
    }, [session, party, actions, state.knownMercenaries]);

    const handleFlee = () => {
        if (!session) return;
        const roll = Math.random() * 100;
        if (roll < fleeChance) {
            actions.showToast("Escape successful! The squad managed to slip away.");
            // 조우 해제 (Reducer에서 encounterStatus를 NONE으로 변경하는 로직 필요)
            // 현재는 간단히 overlay를 껐다 켜거나 상태 업데이트 트리거
            actions.startManualAssault(session.dungeonId, session.partyIds); 
        } else {
            actions.showToast("FAILED TO ESCAPE! The boss strikes as you turn your back.");
            // 패널티: 에너지 -10, 랜덤 1명 큰 데미지
            actions.moveInManualDungeon(0, 0); // 턴 강제 소비 연출
        }
    };

    const currentDialogueText = useMemo(() => {
        if (isCombatProcessing) return currentLog;
        if (session?.encounterStatus === 'ENCOUNTERED') return `CRITICAL ENCOUNTER: ${session.bossEntity?.name || 'Unknown'}. Escape Probability: ${fleeChance}%. Stand your ground or retreat?`;
        if (rescueStep === 'DIALOGUE') return "Help! Is someone there? The rats... they're everywhere! Please, get me out of here!";
        return lastDiscoveryMessage;
    }, [isCombatProcessing, currentLog, session?.encounterStatus, fleeChance, rescueStep, lastDiscoveryMessage, session?.bossEntity]);

    useEffect(() => {
        const checkSize = () => {
            if (containerRef.current && containerRef.current.clientWidth > 0) setIsReady(true);
            else requestAnimationFrame(checkSize);
        };
        checkSize();
    }, []);

    useEffect(() => {
        if (!session || !dungeon) return;

        const room = session.grid[session.playerPos.y][session.playerPos.x];
        const latestLog = state.logs[0];

        if (session.isBossDefeated && !hasTriggeredVictory) {
            setShowResultPopup(true); 
            setHasTriggeredVictory(true);
            return;
        }

        if (room === 'KEY') setLastDiscoveryMessage("Chamber key recovered. Tactical scanning identifies the Boss location. What should we do next?");
        else if (room === 'NPC' && !session.npcFound) setLastDiscoveryMessage("Life-sign confirmed. Survivor location secured. Initializing escort protocols. What is the next move?");
        else if (room === 'BOSS' && !session.isBossDefeated) setLastDiscoveryMessage(`Hostile Signature: ${session.bossEntity?.name || 'Unknown'}. Squad is ready to engage. Commencing Direct Assault?`);
        else if (room === 'BOSS' && session.isBossDefeated) setLastDiscoveryMessage("Enemy High-Value Target neutralized. Sector secured. We can extract safely from this point.");
        else if (isEntranceNode && (lastDiscoveryMessage === '' || lastDiscoveryMessage.includes('Infiltration'))) setLastDiscoveryMessage(`Infiltration of ${dungeon.name} successful. Commencing area sweep. What's our first move?`);
        else if (room === 'EMPTY') {
            const goldTerms = ['Looted', 'Found', 'Discovered', 'cache', 'coins', 'gold'];
            if (goldTerms.some(term => latestLog?.includes(term))) setLastDiscoveryMessage("Treasury cache secured. This sector is now clear and safe. What should be our next course of action?");
            else setLastDiscoveryMessage("Scans indicate this area is vacant. No immediate threats detected. What is the next move?");
        }
    }, [session?.playerPos, session?.grid, session?.npcFound, dungeon?.name, isEntranceNode, state.logs, session?.isBossDefeated, hasTriggeredVictory, session?.bossEntity]);

    useEffect(() => {
        if (!isReady || !containerRef.current || !session || !dungeon) return;
        if (!gameRef.current) {
            const config: Phaser.Types.Core.GameConfig = {
                type: Phaser.AUTO, parent: containerRef.current, width: containerRef.current.clientWidth, height: containerRef.current.clientHeight, backgroundColor: 'transparent', transparent: true, scene: [DungeonScene],
                scale: { mode: Phaser.Scale.RESIZE, autoCenter: Phaser.Scale.CENTER_BOTH }
            };
            const game = new Phaser.Game(config);
            gameRef.current = game;
            game.scene.start('DungeonScene', { session, moveEnergy: dungeon.moveEnergy, bossEnergy: dungeon.bossEnergy, onMove: (dx: number, dy: number) => { actions.moveInManualDungeon(dx, dy); }, cameraMode: cameraMode });
        } else {
            const scene = gameRef.current.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) { scene.updateSession(session); scene.setCameraMode(cameraMode); }
        }
    }, [isReady, session, actions, dungeon?.moveEnergy, dungeon?.bossEnergy, cameraMode]);

    useEffect(() => { return () => { if (gameRef.current) { gameRef.current.destroy(true); gameRef.current = null; } }; }, []);

    const interactionOptions = useMemo(() => {
        if (!session) return [];
        if (isCombatProcessing) return [];

        if (session.encounterStatus === 'ENCOUNTERED') {
            return [
                { label: "ATTACK", action: runCombatTurn, variant: 'primary' as const },
                { label: `FLEE (${fleeChance}%)`, action: handleFlee, variant: 'danger' as const }
            ];
        }

        if (rescueStep === 'DIALOGUE') return [{ label: "Accept Escort Request", action: () => { if (session?.dungeonId === 'dungeon_t1_rats') actions.rescueMercenary('tilly_footloose'); setRescueStep('DONE'); }, variant: 'primary' as const }];

        const opts = [];
        if (session.isBossDefeated && (isEntranceNode || isBossNode)) opts.push({ label: "Claim Rewards & Return", action: () => setShowResultPopup(true), variant: 'primary' as const });
        if (isEntranceNode && !session.isBossDefeated) opts.push({ label: "Retreat to Forge", action: () => setShowRetreatAtEntranceConfirm(true), variant: 'neutral' as const });
        if (isNPCNode && !session.npcFound && rescueStep === 'NONE') opts.push({ label: "Rescue Survivor", action: () => setRescueStep('DIALOGUE'), variant: 'primary' as const });
        return opts;
    }, [session?.playerPos, dungeon, isNPCNode, isBossNode, session?.npcFound, rescueStep, session?.isBossDefeated, actions, isEntranceNode, session?.encounterStatus, fleeChance, isCombatProcessing]);

    if (!session || !dungeon) return null;

    return (
        <div className="absolute inset-0 z-[100] bg-stone-950 flex flex-col animate-in fade-in duration-500 overflow-hidden">
            <div ref={containerRef} className="absolute inset-0 z-0" />

            {/* Squad Status HUD */}
            <div className="absolute top-20 left-4 z-50 flex flex-col gap-2 w-48 md:w-56 pointer-events-none">
                <button onClick={() => setIsSquadStatusExpanded(!isSquadStatusExpanded)} className="bg-stone-950/40 backdrop-blur-md border border-white/10 rounded-lg p-2 mb-1 flex items-center justify-between pointer-events-auto hover:bg-stone-900/60 transition-colors group">
                    <div className="flex items-center gap-2"><Shield className="w-3.5 h-3.5 text-blue-400" /><span className="text-[10px] font-black text-blue-100 uppercase tracking-widest">Squad Status</span></div>
                    {isSquadStatusExpanded ? <ChevronUp className="w-3.5 h-3.5 text-stone-500 group-hover:text-stone-300" /> : <ChevronDown className="w-3.5 h-3.5 text-stone-500 group-hover:text-stone-300" />}
                </button>
                {isSquadStatusExpanded && party.map(merc => {
                    const hpPer = (merc.currentHp / merc.maxHp) * 100;
                    return (
                        <div key={merc.id} className="bg-stone-900/80 border border-stone-700/50 p-2 rounded-xl backdrop-blur-md shadow-lg animate-in slide-in-from-top-2 duration-300">
                            <div className="flex items-center gap-2 mb-1.5"><div className="w-6 h-6 rounded-full bg-stone-800 flex items-center justify-center border border-white/5 text-xs shadow-inner shrink-0">{merc.icon}</div><div className="min-w-0 flex-1"><div className="text-[10px] font-black text-white truncate leading-none uppercase">{merc.name.split(' ')[0]}</div><div className="text-[7px] text-stone-500 font-bold uppercase tracking-tighter truncate">{merc.job} • LV.{merc.level}</div></div></div>
                            <div className="flex justify-between text-[6px] font-mono text-stone-400 px-0.5 uppercase tracking-tighter mb-0.5"><span>HP</span><span>{Math.floor(merc.currentHp)}/{merc.maxHp}</span></div>
                            <div className="w-full bg-stone-950 h-1 rounded-full overflow-hidden border border-white/5"><div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-600 animate-pulse' : 'bg-red-500'}`} style={{ width: `${hpPer}%` }} /></div>
                        </div>
                    );
                })}
            </div>

            {/* Boss HUD (Combat Mode) */}
            {(isBossNode || encounterActive) && session.bossEntity && !session.isBossDefeated && (
                <div className="absolute top-20 right-4 z-50 flex flex-col gap-2 w-56 animate-in slide-in-from-right-4 duration-500">
                    <div className={`bg-stone-950/80 backdrop-blur-md border-2 rounded-xl p-3 shadow-2xl transition-all duration-500 ${encounterActive ? 'border-red-600 ring-2 ring-red-600/50' : 'border-red-900/50'}`}>
                        <div className="flex items-center gap-3 mb-2">
                            <div className="w-10 h-10 bg-red-950/40 rounded-lg flex items-center justify-center border border-red-500/30 text-2xl shadow-inner">{session.bossEntity.icon}</div>
                            <div className="min-w-0 flex-1">
                                <div className="text-xs font-black text-red-100 uppercase truncate leading-none">{session.bossEntity.name}</div>
                                <div className="text-[8px] text-red-500 font-black uppercase tracking-widest mt-1">{encounterActive ? 'BATTLE ENGAGED' : 'Boss Signature Detected'}</div>
                            </div>
                        </div>
                        <div className="w-full bg-stone-950 h-2 rounded-full overflow-hidden border border-red-900/30 relative shadow-inner">
                            <div className="h-full bg-gradient-to-r from-red-800 to-red-600 transition-all duration-500" style={{ width: `${((session.currentEnemyHp ?? session.bossEntity.stats.maxHp) / session.bossEntity.stats.maxHp) * 100}%` }} />
                            <div className="absolute inset-0 flex items-center justify-center"><span className="text-[7px] font-mono font-black text-white/70">{session.currentEnemyHp ?? session.bossEntity.stats.maxHp} / {session.bossEntity.stats.maxHp}</span></div>
                        </div>
                        {encounterActive && (
                            <div className="mt-2 flex justify-between items-center px-1">
                                <span className="text-[7px] text-stone-500 font-bold uppercase">Combat Power</span>
                                <span className="text-[10px] font-mono font-black text-red-400">{calculateCombatPower(session.bossEntity.stats, 'Fighter' as any, 'PHYSICAL')} CP</span>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* Bottom Interaction Unit */}
            <div className="absolute bottom-0 left-0 right-0 z-40 px-[2%] pb-[2%] flex flex-col items-end pointer-events-none">
                <div className={`mb-4 transition-all duration-500 pointer-events-auto ${showResultPopup || rescueStep === 'DIALOGUE' || encounterActive || isCombatProcessing ? 'opacity-0 scale-90 translate-y-4 pointer-events-none' : 'opacity-100 scale-100 translate-y-0'}`}>
                    <div className="grid grid-cols-3 gap-1 md:gap-2 p-2 bg-stone-900/40 backdrop-blur-md rounded-[1.5rem] border border-white/5 shadow-2xl shadow-black/50" style={{ width: '15vmin', height: '15vmin', minWidth: '100px', minHeight: '100px' }}>
                        <div />
                        <button onClick={() => handleDpadMove(0, -1)} disabled={session.playerPos.y <= 0} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800/80 border-stone-600 text-stone-200 shadow-lg disabled:opacity-20"><ChevronUp className="w-[60%] h-[60%]" /></button>
                        <div />
                        <button onClick={() => handleDpadMove(-1, 0)} disabled={session.playerPos.x <= 0} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800/80 border-stone-600 text-stone-200 shadow-lg disabled:opacity-20"><ChevronLeft className="w-[60%] h-[60%]" /></button>
                        <button onClick={() => setCameraMode(prev => prev === 'LOCKED' ? 'ADAPTIVE' : prev === 'ADAPTIVE' ? 'FREE' : 'LOCKED')} className={`w-full h-full rounded-lg border flex flex-col items-center justify-center transition-all ${cameraMode !== 'FREE' ? 'bg-amber-500/20 border-amber-500/50 text-amber-500' : 'bg-stone-800/40 border-stone-700 text-stone-500'}`}>{cameraMode === 'LOCKED' ? <Lock className="w-[50%] h-[50%]" /> : cameraMode === 'ADAPTIVE' ? <Target className="w-[50%] h-[50%]" /> : <Unlock className="w-[50%] h-[50%]" />}</button>
                        <button onClick={() => handleDpadMove(1, 0)} disabled={session.playerPos.x >= (dungeon?.gridWidth || 1) - 1} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800/80 border-stone-600 text-stone-200 shadow-lg disabled:opacity-20"><ChevronRight className="w-[60%] h-[60%]" /></button>
                        <div />
                        <button onClick={() => handleDpadMove(0, 1)} disabled={session.playerPos.y >= (dungeon?.gridHeight || 1) - 1} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800/80 border-stone-600 text-stone-200 shadow-lg disabled:opacity-20"><ChevronDown className="w-[60%] h-[60%]" /></button>
                        <div />
                    </div>
                </div>
                <div className="w-full pointer-events-auto">
                    <DialogueBox 
                        speaker={isCombatProcessing ? "Tactical AI" : (rescueStep === 'DIALOGUE' ? "Tilly Footloose" : (encounterActive ? "Combat Interface" : "Tactical Link"))} 
                        text={currentDialogueText} 
                        options={interactionOptions as any} 
                    />
                </div>
            </div>

            <ConfirmationModal isOpen={showAbortConfirm} title="Abandon Assault?" message="Retreating via system override will forfeit all progress in this floor. All spent energy will not be recovered." confirmLabel="Confirm Retreat" cancelLabel="Stay Focused" isDanger={true} onConfirm={() => actions.retreatFromManualDungeon()} onCancel={() => setShowAbortConfirm(false)} />
            <ConfirmationModal isOpen={showRetreatAtEntranceConfirm} title="Retreat to Forge?" message="If you leave the dungeon now without defeating the Boss, you will forfeit all loot and gold collected during this session. Do you wish to proceed?" confirmLabel="Confirm Retreat" cancelLabel="Continue Mission" isDanger={true} onConfirm={() => actions.retreatFromManualDungeon()} onCancel={() => setShowRetreatAtEntranceConfirm(false)} />

            {showResultPopup && (
                <div className="fixed inset-0 z-[700] bg-black/90 backdrop-blur-md flex items-center justify-center px-[10%] py-[15%] animate-in fade-in duration-500 pointer-events-auto overflow-hidden">
                    <div className="bg-stone-900 border-2 border-amber-600/50 rounded-3xl w-fit max-w-[600px] h-fit max-h-full min-h-[200px] min-w-[280px] shadow-[0_40px_80px_-20px_rgba(0,0,0,0.9)] overflow-hidden flex flex-col animate-in zoom-in-95 duration-500 mx-auto">
                        <div className="bg-amber-600 p-4 md:p-6 flex flex-col items-center text-center text-white shrink-0">
                            <Trophy className="w-8 h-8 md:w-12 md:h-12 mb-1 md:mb-2 animate-bounce" />
                            <h2 className="text-xl md:text-2xl font-black italic tracking-tighter uppercase font-serif leading-none px-4">Objective Complete!</h2>
                        </div>
                        <div className="p-4 md:p-6 space-y-6 overflow-y-auto custom-scrollbar flex-1">
                            <div className="space-y-2">
                                <h3 className="text-[8px] md:text-[10px] font-black text-stone-500 uppercase tracking-widest text-center">Treasury Secured</h3>
                                <div className="bg-stone-950 p-3 md:p-4 rounded-2xl border border-stone-800 flex flex-col items-center gap-1">
                                    <div className="flex items-center gap-2 text-stone-400 font-mono text-xs md:text-sm"><span>Base: {dungeon.goldReward}G</span><span>+</span><span className="text-amber-400">Bonus: {session.goldCollected}G</span></div>
                                    <div className="flex items-center gap-2 mt-1"><Coins className="w-5 h-5 md:w-6 md:h-6 text-amber-500" /><span className="text-xl md:text-3xl font-black font-mono text-stone-100">{dungeon.goldReward! + session.goldCollected} G</span></div>
                                </div>
                            </div>
                        </div>
                        <div className="p-4 md:p-6 pt-0 flex flex-col gap-2 md:gap-3 shrink-0">
                            <button onClick={() => actions.finishManualAssault()} className="w-full py-3 md:py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl shadow-xl flex items-center justify-center gap-2 transition-all active:scale-95 border-b-4 border-emerald-800 text-[10px] md:text-base uppercase tracking-widest px-8"><Package className="w-4 h-4 md:w-5 md:h-5" />SECURE LOOT & RETURN</button>
                            <button onClick={() => setShowResultPopup(false)} className="w-full py-2.5 md:py-4 bg-stone-800 hover:bg-stone-700 text-stone-300 font-black rounded-xl transition-all flex items-center justify-center gap-2 text-[10px] md:text-sm uppercase tracking-widest px-6"><ArrowRight className="w-4 h-4 md:w-5 md:h-5" /> KEEP EXPLORING</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default AssaultNavigator;

import React, { useEffect, useRef, useState, useMemo, useCallback } from 'react';
import Phaser from 'phaser';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import DungeonScene from '../../../game/DungeonScene';
import DialogueBox from '../../DialogueBox';
import { 
    Key, Zap, LogOut, X, Trophy, Sparkles, Coins, ArrowRight, Package, ChevronUp, ChevronDown, CheckCircle, AlertTriangle, Shield, ChevronLeft, ChevronRight, Lock, Unlock, Target, Sword, Wind, Skull
} from 'lucide-react';
import ConfirmationModal from '../../modals/ConfirmationModal';
import { getAssetUrl, formatDuration } from '../../../utils';
import { calculateCombatPower, calculateMercenaryPower, calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, mergePrimaryStats, applyEquipmentBonuses } from '../../../models/Stats';
// Added missing model imports to fix type inference issues where properties like 'stats' were being flagged on 'unknown' types
import { Equipment } from '../../../models/Equipment';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';

type CameraMode = 'LOCKED' | 'ADAPTIVE' | 'FREE';

const AssaultNavigator = () => {
    const { state, actions } = useGame();
    const session = state.activeManualDungeon;
    const gameRef = useRef<Phaser.Game | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isReady, setIsReady] = useState(false);
    const [showAbortConfirm, setShowAbortConfirm] = useState(false);
    const [showRetreatAtEntranceConfirm, setShowRetreatAtEntranceConfirm] = useState(false);
    const [cameraMode, setCameraMode] = useState<CameraMode>('LOCKED');

    const [isSquadStatusExpanded, setIsSquadStatusExpanded] = useState(true);
    const [showResultPopup, setShowResultPopup] = useState(false);
    const [hasTriggeredVictory, setHasTriggeredVictory] = useState(false);
    const [lastDiscoveryMessage, setLastDiscoveryMessage] = useState<string>('');
    const [rescueStep, setRescueStep] = useState<'NONE' | 'DIALOGUE' | 'DONE'>('NONE');

    const [isCombatProcessing, setIsCombatProcessing] = useState(false);
    const [currentLog, setCurrentLog] = useState<string>('');

    const dungeon = session ? DUNGEONS.find(d => d.id === session.dungeonId) : null;
    const party = session ? state.knownMercenaries.filter(m => session.partyIds.includes(m.id)) : [];
    const avgEnergy = party.length > 0 ? party.reduce((sum, m) => sum + (m.expeditionEnergy || 0), (party.length || 1)) / (party.length || 1) : 0;

    const currentRoomType = (session && dungeon) ? session.grid[session.playerPos.y][session.playerPos.x] : null;
    const isNPCNode = currentRoomType === 'NPC';
    const isEntranceNode = currentRoomType === 'ENTRANCE';
    const isBossNode = currentRoomType === 'BOSS';

    const encounterActive = session?.encounterStatus === 'ENCOUNTERED' || session?.encounterStatus === 'BATTLE';

    const handleDpadMove = (dx: number, dy: number) => {
        if (encounterActive) return; // 전투 중 이동 불가
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.move(dx, dy);
    };

    // 도주 확률 계산
    const fleeChance = useMemo(() => {
        // Fix: Explicitly check bossEntity existence for type safety
        if (!session || !session.bossEntity) return 0;
        const monsterCP = calculateCombatPower(session.bossEntity.stats, 'Fighter' as any, 'PHYSICAL'); // 임시 직업 할당
        const partyCP = party.reduce((sum, m) => sum + calculateMercenaryPower(m), 0);
        return Math.max(10, Math.min(90, Math.round(50 + (partyCP - monsterCP) / 10)));
    }, [session, party]);

    const runCombatTurn = useCallback(async () => {
        // Fix: Explicitly narrow session and bossEntity types for safety
        if (!session || !session.bossEntity) return;
        const boss = session.bossEntity as Monster;

        setIsCombatProcessing(true);
        setCurrentLog("Engagement protocols initialized. Exchanging fire...");

        // 간이 시뮬레이션 (SimulationTab의 로직 차용)
        let bossHp = session.currentEnemyHp ?? boss.stats.maxHp;
        const bossStats = boss.stats;

        // 전투 루프 (순식간에 처리하거나 턴마다 딜레이 부여 가능)
        // 여기서는 몰입감을 위해 단계별 처리
        await new Promise(r => setTimeout(r, 800));

        // 파티의 총 공격
        const partyTotalDmg = party.reduce((sum, m: Mercenary) => {
            const p = mergePrimaryStats(m.stats, m.allocatedStats);
            const d = applyEquipmentBonuses(calculateDerivedStats(p, m.level), Object.values(m.equipment).map(e => (e as Equipment | null)?.stats).filter(Boolean) as any);
            const res = calculateCombatResult(d, bossStats, m.job, p.int > p.str ? 'MAGICAL' : 'PHYSICAL');
            return sum + (res.isHit ? res.damage : 0);
        }, 0);

        bossHp -= partyTotalDmg;
        gameRef.current?.scene.getScene('DungeonScene').cameras.main.shake(300, 0.01);
        setCurrentLog(`Squad dealt ${partyTotalDmg} damage to ${boss.name}.`);

        await new Promise(r => setTimeout(r, 800));

        if (bossHp <= 0) {
            // 승리
            actions.moveInManualDungeon(0, 0); // 상태 갱신 (isBossDefeated 등)
            // 실제 상태 업데이트는 리듀서에서 하지만, 로컬 피드백을 위해 encounterStatus 변경 필요
            // 여기서는 actions에 위임
            actions.startManualAssault(session.dungeonId, session.partyIds); // 재호출로 상태 리프레시 유도
            setIsCombatProcessing(false);
            setHasTriggeredVictory(true);
            setShowResultPopup(true);
            return;
        }

        // 적의 반격 (랜덤 대상 1명)
        const targetMerc = party[Math.floor(Math.random() * party.length)];

        const bossAtkRes = calculateCombatResult(bossStats, bossStats, 'Fighter' as any, 'PHYSICAL'); // 적 데이터 기반
        if (bossAtkRes.isHit) {
            setCurrentLog(`${boss.name} countered! ${targetMerc.name.split(' ')[0]} took ${bossAtkRes.damage} damage.`);

            // 파티원 전멸 체크
            if (party.every(m => m.currentHp <= bossAtkRes.damage && m.id === targetMerc.id)) {
                setIsCombatProcessing(false);
                actions.retreatFromManualDungeon(); // 전멸 시 퇴출
                return;
            }
        } else {
            setCurrentLog(`${targetMerc.name.split(' ')[0]} successfully evaded the counter-attack!`);
        }

        // 보스 HP 업데이트를 위해 세션 갱신 로직 필요 (현재는 UI에서만 추적)
        // 실제 게임 환경에서는 Reducer에서 이 모든 시뮬레이션을 처리하는 것이 정석
        setIsCombatProcessing(false);
    }, [session, party, actions]);

    const handleFlee = () => {
        if (!session) return;
        const roll = Math.random() * 100;
        if (roll < fleeChance) {
            actions.showToast("Escape successful! The squad managed to slip away.");
            // 조우 해제 (Reducer에서 encounterStatus를 NONE으로 변경하는 로직 필요)
            // 현재는 간단히 overlay를 껐다 켜거나 상태 업데이트 트리거
            actions.startManualAssault(session.dungeonId, session.partyIds); 
        } else {
            actions.showToast("FAILED TO ESCAPE! The boss strikes as you turn your back.");
            // 패널티: 에너지 -10, 랜덤 1명 큰 데미지
            actions.moveInManualDungeon(0, 0); // 턴 강제 소비 연출
        }
    };

    const currentDialogueText = useMemo(() => {
        if (isCombatProcessing) return currentLog;
        if (session?.encounterStatus === 'ENCOUNTERED') return `CRITICAL ENCOUNTER: ${session?.bossEntity?.name || 'Unknown'}. Escape Probability: ${fleeChance}%. Stand your ground or retreat?`;
        if (rescueStep === 'DIALOGUE') return "Help! Is someone there? The rats... they're everywhere! Please, get me out of here!";
        return lastDiscoveryMessage;
    }, [isCombatProcessing, currentLog, session?.encounterStatus, fleeChance, rescueStep, lastDiscoveryMessage, session?.bossEntity]);

    useEffect(() => {
        const checkSize = () => {
            if (containerRef.current && containerRef.current.clientWidth > 0) setIsReady(true);
            else requestAnimationFrame(checkSize);
        };
        checkSize();
    }, []);

    useEffect(() => {
        if (!session || !dungeon) return;

        const room = session.grid[session.playerPos.y][session.playerPos.x];
        const latestLog = state.logs[0];

        if (session.isBossDefeated && !hasTriggeredVictory) {
            setShowResultPopup(true); 
            setHasTriggeredVictory(true);
            return;
        }

        if (room === 'KEY') setLastDiscoveryMessage("Chamber key recovered. Tactical scanning identifies the Boss location. What should we do next?");
        else if (room === 'NPC' && !session.npcFound) setLastDiscoveryMessage("Life-sign confirmed. Survivor location secured. Initializing escort protocols. What is the next move?");
        else if (room === 'BOSS' && !session.isBossDefeated) setLastDiscoveryMessage(`Hostile Signature: ${session?.bossEntity?.name || 'Unknown'}. Squad is ready to engage. Commencing Direct Assault?`);
        else if (room === 'BOSS' && session.isBossDefeated) setLastDiscoveryMessage("Enemy High-Value Target neutralized. Sector secured. We can extract safely from this point.");
        else if (isEntranceNode && (lastDiscoveryMessage === '' || lastDiscoveryMessage.includes('Infiltration'))) setLastDiscoveryMessage(`Infiltration of ${dungeon.name} successful. Commencing area sweep. What's our first move?`);
        else if (room === 'EMPTY') {
            const goldTerms = ['Looted', 'Found', 'Discovered', 'cache', 'coins', 'gold'];
            if (goldTerms.some(term => latestLog?.includes(term))) setLastDiscoveryMessage("Treasury cache secured. This sector is now clear and safe. What should be our next course of action?");
            else setLastDiscoveryMessage("Scans indicate this area is vacant. No immediate threats detected. What is the next move?");
        }
    }, [session?.playerPos, session?.grid, session?.npcFound, dungeon?.name, isEntranceNode, state.logs, session?.isBossDefeated, hasTriggeredVictory, session?.bossEntity]);

    useEffect(() => {
        if (!isReady || !containerRef.current || !session || !dungeon) return;
        if (!gameRef.current) {
            const config: Phaser.Types.Core.GameConfig = {
                type: Phaser.AUTO, parent: containerRef.current, width: containerRef.current.clientWidth, height: containerRef.current.clientHeight, backgroundColor: 'transparent', transparent: true, scene: [DungeonScene],
                scale: { mode: Phaser.Scale.RESIZE, autoCenter: Phaser.Scale.CENTER_BOTH }
            };
            const game = new Phaser.Game(config);
            gameRef.current = game;
            game.scene.start('DungeonScene', { session, moveEnergy: dungeon.moveEnergy, bossEnergy: dungeon.bossEnergy, onMove: (dx: number, dy: number) => { actions.moveInManualDungeon(dx, dy); }, cameraMode: cameraMode });
        } else {
            const scene = gameRef.current.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) { scene.updateSession(session); scene.setCameraMode(cameraMode); }
        }
    }, [isReady, session, actions, dungeon?.moveEnergy, dungeon?.bossEnergy, cameraMode]);

    useEffect(() => { return () => { if (gameRef.current) { gameRef.current.destroy(true); gameRef.current = null; } }; }, []);

    const interactionOptions = useMemo(() => {
        if (!session) return [];
        if (isCombatProcessing) return [];

        if (session.encounterStatus === 'ENCOUNTERED') {
            return [
                { label: "ATTACK", action: runCombatTurn, variant: 'primary' as const },
                { label: `FLEE (${fleeChance}%)`, action: handleFlee, variant: 'danger' as const }
            ];
        }

        if (rescueStep === 'DIALOGUE') return [{ label: "Accept Escort Request", action: () => { if (session?.dungeonId === 'dungeon_t1_rats') actions.rescueMercenary('tilly_footloose'); setRescueStep('DONE'); }, variant: 'primary' as const }];

        const opts = [];
        if (session.isBossDefeated && (isEntranceNode || isBossNode)) opts.push({ label: "Claim Rewards & Return", action: () => setShowResultPopup(true), variant: 'primary' as const });
        if (isEntranceNode && !session.isBossDefeated) opts.push({ label: "Retreat to Forge", action: () => setShowRetreatAtEntranceConfirm(true), variant: 'neutral' as const });
        if (isNPCNode && !session.npcFound && rescueStep === 'NONE') opts.push({ label: "Rescue Survivor", action: () => setRescueStep('DIALOGUE'), variant: 'primary' as const });
        return opts;
    }, [session?.playerPos, dungeon, isNPCNode, isBossNode, session?.npcFound, rescueStep, session?.isBossDefeated, actions, isEntranceNode, session?.encounterStatus, fleeChance, isCombatProcessing, runCombatTurn]);

    if (!session || !dungeon) return null;

    return (
        <div className="absolute inset-0 z-[100] bg-stone-950 flex flex-col animate-in fade-in duration-500 overflow-hidden">
            <div ref={containerRef} className="absolute inset-0 z-0" />

            {/* Squad Status HUD */}
            <div className="absolute top-20 left-4 z-50 flex flex-col gap-2 w-48 md:w-56 pointer-events-none">
                <button onClick={() => setIsSquadStatusExpanded(!isSquadStatusExpanded)} className="bg-stone-950/40 backdrop-blur-md border border-white/10 rounded-lg p-2 mb-1 flex items-center justify-between pointer-events-auto hover:bg-stone-900/60 transition-colors group">
                    <div className="flex items-center gap-2"><Shield className="w-3.5 h-3.5 text-blue-400" /><span className="text-[10px] font-black text-blue-100 uppercase tracking-widest">Squad Status</span></div>
                    {isSquadStatusExpanded ? <ChevronUp className="w-3.5 h-3.5 text-stone-500 group-hover:text-stone-300" /> : <ChevronDown className="w-3.5 h-3.5 text-stone-500 group-hover:text-stone-300" />}
                </button>
                {isSquadStatusExpanded && party.map(merc => {
                    const hpPer = (merc.currentHp / merc.maxHp) * 100;
                    return (
                        <div key={merc.id} className="bg-stone-900/80 border border-stone-700/50 p-2 rounded-xl backdrop-blur-md shadow-lg animate-in slide-in-from-top-2 duration-300">
                            <div className="flex items-center gap-2 mb-1.5"><div className="w-6 h-6 rounded-full bg-stone-800 flex items-center justify-center border border-white/5 text-xs shadow-inner shrink-0">{merc.icon}</div><div className="min-w-0 flex-1"><div className="text-[10px] font-black text-white truncate leading-none uppercase">{merc.name.split(' ')[0]}</div><div className="text-[7px] text-stone-500 font-bold uppercase tracking-tighter truncate">{merc.job} • LV.{merc.level}</div></div></div>
                            <div className="flex justify-between text-[6px] font-mono text-stone-400 px-0.5 uppercase tracking-tighter mb-0.5"><span>HP</span><span>{Math.floor(merc.currentHp)}/{merc.maxHp}</span></div>
                            <div className="w-full bg-stone-950 h-1 rounded-full overflow-hidden border border-white/5"><div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-600 animate-pulse' : 'bg-red-500'}`} style={{ width: `${hpPer}%` }} /></div>
                        </div>
                    );
                })}
            </div>

            {/* Boss HUD (Combat Mode) */}
            {(isBossNode || encounterActive) && session.bossEntity && !session.isBossDefeated && (
                <div className="absolute top-20 right-4 z-50 flex flex-col gap-2 w-56 animate-in slide-in-from-right-4 duration-500">
                    <div className={`bg-stone-950/80 backdrop-blur-md border-2 rounded-xl p-3 shadow-2xl transition-all duration-500 ${encounterActive ? 'border-red-600 ring-2 ring-red-600/50' : 'border-red-900/50'}`}>
                        <div className="flex items-center gap-3 mb-2">
                            <div className="w-10 h-10 bg-red-950/40 rounded-lg flex items-center justify-center border border-red-500/30 text-2xl shadow-inner">{session.bossEntity.icon}</div>
