                        <button onClick={() => handleDpadMove(-1, 0)} disabled={session.playerPos.x <= 0} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800/80 border-stone-600 text-stone-200 shadow-lg disabled:opacity-20"><ChevronLeft className="w-[60%] h-[60%]" /></button>
                        <button onClick={() => setCameraMode(prev => prev === 'LOCKED' ? 'ADAPTIVE' : prev === 'ADAPTIVE' ? 'FREE' : 'LOCKED')} className={`w-full h-full rounded-lg border flex flex-col items-center justify-center transition-all ${cameraMode !== 'FREE' ? 'bg-amber-500/20 border-amber-500/50 text-amber-500' : 'bg-stone-800/40 border-stone-700 text-stone-500'}`}>{cameraMode === 'LOCKED' ? <Lock className="w-[50%] h-[50%]" /> : cameraMode === 'ADAPTIVE' ? <Target className="w-[50%] h-[50%]" /> : <Unlock className="w-[50%] h-[50%]" />}</button>
                        <button onClick={() => handleDpadMove(1, 0)} disabled={session.playerPos.x >= (dungeon?.gridWidth || 1) - 1} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800/80 border-stone-600 text-stone-200 shadow-lg disabled:opacity-20"><ChevronRight className="w-[60%] h-[60%]" /></button>
                        <div />
                        <button onClick={() => handleDpadMove(0, 1)} disabled={session.playerPos.y >= (dungeon?.gridHeight || 1) - 1} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800/80 border-stone-600 text-stone-200 shadow-lg disabled:opacity-20"><ChevronDown className="w-[60%] h-[60%]" /></button>
                        <div />
                    </div>
                </div>
                <div className="w-full pointer-events-auto">
                    <DialogueBox 
                        speaker={isCombatProcessing ? "Tactical AI" : (rescueStep === 'DIALOGUE' ? "Tilly Footloose" : (encounterActive ? "Combat Interface" : "Tactical Link"))} 
                        text={currentDialogueText} 
                        options={interactionOptions as any} 
                    />
                </div>
            </div>

            <ConfirmationModal isOpen={showAbortConfirm} title="Abandon Assault?" message="Retreating via system override will forfeit all progress in this floor. All spent energy will not be recovered." confirmLabel="Confirm Retreat" cancelLabel="Stay Focused" isDanger={true} onConfirm={() => actions.retreatFromManualDungeon()} onCancel={() => setShowAbortConfirm(false)} />
            <ConfirmationModal isOpen={showRetreatAtEntranceConfirm} title="Retreat to Forge?" message="If you leave the dungeon now without defeating the Boss, you will forfeit all loot and gold collected during this session. Do you wish to proceed?" confirmLabel="Confirm Retreat" cancelLabel="Continue Mission" isDanger={true} onConfirm={() => actions.retreatFromManualDungeon()} onCancel={() => setShowRetreatAtEntranceConfirm(false)} />

            {showResultPopup && (
                <div className="fixed inset-0 z-[700] bg-black/90 backdrop-blur-md flex items-center justify-center px-[10%] py-[15%] animate-in fade-in duration-500 pointer-events-auto overflow-hidden">
                    <div className="bg-stone-900 border-2 border-amber-600/50 rounded-3xl w-fit max-w-[600px] h-fit max-h-full min-h-[200px] min-w-[280px] shadow-[0_40px_80px_-20px_rgba(0,0,0,0.9)] overflow-hidden flex flex-col animate-in zoom-in-95 duration-500 mx-auto">
                        <div className="bg-amber-600 p-4 md:p-6 flex flex-col items-center text-center text-white shrink-0">
                            <Trophy className="w-8 h-8 md:w-12 md:h-12 mb-1 md:mb-2 animate-bounce" />
                            <h2 className="text-xl md:text-2xl font-black italic tracking-tighter uppercase font-serif leading-none px-4">Objective Complete!</h2>
                        </div>
                        <div className="p-4 md:p-6 space-y-6 overflow-y-auto custom-scrollbar flex-1">
                            <div className="space-y-2">
                                <h3 className="text-[8px] md:text-[10px] font-black text-stone-500 uppercase tracking-widest text-center">Treasury Secured</h3>
                                <div className="bg-stone-950 p-3 md:p-4 rounded-2xl border border-stone-800 flex flex-col items-center gap-1">
                                    <div className="flex items-center gap-2 text-stone-400 font-mono text-xs md:text-sm"><span>Base: {dungeon.goldReward}G</span><span>+</span><span className="text-amber-400">Bonus: {session.goldCollected}G</span></div>
                                    <div className="flex items-center gap-2 mt-1"><Coins className="w-5 h-5 md:w-6 md:h-6 text-amber-500" /><span className="text-xl md:text-3xl font-black font-mono text-stone-100">{dungeon.goldReward! + session.goldCollected} G</span></div>
                                </div>
                            </div>
                        </div>
                        <div className="p-4 md:p-6 pt-0 flex flex-col gap-2 md:gap-3 shrink-0">
                            <button onClick={() => actions.finishManualAssault()} className="w-full py-3 md:py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-xl shadow-xl flex items-center justify-center gap-2 transition-all active:scale-95 border-b-4 border-emerald-800 text-[10px] md:text-base uppercase tracking-widest px-8"><Package className="w-4 h-4 md:w-5 md:h-5" />SECURE LOOT & RETURN</button>
                            <button onClick={() => setShowResultPopup(false)} className="w-full py-2.5 md:py-4 bg-stone-800 hover:bg-stone-700 text-stone-300 font-black rounded-xl transition-all flex items-center justify-center gap-2 text-[10px] md:text-sm uppercase tracking-widest px-6"><ArrowRight className="w-4 h-4 md:w-5 md:h-5" /> KEEP EXPLORING</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default AssaultNavigator;

import { GameState, ManualDungeonSession, RoomType } from '../../types/game-state';
import { DUNGEONS } from '../../data/dungeons';
import { handleClaimExpedition } from './expedition';
import { TILLY_FOOTLOOSE } from '../../data/mercenaries';
import { MONSTERS } from '../../data/monsters';

const generateManualGrid = (width: number, height: number, locked: boolean, dungeonId: string, knownMercs: any[]) => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));
    const visited: boolean[][] = Array.from({ length: height }, () => Array(width).fill(false));

    const startX = Math.floor(Math.random() * width);
    const startY = Math.floor(Math.random() * height);
    grid[startY][startX] = 'ENTRANCE';
    visited[startY][startX] = true;

    let bossX, bossY;
    do {
        bossX = Math.floor(Math.random() * width);
        bossY = Math.floor(Math.random() * height);
    } while (Math.abs(bossX - startX) + Math.abs(bossY - startY) < 2);
    grid[bossY][bossX] = 'BOSS';

    if (locked) {
        let keyX, keyY;
        do {
            keyX = Math.floor(Math.random() * width);
            keyY = Math.floor(Math.random() * height);
        } while (grid[keyY][keyX] !== 'EMPTY');
        grid[keyY][keyX] = 'KEY';
    }

    if (dungeonId === 'dungeon_t1_rats' && !knownMercs.some(m => m.id === 'tilly_footloose')) {
        let npcX, npcY;
        do {
            npcX = Math.floor(Math.random() * width);
            npcY = Math.floor(Math.random() * height);
        } while (grid[npcY][npcX] !== 'EMPTY');
        grid[npcY][npcX] = 'NPC';
    }

    const totalTiles = width * height;
    const goldSpawnChance = 1 / totalTiles;
    const trapSpawnChance = 1 / totalTiles;

    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const roll = Math.random();
                if (roll < goldSpawnChance) {
                    grid[y][x] = 'GOLD';
                } else if (roll < goldSpawnChance + trapSpawnChance) {
                    grid[y][x] = 'TRAP';
                }
            }
        }
    }

    return { grid, visited, playerPos: { x: startX, y: startY } };
};

export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string, partyIds: string[] }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const { grid, visited, playerPos } = generateManualGrid(
        dungeon.gridWidth, 
        dungeon.gridHeight, 
        !!dungeon.isBossLocked,
        dungeon.id,
        state.knownMercenaries
    );

    let bossEntity = undefined;
    if (dungeon.id === 'dungeon_t1_rats') {
        bossEntity = { ...MONSTERS.rat_man };
    }

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos,
        hasKey: false,
        isBossLocked: !!dungeon.isBossLocked,
        isBossDefeated: false,
        bossEntity,
        goldCollected: 0,
        encounterStatus: 'NONE'
    };

    const updatedMercenaries = state.knownMercenaries.map(m => {
        if (payload.partyIds.includes(m.id)) {
            return { ...m, status: 'ON_EXPEDITION' as const };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercenaries,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`Squad has entered ${dungeon.name}. Tactical scanners active.`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus === 'ENCOUNTERED' || session.encounterStatus === 'BATTLE') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) return state;

    const targetRoom = session.grid[newY][newX];
    const isAlreadyVisited = session.visited[newY][newX];
    const cost = isAlreadyVisited ? -1 : (targetRoom === 'BOSS' ? dungeon.bossEnergy : dungeon.moveEnergy);

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    if (cost > 0 && party.some(m => (m.expeditionEnergy || 0) < cost)) {
        return { ...state, logs: [`Your squad is too exhausted to move further.`, ...state.logs] };
    }

    if (targetRoom === 'BOSS' && session.isBossLocked && !session.hasKey) {
        return { ...state, logs: [`The Boss chamber is sealed. You need a key.`, ...state.logs] };
    }

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextEnergy = Math.max(0, (m.expeditionEnergy || 0) - cost);
            let nextHp = m.currentHp;
            if (targetRoom === 'TRAP' && !isAlreadyVisited) nextHp = Math.max(0, m.currentHp - 25);
            return { ...m, expeditionEnergy: nextEnergy, currentHp: nextHp };
        }
        return m;
    });

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let logMsg = '';
    let encounterStatus: ManualDungeonSession['encounterStatus'] = 'NONE';

    if (targetRoom === 'GOLD' && !isAlreadyVisited) {
        extraGold = (dungeon.tier || 1) * 50;
        newGrid[newY][newX] = 'EMPTY';
        logMsg = `Treasury cache secured. (+${extraGold} G)`;
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        logMsg = `AMBUSH: Traps detected. Squad took heavy damage. (-25 HP)`;
    } else if (targetRoom === 'KEY' && !isAlreadyVisited) {
        logMsg = `Chamber key recovered.`;
        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'BOSS' && !session.isBossDefeated) {
        encounterStatus = 'ENCOUNTERED';
        logMsg = `CRITICAL ALERT: ${session.bossEntity?.name} identified. Defense systems active.`;
    }

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: {
            ...session,
            grid: newGrid,
            playerPos: { x: newX, y: newY },
            visited: newVisited,
            hasKey: targetRoom === 'KEY' ? true : session.hasKey,
            encounterStatus,
            goldCollected: session.goldCollected + extraGold
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const dummyExpId = `manual_clear_${Date.now()}`;
    const tempState: GameState = {
        ...state,
        activeExpeditions: [{
            id: dummyExpId, dungeonId: session.dungeonId, partyIds: session.partyIds,
            startTime: Date.now(), endTime: Date.now(), status: 'COMPLETED' as const
        }]
    };

    const finalState = handleClaimExpedition(tempState, { expeditionId: dummyExpId, rescuedNpcId: session.rescuedNpcId });
    const totalManualGold = session.goldCollected;

    return { 
        ...finalState, 
        stats: {
            ...finalState.stats,
            gold: finalState.stats.gold + totalManualGold,
            dailyFinancials: { ...finalState.stats.dailyFinancials, incomeDungeon: finalState.stats.dailyFinancials.incomeDungeon + totalManualGold }
        },
        activeManualDungeon: null, 
        showManualDungeonOverlay: false 
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const isDefeat = session.encounterStatus === 'DEFEAT';

    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextStatus: any = 'HIRED';
            if (isDefeat) {
                const roll = Math.random();
                if (roll < 0.15) nextStatus = 'DEAD';
                else if (roll < 0.60) nextStatus = 'INJURED';
            }
            return { ...m, status: nextStatus, assignedExpeditionId: undefined };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: [isDefeat ? 'CRITICAL FAILURE: The squad was overrun.' : 'The squad retreated from the area.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    const currentSession = state.activeManualDungeon;
    if (!currentSession) return state;

    let newGrid = [...currentSession.grid.map(row => [...row])];
    newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';

    return {
        ...state,
        activeManualDungeon: { ...currentSession, grid: newGrid, npcFound: true, rescuedNpcId: payload.npcId },
        logs: [`Rescue initiated for survivor. Secure the area for extraction.`, ...state.logs]
    };
};

import React, { useEffect, useRef, useState, useMemo } from 'react';
import Phaser from 'phaser';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import DungeonScene from '../../../game/DungeonScene';
import DialogueBox from '../../DialogueBox';
import { 
    Key, Zap, LogOut, X, ChevronUp, ChevronDown, ChevronLeft, ChevronRight, Lock, Unlock, Target, Shield, Sword, Skull
} from 'lucide-react';
import ConfirmationModal from '../../modals/ConfirmationModal';
import { calculateCombatPower, calculateMercenaryPower } from '../../../utils/combatLogic';
import DungeonCombatView from './DungeonCombatView';

type CameraMode = 'LOCKED' | 'ADAPTIVE' | 'FREE';

const AssaultNavigator = () => {
    const { state, actions } = useGame();
    const session = state.activeManualDungeon;
    const gameRef = useRef<Phaser.Game | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isReady, setIsReady] = useState(false);
    const [showRetreatConfirm, setShowRetreatConfirm] = useState(false);
    const [cameraMode, setCameraMode] = useState<CameraMode>('LOCKED');

    const [isSquadStatusExpanded, setIsSquadStatusExpanded] = useState(true);
    const [lastDiscoveryMessage, setLastDiscoveryMessage] = useState<string>('');
    const [rescueStep, setRescueStep] = useState<'NONE' | 'DIALOGUE' | 'DONE'>('NONE');

    const dungeon = session ? DUNGEONS.find(d => d.id === session.dungeonId) : null;
    const party = session ? state.knownMercenaries.filter(m => session.partyIds.includes(m.id)) : [];
    const avgEnergy = party.length > 0 ? party.reduce((sum, m) => sum + (m.expeditionEnergy || 0), 0) / (party.length || 1) : 0;

    const isEncountered = session?.encounterStatus === 'ENCOUNTERED';
    const isBattle = session?.encounterStatus === 'BATTLE';
    const isVictory = session?.encounterStatus === 'VICTORY';
    const isDefeat = session?.encounterStatus === 'DEFEAT';

    const bossPower = useMemo(() => {
        if (!session?.bossEntity) return 0;
        return calculateCombatPower(session.bossEntity.stats, 'Fighter' as any, 'PHYSICAL');
    }, [session?.bossEntity]);

    const fleeChance = useMemo(() => {
        if (!session || !session.bossEntity) return 0;
        const partyCP = party.reduce((sum, m) => sum + calculateMercenaryPower(m), 0);
        return Math.max(5, Math.min(95, Math.round(50 + (partyCP - bossPower) / 5)));
    }, [session, party, bossPower]);

    const handleDpadMove = (dx: number, dy: number) => {
        if (isEncountered || isBattle) return;
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.move(dx, dy);
    };

    const handleStartCombat = () => {
        if (!session) return;
        actions.toggleManualDungeonOverlay(true); 
        // Reducer에 직접 액션은 없지만 UI 상태로 조작
        const newSession = { ...session, encounterStatus: 'BATTLE' as const };
        state.activeManualDungeon = newSession; 
        actions.moveInManualDungeon(0, 0); // 상태 강제 트리거
    };

    const handleFlee = () => {
        if (!session) return;
        const roll = Math.random() * 100;
        if (roll < fleeChance) {
            actions.showToast("SUCCESSFUL FLEE: The squad broke contact!");
            const newSession = { ...session, encounterStatus: 'NONE' as const };
            state.activeManualDungeon = newSession;
            actions.moveInManualDungeon(0, 0);
        } else {
            actions.showToast("FLEE FAILED! The enemy strikes as you turn!");
            actions.moveInManualDungeon(0, 0); // 턴 소비 패널티
        }
    };

    useEffect(() => {
        const checkSize = () => {
            if (containerRef.current && containerRef.current.clientWidth > 0) setIsReady(true);
            else requestAnimationFrame(checkSize);
        };
        checkSize();
    }, []);

    useEffect(() => {
        if (!session || !dungeon) return;
        const room = session.grid[session.playerPos.y][session.playerPos.x];
        if (isEncountered) setLastDiscoveryMessage(`CRITICAL ALERT: ${session.bossEntity?.name} identified. Power Level: ${bossPower} CP. Probability of escape: ${fleeChance}%. Stand ground or retreat?`);
        else if (room === 'NPC' && !session.npcFound) setLastDiscoveryMessage("Life-sign confirmed. Survivor identified. Initializing rescue protocols. What is the command?");
        else if (room === 'BOSS' && session.isBossDefeated) setLastDiscoveryMessage("High-Value Target neutralized. The area is now secure. Proceed to extraction?");
        else if (room === 'ENTRANCE' && lastDiscoveryMessage === '') setLastDiscoveryMessage(`Infiltration of ${dungeon.name} complete. Commencing grid sweep.`);
        else setLastDiscoveryMessage("Sector clear. No immediate hostiles detected. What is the next move?");
    }, [session?.playerPos, session?.encounterStatus, dungeon?.name]);

    useEffect(() => {
        if (!isReady || !containerRef.current || !session || !dungeon) return;
        if (!gameRef.current) {
            const config: Phaser.Types.Core.GameConfig = {
                type: Phaser.AUTO, parent: containerRef.current, width: containerRef.current.clientWidth, height: containerRef.current.clientHeight, backgroundColor: 'transparent', transparent: true, scene: [DungeonScene],
                scale: { mode: Phaser.Scale.RESIZE, autoCenter: Phaser.Scale.CENTER_BOTH }
            };
            const game = new Phaser.Game(config);
            gameRef.current = game;
            game.scene.start('DungeonScene', { session, moveEnergy: dungeon.moveEnergy, bossEnergy: dungeon.bossEnergy, onMove: (dx, dy) => actions.moveInManualDungeon(dx, dy), cameraMode: cameraMode });
        } else {
            const scene = gameRef.current.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) { scene.updateSession(session); scene.setCameraMode(cameraMode); }
        }
    }, [isReady, session, actions, dungeon, cameraMode]);

    if (!session || !dungeon) return null;

    return (
        <div className="absolute inset-0 z-[100] bg-stone-950 flex flex-col animate-in fade-in duration-500 overflow-hidden">
            <div ref={containerRef} className={`absolute inset-0 z-0 transition-all duration-700 ${isBattle ? 'opacity-20 blur-lg' : 'opacity-100'}`} />

            {isBattle && (
                <DungeonCombatView 
                    session={session} 
                    party={party} 
                    boss={session.bossEntity!} 
                    fleeChance={fleeChance}
                    onFinish={(win) => {
                        const nextStatus = win ? 'VICTORY' : 'DEFEAT';
                        const newSession = { ...session, encounterStatus: nextStatus as any, isBossDefeated: win };
                        state.activeManualDungeon = newSession;
                        actions.moveInManualDungeon(0, 0);
                    }}
                    onFlee={handleFlee}
                />
            )}

            {/* Squad HUD */}
            {!isBattle && (
                <div className="absolute top-20 left-4 z-50 flex flex-col gap-2 w-48 md:w-56 pointer-events-none">
                    <button onClick={() => setIsSquadStatusExpanded(!isSquadStatusExpanded)} className="bg-stone-950/40 backdrop-blur-md border border-white/10 rounded-lg p-2 flex items-center justify-between pointer-events-auto hover:bg-stone-900/60 transition-colors">
                        <div className="flex items-center gap-2"><Shield className="w-3.5 h-3.5 text-blue-400" /><span className="text-[10px] font-black text-blue-100 uppercase tracking-widest">Squad Status</span></div>
                        {isSquadStatusExpanded ? <ChevronUp className="w-3.5 h-3.5 text-stone-500" /> : <ChevronDown className="w-3.5 h-3.5 text-stone-500" />}
                    </button>
                    {isSquadStatusExpanded && party.map(merc => {
                        const hpPer = (merc.currentHp / merc.maxHp) * 100;
                        return (
                            <div key={merc.id} className="bg-stone-900/80 border border-stone-700/50 p-2 rounded-xl backdrop-blur-md shadow-lg animate-in slide-in-from-top-2 duration-300">
                                <div className="flex items-center gap-2 mb-1.5"><div className="w-6 h-6 rounded-full bg-stone-800 flex items-center justify-center border border-white/5 text-xs shadow-inner shrink-0">{merc.icon}</div><div className="min-w-0 flex-1"><div className="text-[10px] font-black text-white truncate leading-none uppercase">{merc.name.split(' ')[0]}</div><div className="text-[7px] text-stone-500 font-bold uppercase tracking-tighter truncate">{merc.job} • LV.{merc.level}</div></div></div>
                                <div className="flex justify-between text-[6px] font-mono text-stone-400 px-0.5 uppercase tracking-tighter mb-0.5"><span>HP</span><span>{Math.floor(merc.currentHp)}/{merc.maxHp}</span></div>
                                <div className="w-full bg-stone-950 h-1 rounded-full overflow-hidden border border-white/5"><div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-600 animate-pulse' : 'bg-red-500'}`} style={{ width: `${hpPer}%` }} /></div>
                            </div>
                        );
                    })}
                </div>
            )}

            {/* Controls & Dialogue */}
            <div className={`absolute bottom-0 left-0 right-0 z-40 px-[2%] pb-[2%] flex flex-col items-end pointer-events-none transition-all duration-500 ${isBattle ? 'translate-y-full opacity-0' : 'translate-y-0 opacity-100'}`}>
                <div className={`mb-4 transition-all duration-500 pointer-events-auto ${isEncountered || rescueStep === 'DIALOGUE' ? 'opacity-0 scale-90 translate-y-4 pointer-events-none' : 'opacity-100 scale-100 translate-y-0'}`}>
                    <div className="grid grid-cols-3 gap-2 p-2 bg-stone-900/40 backdrop-blur-md rounded-[1.5rem] border border-white/5 shadow-2xl" style={{ width: '15vmin', height: '15vmin', minWidth: '100px', minHeight: '100px' }}>
                        <div />
                        <button onClick={() => handleDpadMove(0, -1)} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800/80 border-stone-600 text-stone-200 active:scale-90"><ChevronUp className="w-[60%] h-[60%]" /></button>
                        <div />
                        <button onClick={() => handleDpadMove(-1, 0)} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800/80 border-stone-600 text-stone-200 active:scale-90"><ChevronLeft className="w-[60%] h-[60%]" /></button>
                        <button onClick={() => setCameraMode(prev => prev === 'LOCKED' ? 'ADAPTIVE' : prev === 'ADAPTIVE' ? 'FREE' : 'LOCKED')} className={`w-full h-full rounded-lg border flex items-center justify-center transition-all ${cameraMode !== 'FREE' ? 'bg-amber-500/20 border-amber-500/50 text-amber-500' : 'bg-stone-800/40 border-stone-700 text-stone-500'}`}>{cameraMode === 'LOCKED' ? <Lock className="w-[50%] h-[50%]" /> : cameraMode === 'ADAPTIVE' ? <Target className="w-[50%] h-[50%]" /> : <Unlock className="w-[50%] h-[50%]" />}</button>
                        <button onClick={() => handleDpadMove(1, 0)} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800/80 border-stone-600 text-stone-200 active:scale-90"><ChevronRight className="w-[60%] h-[60%]" /></button>
                        <div />
                        <button onClick={() => handleDpadMove(0, 1)} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800/80 border-stone-600 text-stone-200 active:scale-90"><ChevronDown className="w-[60%] h-[60%]" /></button>
                        <div />
                    </div>
                </div>
                <div className="w-full pointer-events-auto">
                    <DialogueBox 
                        speaker={isEncountered ? "Combat Interface" : "Tactical Link"} 
                        text={lastDiscoveryMessage} 
                        options={isEncountered ? [
                            { label: "ENGAGE TARGET", action: handleStartCombat, variant: 'primary' },
                            { label: `FLEE (${fleeChance}%)`, action: handleFlee, variant: 'danger' }
                        ] : (isVictory || isDefeat) ? [
                            { label: isVictory ? "Secure Loot & Extract" : "Emergency Retreat", action: () => isVictory ? actions.finishManualAssault() : actions.retreatFromManualDungeon(), variant: 'primary' }
                        ] : [
                            { label: "Retreat", action: () => setShowRetreatConfirm(true), variant: 'neutral' }
                        ]} 
                    />
                </div>
            </div>

            <ConfirmationModal isOpen={showRetreatConfirm} title="Abort Assault?" message="Recalling the squad will forfeit all progress and loot. Confirm extraction?" onConfirm={() => actions.retreatFromManualDungeon()} onCancel={() => setShowRetreatConfirm(false)} isDanger={true} />
        </div>
    );
};

export default AssaultNavigator;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Shield, Sword, Activity, Skull, Zap, Wind, Target, FastForward, LogOut } from 'lucide-react';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';
import { ManualDungeonSession } from '../../../types/game-state';
import { calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, applyEquipmentBonuses, mergePrimaryStats } from '../../../models/Stats';
import { getAssetUrl } from '../../../utils';

const ACTION_THRESHOLD = 1000;

interface CombatLogEntry {
    msg: string;
    team: 'PLAYER' | 'ENEMY';
    isCrit?: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    boss: Monster;
    fleeChance: number;
    onFinish: (win: boolean) => void;
    onFlee: () => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ party, boss, fleeChance, onFinish, onFlee }) => {
    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), Object.values(m.equipment).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, gauge: 0, lastAttacker: false, lastDamaged: false };
    }));

    const [bossState, setBossState] = useState({
        ...boss,
        gauge: 0,
        lastAttacker: false,
        lastDamaged: false
    });

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [isPaused, setIsPaused] = useState(false);
    const [retreatRequested, setRetreatRequested] = useState(false);
    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);

    const addLog = (msg: string, team: 'PLAYER' | 'ENEMY', isCrit = false) => {
        setLogs(prev => [{ msg, team, isCrit }, ...prev].slice(0, 50));
    };

    const processAttack = useCallback(() => {
        if (isPaused) return;

        setPartyState(prevParty => {
            const nextParty = [...prevParty];
            setBossState(prevBoss => {
                const nextBoss = { ...prevBoss };

                // 1. 게이지 충전
                nextParty.forEach(p => { if (p.currentHp > 0) p.gauge += p.derived.speed * 0.4; });
                nextBoss.gauge += nextBoss.stats.speed * 0.4;

                // 2. 플레이어 턴 처리
                nextParty.forEach(p => {
                    if (p.gauge >= ACTION_THRESHOLD && p.currentHp > 0) {
                        p.gauge -= ACTION_THRESHOLD;

                        if (retreatRequested) {
                            onFlee(); // 도주 성공 시나리오 연계 가능
                            return;
                        }

                        const res = calculateCombatResult(p.derived, nextBoss.stats, p.job, p.derived.magicalAttack > p.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL');
                        p.lastAttacker = true;
                        setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastAttacker: false } : c)), 200);

                        if (res.isHit) {
                            nextBoss.currentHp = Math.max(0, nextBoss.currentHp - res.damage);
                            nextBoss.lastDamaged = true;
                            addLog(`${p.name.split(' ')[0]} hit ${nextBoss.name} for ${res.damage}${res.isCrit ? "!" : ""}`, 'PLAYER', res.isCrit);
                            setTimeout(() => setBossState(curr => ({ ...curr, lastDamaged: false })), 200);
                        } else {
                            addLog(`${p.name.split(' ')[0]} missed.`, 'PLAYER');
                        }
                    }
                });

                // 3. 적 턴 처리
                if (nextBoss.gauge >= ACTION_THRESHOLD && nextBoss.currentHp > 0) {
                    nextBoss.gauge -= ACTION_THRESHOLD;
                    const targets = nextParty.filter(p => p.currentHp > 0);
                    if (targets.length > 0) {
                        const target = targets[Math.floor(Math.random() * targets.length)];
                        const res = calculateCombatResult(nextBoss.stats, target.derived, 'Fighter' as any, 'PHYSICAL');
                        nextBoss.lastAttacker = true;
                        setTimeout(() => setBossState(curr => ({ ...curr, lastAttacker: false })), 200);

                        if (res.isHit) {
                            target.currentHp = Math.max(0, target.currentHp - res.damage);
                            target.lastDamaged = true;
                            addLog(`${nextBoss.name} struck ${target.name.split(' ')[0]} for ${res.damage}`, 'ENEMY');
                            setTimeout(() => setPartyState(curr => curr.map(c => c.id === target.id ? { ...c, lastDamaged: false } : c)), 200);
                        }
                    }
                }

                return nextBoss;
            });
            return nextParty;
        });
    }, [isPaused, retreatRequested, onFlee]);

    useEffect(() => {
        battleInterval.current = setInterval(processAttack, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processAttack]);

    // 종료 체크
    useEffect(() => {
        if (bossState.currentHp <= 0) {
            setIsPaused(true);
            setTimeout(() => onFinish(true), 1000);
        } else if (partyState.every(p => p.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(false), 1000);
        }
    }, [bossState.currentHp, partyState, onFinish]);

    return (
        <div className="fixed inset-0 z-[110] flex flex-col bg-stone-950/80 backdrop-blur-md animate-in zoom-in-95 duration-500">
            {/* Header: Encounter Status */}
            <div className="p-4 md:p-6 bg-red-950/40 border-b border-red-800/30 flex justify-between items-center shrink-0">
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-red-900/40 rounded-xl flex items-center justify-center border border-red-500/50 shadow-inner text-2xl animate-pulse">
                        <Skull className="text-red-500" />
                    </div>
                    <div>
                        <h2 className="text-white font-black uppercase text-xl md:text-2xl tracking-tighter">Engagement Protocol</h2>
                        <div className="flex items-center gap-2">
                            <span className="text-red-500 font-bold text-[10px] uppercase tracking-widest">Active Combat Zone</span>
                            <span className="w-1.5 h-1.5 rounded-full bg-red-600 animate-ping"></span>
                        </div>
                    </div>
                </div>
                <button 
                    onClick={() => setRetreatRequested(true)}
                    className="flex flex-col items-center px-6 py-2 bg-stone-800 hover:bg-red-900 border-2 border-stone-700 rounded-xl text-stone-300 transition-all active:scale-95"
                >
                    <LogOut className="w-4 h-4 mb-0.5" />
                    <span className="text-[10px] font-black uppercase tracking-widest">Retreat ({fleeChance}%)</span>
                </button>
            </div>

            <div className="flex-1 flex flex-col md:flex-row p-4 gap-4 overflow-hidden">
                {/* Party Side */}
                <div className="flex-1 flex flex-col gap-3 overflow-y-auto no-scrollbar justify-center">
                    {partyState.map(p => (
                        <div key={p.id} className={`bg-stone-900 border-2 rounded-2xl p-3 md:p-4 flex gap-3 md:gap-4 transition-all ${p.lastDamaged ? 'border-red-600 ring-4 ring-red-600/20' : 'border-stone-800'} ${p.currentHp <= 0 ? 'grayscale opacity-40' : ''}`}>
                            <div className="w-14 h-14 md:w-20 md:h-20 bg-stone-850 rounded-xl flex items-center justify-center text-3xl md:text-5xl shadow-inner shrink-0 relative overflow-hidden">
                                {p.icon}
                                <div className="absolute inset-0 bg-red-600/20 animate-pulse" style={{ opacity: p.lastDamaged ? 1 : 0 }} />
                            </div>
                            <div className="flex-1 min-w-0 flex flex-col justify-center">
                                <div className="flex justify-between items-end mb-2">
                                    <span className="font-black text-stone-100 text-xs md:text-lg uppercase truncate">{p.name}</span>
                                    <span className="font-mono font-black text-red-500 text-[10px] md:text-sm">{Math.floor(p.currentHp)}/{p.derived.maxHp}</span>
                                </div>
                                <div className="space-y-1.5">
                                    <div className="h-2 bg-stone-950 rounded-full overflow-hidden border border-white/5"><div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(p.currentHp/p.derived.maxHp)*100}%` }} /></div>
                                    <div className="h-1.5 bg-stone-950 rounded-full overflow-hidden border border-white/5"><div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} /></div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

                {/* VS Center */}
                <div className="flex flex-col items-center justify-center shrink-0">
