                                </div>
                                <div className="h-2 bg-stone-950 rounded-full overflow-hidden border border-white/5"><div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(bossState.gauge/ACTION_THRESHOLD)*100}%` }} /></div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Bottom Combat Logs */}
            <div className="h-24 md:h-40 bg-stone-900/90 border-t border-red-900/30 p-3 flex flex-col overflow-hidden shrink-0">
                <div className="flex items-center gap-2 mb-2 px-2">
                    <Activity className="w-3 h-3 text-red-500 animate-pulse" />
                    <span className="text-[8px] md:text-[10px] font-black text-stone-500 uppercase tracking-widest">Tactical Log Feed</span>
                </div>
                <div className="flex-1 overflow-y-auto custom-scrollbar space-y-1">
                    {logs.map((log, idx) => (
                        <div key={idx} className={`text-[10px] md:text-xs font-mono px-4 py-0.5 border-l-2 ${log.team === 'PLAYER' ? 'border-blue-500 text-blue-100' : 'border-red-500 text-red-100'} ${log.isCrit ? 'bg-amber-900/20 font-black italic' : ''}`}>
                            <span className="opacity-50 mr-2">[{new Date().toLocaleTimeString([], { hour12: false, minute: '2-digit', second: '2-digit' })}]</span>
                            {log.msg}
                        </div>
                    ))}
                    {logs.length === 0 && <div className="h-full flex items-center justify-center text-stone-700 italic text-xs">Awaiting primary ignition...</div>}
                </div>
            </div>
        </div>
    );
};

export default DungeonCombatView;

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';
import { ManualDungeonSession, RoomType } from '../types/game-state';

export type CameraMode = 'LOCKED' | 'ADAPTIVE' | 'FREE';

export interface DungeonSceneData {
    session: ManualDungeonSession;
    moveEnergy: number;
    bossEnergy: number;
    onMove: (dx: number, dy: number) => void;
    cameraMode: CameraMode;
}

export default class DungeonScene extends Phaser.Scene {
    public add!: Phaser.GameObjects.GameObjectFactory;
    public tweens!: Phaser.Tweens.TweenManager;
    public scale!: Phaser.Scale.ScaleManager;
    public cameras!: Phaser.Cameras.Scene2D.CameraManager;
    public input!: Phaser.Input.InputPlugin;
    public time!: Phaser.Time.Clock;
    public events!: Phaser.Events.EventEmitter;
    public load!: Phaser.Loader.LoaderPlugin;
    public textures!: Phaser.Textures.TextureManager;
    public anims!: Phaser.Animations.AnimationManager;

    private session!: ManualDungeonSession;
    private onMoveCallback!: (dx: number, dy: number) => void;
    private cameraMode: CameraMode = 'LOCKED';

    private root!: Phaser.GameObjects.Container;
    private mapLayer!: Phaser.GameObjects.Container;
    private contentLayer!: Phaser.GameObjects.Container;
    private playerLayer!: Phaser.GameObjects.Container;
    private fxLayer!: Phaser.GameObjects.Container;

    private playerMarker!: Phaser.GameObjects.Container;
    private revealedTiles: Set<string> = new Set();
    private contentByCoord: Map<string, Phaser.GameObjects.Text> = new Map();

    private sprayEmitter!: Phaser.GameObjects.Particles.ParticleEmitter;
    private vignette!: Phaser.GameObjects.Graphics;
    private redFocusOverlay!: Phaser.GameObjects.Graphics;

    private tileWidth = 84;
    private tileGap = 8;
    private isMoving = false;

    private isDragging = false;
    private dragStartX = 0;
    private dragStartY = 0;

    private cameraTrackTimer: Phaser.Time.TimerEvent | null = null;
    private cameraTrackTween: Phaser.Tweens.Tween | null = null;

    constructor() {
        super('DungeonScene');
    }

    init(data: DungeonSceneData) {
        this.session = data.session;
        this.onMoveCallback = data.onMove;
        this.cameraMode = data.cameraMode ?? 'LOCKED';
    }

    preload() {
        this.load.image('sparkle', getAssetUrl('particle_spark1.png'));
        this.load.image('red_mist', getAssetUrl('particle_spark2.png'));
    }

    create() {
        this.cameras.main.setBackgroundColor(0x000000);

        this.root = this.add.container(0, 0);

        this.mapLayer = this.add.container(0, 0);
        this.contentLayer = this.add.container(0, 0);
        this.playerLayer = this.add.container(0, 0);
        this.fxLayer = this.add.container(0, 0).setDepth(100);

        this.root.add([this.mapLayer, this.contentLayer, this.playerLayer]);

        this.vignette = this.add.graphics().setDepth(200).setScrollFactor(0);
        this.redFocusOverlay = this.add.graphics().setDepth(210).setScrollFactor(0);

        this.sprayEmitter = this.add.particles(0, 0, 'sparkle', {
            speed: { min: 60, max: 140 },
            scale: { start: 0.6, end: 0 },
            alpha: { start: 1, end: 0 },
            lifespan: 800,
            gravityY: 80,
            blendMode: 'ADD',
            emitting: false
        });
        this.root.add(this.sprayEmitter);

        this.initialRender();
        this.createPlayer();
        this.alignViewToPlayer(); 

        this.scale.on('resize', () => {
            this.alignViewToPlayer();
            this.drawRedFocus();
        }, this);
        this.setupDragControls();

        this.drawRedFocus();
    }

    public setCameraMode(mode: CameraMode) {
        this.cameraMode = mode;
        if (mode === 'LOCKED' && !this.isMoving) {
            this.alignViewToPlayer(); 
        }
    }

    private drawRedFocus() {
        const { width, height } = this.scale;
        this.redFocusOverlay.clear();

        const isFocusNeeded = this.session.encounterStatus === 'ENCOUNTERED' || this.session.encounterStatus === 'BATTLE';
        if (!isFocusNeeded) return;

        // 붉은계열 스프레이/비네트 효과
        const thickness = 60;
        this.redFocusOverlay.fillStyle(0x7f1d1d, 0.4);

        // 상단
        this.redFocusOverlay.fillRect(0, 0, width, thickness);
        // 하단
        this.redFocusOverlay.fillRect(0, height - thickness, width, thickness);
        // 좌측
        this.redFocusOverlay.fillRect(0, thickness, thickness, height - thickness * 2);
        // 우측
        this.redFocusOverlay.fillRect(width - thickness, thickness, thickness, height - thickness * 2);

        // 연무 입자 효과 (랜덤)
        if (Math.random() > 0.7) {
            const rx = Math.random() * width;
            const ry = Math.random() * height;
            if (rx < thickness || rx > width - thickness || ry < thickness || ry > height - thickness) {
                this.add.particles(rx, ry, 'red_mist', {
                    speed: { min: 10, max: 30 },
                    scale: { start: 0.8, end: 0 },
                    alpha: { start: 0.4, end: 0 },
                    lifespan: 2000,
                    tint: 0xef4444,
                    blendMode: 'ADD'
                }).explode(3);
            }
        }
    }

    private setupDragControls() {
        this.input.on('pointerdown', (pointer: Phaser.Input.Pointer) => {
            if (this.session.encounterStatus === 'BATTLE') return;
            this.isDragging = true;
            this.dragStartX = pointer.x - this.root.x;
            this.dragStartY = pointer.y - this.root.y;

            if (this.cameraTrackTween) {
                this.cameraTrackTween.stop();
                this.cameraTrackTween = null;
            }
        });

        this.input.on('pointermove', (pointer: Phaser.Input.Pointer) => {
            if (!this.isDragging) return;
            this.root.setPosition(pointer.x - this.dragStartX, pointer.y - this.dragStartY);
        });

        this.input.on('pointerup', () => { this.isDragging = false; });
    }

    private initialRender() {
        const { grid, visited } = this.session;
        const rows = grid.length;
        const cols = grid[0].length;

        this.mapLayer.removeAll(true);
        this.contentLayer.removeAll(true);
        this.revealedTiles.clear();
        this.contentByCoord.clear();

        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
                if (visited[y][x]) {
                    this.drawRevealedTile(x, y, grid[y][x], false);
                }
            }
        }
    }

    private drawRevealedTile(x: number, y: number, type: RoomType, animate: boolean) {
        const key = `${x},${y}`;
        const tx = x * (this.tileWidth + this.tileGap);
        const ty = y * (this.tileWidth + this.tileGap);

        if (!this.revealedTiles.has(key)) {
            const tile = this.add.rectangle(tx, ty, this.tileWidth, this.tileWidth, 0x1c1917)
                .setStrokeStyle(2, 0x44403c)
                .setOrigin(0.5);
            this.mapLayer.add(tile);
            if (animate) {
                this.sprayEmitter.emitParticleAt(tx, ty, 15);
                tile.setAlpha(0).setScale(0.7);
                this.tweens.add({ targets: tile, alpha: 1, scale: 1, duration: 600, ease: 'Back.easeOut' });
            }
            this.revealedTiles.add(key);
        }

        const content = this.createRoomContents(type, tx, ty);
        if (content) {
            this.contentByCoord.set(key, content);
            if (animate) {
                content.setAlpha(0).setScale(0.5);
                this.tweens.add({ targets: content, alpha: 1, scale: 1, duration: 500, delay: 200, ease: 'Cubic.easeOut' });
            }
        }
    }

    private createRoomContents(type: RoomType, x: number, y: number) {
        let content: Phaser.GameObjects.Text | null = null;
        switch (type) {
            case 'BOSS':
                content = this.add.text(x, y, '💀', { fontSize: '32px' }).setOrigin(0.5);
                if (this.session.isBossLocked && !this.session.hasKey) content.setAlpha(0.3);
                break;
            case 'KEY': content = this.add.text(x, y, '🔑', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'ENTRANCE': content = this.add.text(x, y, '🚪', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'GOLD': content = this.add.text(x, y, '💰', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'TRAP': content = this.add.text(x, y, '🕸️', { fontSize: '28px' }).setOrigin(0.5); break;
            case 'NPC':
                if (this.session.npcFound) return null;
                content = this.add.text(x, y, '👤', { fontSize: '30px' }).setOrigin(0.5);
                break;
        }
        if (content) this.contentLayer.add(content);
        return content;
    }

    private createPlayer() {
        const { x, y } = this.session.playerPos;
        const px = x * (this.tileWidth + this.tileGap);
        const py = y * (this.tileWidth + this.tileGap);
        const visual = this.add.container(0, 0);
        const circle = this.add.circle(0, 0, 26, 0x6366f1, 0.9).setStrokeStyle(3, 0xffffff);
        const icon = this.add.text(0, 0, '👤', { fontSize: '24px' }).setOrigin(0.5);
        visual.add([circle, icon]);
        this.playerMarker = this.add.container(px, py, [visual]);
        this.playerLayer.add(this.playerMarker);
        this.tweens.add({ targets: visual, y: -8, duration: 800, yoyo: true, repeat: -1, ease: 'Sine.easeInOut' });
    }

    private alignViewToPlayer() {
        const { width, height } = this.scale;
        const { x, y } = this.session.playerPos;
        const currentScale = 1.0;
        const targetX = x * (this.tileWidth + this.tileGap);
        const targetY = y * (this.tileWidth + this.tileGap);
        this.root.setPosition((width / 2) - (targetX * currentScale), (height / 2) - (targetY * currentScale));
    }

    public updateSession(newSession: ManualDungeonSession) {
        const oldStatus = this.session.encounterStatus;
        this.session = newSession;
        if (oldStatus !== newSession.encounterStatus) this.drawRedFocus();
        const { width, height } = this.scale;
        const { x, y } = newSession.playerPos;
        const targetLocalX = x * (this.tileWidth + this.tileGap);
        const targetLocalY = y * (this.tileWidth + this.tileGap);
        this.isMoving = true;
        this.tweens.add({
            targets: this.playerMarker, x: targetLocalX, y: targetLocalY, duration: 300, ease: 'Cubic.out',
            onComplete: () => { this.isMoving = false; this.initialRender(); }
        });
        if (this.cameraMode !== 'FREE') {
            const targetRootX = (width / 2) - targetLocalX;
            const targetRootY = (height / 2) - targetLocalY;
            if (this.cameraTrackTween) this.cameraTrackTween.stop();
            this.cameraTrackTween = this.tweens.add({ targets: this.root, x: targetRootX, y: targetRootY, duration: 600, ease: 'Cubic.out' });
        }
    }

    public move(dx: number, dy: number) {
        if (this.isMoving) return;
        this.onMoveCallback(dx, dy);
    }
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Shield, Sword, Activity, Skull, Zap, Wind, Target, FastForward, LogOut } from 'lucide-react';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';
import { ManualDungeonSession } from '../../../types/game-state';
import { calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, applyEquipmentBonuses, mergePrimaryStats } from '../../../models/Stats';
import { getAssetUrl } from '../../../utils';

const ACTION_THRESHOLD = 1000;

interface CombatLogEntry {
    msg: string;
    team: 'PLAYER' | 'ENEMY';
    isCrit?: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    boss: Monster;
    fleeChance: number;
    onFinish: (win: boolean) => void;
    onFlee: () => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ party, boss, fleeChance, onFinish, onFlee }) => {
    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        // FIX: Explicitly cast Object.values(m.equipment) to any[] to avoid 'unknown' type inference which prevents accessing .stats
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), (Object.values(m.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, gauge: 0, lastAttacker: false, lastDamaged: false };
    }));

    const [bossState, setBossState] = useState({
        ...boss,
        gauge: 0,
        lastAttacker: false,
        lastDamaged: false
    });

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [isPaused, setIsPaused] = useState(false);
    const [retreatRequested, setRetreatRequested] = useState(false);
    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);

    const addLog = (msg: string, team: 'PLAYER' | 'ENEMY', isCrit = false) => {
        setLogs(prev => [{ msg, team, isCrit }, ...prev].slice(0, 50));
    };

    const processAttack = useCallback(() => {
        if (isPaused) return;

        setPartyState(prevParty => {
            const nextParty = [...prevParty];
            setBossState(prevBoss => {
                const nextBoss = { ...prevBoss };

                // 1. 게이지 충전
                nextParty.forEach(p => { if (p.currentHp > 0) p.gauge += p.derived.speed * 0.4; });
                nextBoss.gauge += nextBoss.stats.speed * 0.4;

                // 2. 플레이어 턴 처리
                nextParty.forEach(p => {
                    if (p.gauge >= ACTION_THRESHOLD && p.currentHp > 0) {
                        p.gauge -= ACTION_THRESHOLD;

                        if (retreatRequested) {
                            onFlee(); // 도주 성공 시나리오 연계 가능
                            return;
                        }

                        const res = calculateCombatResult(p.derived, nextBoss.stats, p.job, p.derived.magicalAttack > p.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL');
                        p.lastAttacker = true;
                        setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastAttacker: false } : c)), 200);

                        if (res.isHit) {
                            nextBoss.currentHp = Math.max(0, nextBoss.currentHp - res.damage);
                            nextBoss.lastDamaged = true;
                            addLog(`${p.name.split(' ')[0]} hit ${nextBoss.name} for ${res.damage}${res.isCrit ? "!" : ""}`, 'PLAYER', res.isCrit);
                            setTimeout(() => setBossState(curr => ({ ...curr, lastDamaged: false })), 200);
                        } else {
                            addLog(`${p.name.split(' ')[0]} missed.`, 'PLAYER');
                        }
                    }
                });

                // 3. 적 턴 처리
                if (nextBoss.gauge >= ACTION_THRESHOLD && nextBoss.currentHp > 0) {
                    nextBoss.gauge -= ACTION_THRESHOLD;
                    const targets = nextParty.filter(p => p.currentHp > 0);
                    if (targets.length > 0) {
                        const target = targets[Math.floor(Math.random() * targets.length)];
                        const res = calculateCombatResult(nextBoss.stats, target.derived, 'Fighter' as any, 'PHYSICAL');
                        nextBoss.lastAttacker = true;
                        setTimeout(() => setBossState(curr => ({ ...curr, lastAttacker: false })), 200);

                        if (res.isHit) {
                            target.currentHp = Math.max(0, target.currentHp - res.damage);
                            target.lastDamaged = true;
                            addLog(`${nextBoss.name} struck ${target.name.split(' ')[0]} for ${res.damage}`, 'ENEMY');
                            setTimeout(() => setPartyState(curr => curr.map(c => c.id === target.id ? { ...c, lastDamaged: false } : c)), 200);
                        }
                    }
                }

                return nextBoss;
            });
            return nextParty;
        });
    }, [isPaused, retreatRequested, onFlee]);

    useEffect(() => {
        battleInterval.current = setInterval(processAttack, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processAttack]);

    // 종료 체크
    useEffect(() => {
        if (bossState.currentHp <= 0) {
            setIsPaused(true);
            setTimeout(() => onFinish(true), 1000);
        } else if (partyState.every(p => p.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(false), 1000);
        }
    }, [bossState.currentHp, partyState, onFinish]);

    return (
        <div className="fixed inset-0 z-[110] flex flex-col bg-stone-950/80 backdrop-blur-md animate-in zoom-in-95 duration-500">
            {/* Header: Encounter Status */}
            <div className="p-4 md:p-6 bg-red-950/40 border-b border-red-800/30 flex justify-between items-center shrink-0">
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-red-900/40 rounded-xl flex items-center justify-center border border-red-500/50 shadow-inner text-2xl animate-pulse">
                        <Skull className="text-red-500" />
                    </div>
                    <div>
                        <h2 className="text-white font-black uppercase text-xl md:text-2xl tracking-tighter">Engagement Protocol</h2>
                        <div className="flex items-center gap-2">
                            <span className="text-red-500 font-bold text-[10px] uppercase tracking-widest">Active Combat Zone</span>
                            <span className="w-1.5 h-1.5 rounded-full bg-red-600 animate-ping"></span>
                        </div>
                    </div>
                </div>
                <button 
                    onClick={() => setRetreatRequested(true)}
                    className="flex flex-col items-center px-6 py-2 bg-stone-800 hover:bg-red-900 border-2 border-stone-700 rounded-xl text-stone-300 transition-all active:scale-95"
                >
                    <LogOut className="w-4 h-4 mb-0.5" />
                    <span className="text-[10px] font-black uppercase tracking-widest">Retreat ({fleeChance}%)</span>
                </button>
            </div>

            <div className="flex-1 flex flex-col md:flex-row p-4 gap-4 overflow-hidden">
                {/* Party Side */}
                <div className="flex-1 flex flex-col gap-3 overflow-y-auto no-scrollbar justify-center">
                    {partyState.map(p => (
                        <div key={p.id} className={`bg-stone-900 border-2 rounded-2xl p-3 md:p-4 flex gap-3 md:gap-4 transition-all ${p.lastDamaged ? 'border-red-600 ring-4 ring-red-600/20' : 'border-stone-800'} ${p.currentHp <= 0 ? 'grayscale opacity-40' : ''}`}>
                            <div className="w-14 h-14 md:w-20 md:h-20 bg-stone-850 rounded-xl flex items-center justify-center text-3xl md:text-5xl shadow-inner shrink-0 relative overflow-hidden">
                                {p.icon}
                                <div className="absolute inset-0 bg-red-600/20 animate-pulse" style={{ opacity: p.lastDamaged ? 1 : 0 }} />
                            </div>
                            <div className="flex-1 min-w-0 flex flex-col justify-center">
                                <div className="flex justify-between items-end mb-2">
                                    <span className="font-black text-stone-100 text-xs md:text-lg uppercase truncate">{p.name}</span>
                                    <span className="font-mono font-black text-red-500 text-[10px] md:text-sm">{Math.floor(p.currentHp)}/{p.derived.maxHp}</span>
                                </div>
                                <div className="space-y-1.5">
                                    <div className="h-2 bg-stone-950 rounded-full overflow-hidden border border-white/5"><div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(p.currentHp/p.derived.maxHp)*100}%` }} /></div>
                                    <div className="h-1.5 bg-stone-950 rounded-full overflow-hidden border border-white/5"><div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} /></div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

                {/* VS Center */}
                <div className="flex flex-col items-center justify-center shrink-0">
                    <div className="w-16 h-16 rounded-full bg-stone-900 border-4 border-red-900/50 flex items-center justify-center text-2xl font-black italic text-stone-600 shadow-2xl">VS</div>
                </div>

                {/* Boss Side */}
                <div className="flex-1 flex flex-col items-center justify-center p-4">
                    <div className={`relative flex flex-col items-center transition-all ${bossState.lastDamaged ? 'scale-110' : 'scale-100'}`}>
                        <div className={`w-32 h-32 md:w-56 md:h-56 bg-stone-900 rounded-3xl border-4 flex items-center justify-center text-6xl md:text-9xl shadow-2xl transition-all ${bossState.lastDamaged ? 'border-white brightness-150' : 'border-red-900/50'}`}>
                            {bossState.icon}
