import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Shield, Sword, Activity, Skull, Zap, Wind, Target, FastForward, LogOut } from 'lucide-react';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';
import { ManualDungeonSession } from '../../../types/game-state';
import { calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, applyEquipmentBonuses, mergePrimaryStats } from '../../../models/Stats';
import { getAssetUrl } from '../../../utils';

const ACTION_THRESHOLD = 1000;

interface CombatLogEntry {
    msg: string;
    team: 'PLAYER' | 'ENEMY' | 'SYSTEM';
    isCrit?: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    boss: Monster;
    fleeChance: number;
    onFinish: (win: boolean) => void;
    onFlee: () => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ party, boss, fleeChance, onFinish, onFlee }) => {
    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), (Object.values(m.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, gauge: 0, lastAttacker: false, lastDamaged: false };
    }));

    const [bossState, setBossState] = useState({
        ...boss,
        gauge: 0,
        lastAttacker: false,
        lastDamaged: false
    });

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [isPaused, setIsPaused] = useState(false);
    const [retreatRequested, setRetreatRequested] = useState(false);
    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);

    const addLog = (msg: string, team: 'PLAYER' | 'ENEMY' | 'SYSTEM', isCrit = false) => {
        setLogs(prev => [{ msg, team, isCrit }, ...prev].slice(0, 50));
    };

    const processAttack = useCallback(() => {
        if (isPaused) return;

        setPartyState(prevParty => {
            const nextParty = [...prevParty];
            setBossState(prevBoss => {
                const nextBoss = { ...prevBoss };

                // 1. 게이지 충전 (Speed에 비례)
                nextParty.forEach(p => { if (p.currentHp > 0) p.gauge += p.derived.speed * 0.4; });
                nextBoss.gauge += nextBoss.stats.speed * 0.4;

                // 2. 플레이어 행동 처리 (AP 획득 시)
                let fleeTriggeredInThisTick = false;

                for (let i = 0; i < nextParty.length; i++) {
                    const p = nextParty[i];
                    if (p.gauge >= ACTION_THRESHOLD && p.currentHp > 0) {
                        p.gauge -= ACTION_THRESHOLD; // 1 AP 소모

                        // 도주 예약 확인
                        if (retreatRequested && !fleeTriggeredInThisTick) {
                            const roll = Math.random() * 100;
                            if (roll < fleeChance) {
                                addLog("TACTICAL SUCCESS: The squad has escaped!", 'SYSTEM');
                                onFlee(); // 외부 핸들러에서 전투 종료 처리
                                fleeTriggeredInThisTick = true;
                                return nextBoss; // 도주 성공 시 즉시 종료
                            } else {
                                addLog(`${p.name.split(' ')[0]} failed to find an exit! (1 AP Spent)`, 'PLAYER');
                                setRetreatRequested(false); // 예약 해제 (턴 소모 패널티)
                                fleeTriggeredInThisTick = true;
                                continue; // 공격하지 않고 턴 종료
                            }
                        }

                        // 일반 공격 행동
                        const res = calculateCombatResult(p.derived, nextBoss.stats, p.job, p.derived.magicalAttack > p.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL');
                        p.lastAttacker = true;
                        setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastAttacker: false } : c)), 200);

                        if (res.isHit) {
                            nextBoss.currentHp = Math.max(0, nextBoss.currentHp - res.damage);
                            nextBoss.lastDamaged = true;
                            addLog(`${p.name.split(' ')[0]} dealt ${res.damage} damage.${res.isCrit ? " (CRITICAL)" : ""}`, 'PLAYER', res.isCrit);
                            setTimeout(() => setBossState(curr => ({ ...curr, lastDamaged: false })), 200);
                        } else {
                            addLog(`${p.name.split(' ')[0]}'s attack missed.`, 'PLAYER');
                        }
                    }
                }

                // 3. 적 행동 처리 (AP 획득 시)
                if (nextBoss.gauge >= ACTION_THRESHOLD && nextBoss.currentHp > 0) {
                    nextBoss.gauge -= ACTION_THRESHOLD; // 1 AP 소모
                    const targets = nextParty.filter(p => p.currentHp > 0);
                    if (targets.length > 0) {
                        const target = targets[Math.floor(Math.random() * targets.length)];
                        const res = calculateCombatResult(nextBoss.stats, target.derived, 'Fighter' as any, 'PHYSICAL');
                        nextBoss.lastAttacker = true;
                        setTimeout(() => setBossState(curr => ({ ...curr, lastDamaged: false })), 200);

                        if (res.isHit) {
                            target.currentHp = Math.max(0, target.currentHp - res.damage);
                            target.lastDamaged = true;
                            addLog(`${nextBoss.name} hit ${target.name.split(' ')[0]} for ${res.damage}.`, 'ENEMY');
                            setTimeout(() => setPartyState(curr => curr.map(c => c.id === target.id ? { ...c, lastDamaged: false } : c)), 200);
                        } else {
                            addLog(`${nextBoss.name}'s attack was evaded!`, 'ENEMY');
                        }
                    }
                }

                return nextBoss;
            });
            return nextParty;
        });
    }, [isPaused, retreatRequested, fleeChance, onFlee]);

    useEffect(() => {
        battleInterval.current = setInterval(processAttack, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processAttack]);

    // 종료 조건 체크
    useEffect(() => {
        if (bossState.currentHp <= 0) {
            setIsPaused(true);
            setTimeout(() => onFinish(true), 1000);
        } else if (partyState.every(p => p.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(false), 1000);
        }
    }, [bossState.currentHp, partyState, onFinish]);

    return (
        <div className="fixed inset-0 z-[110] flex flex-col bg-stone-950/80 backdrop-blur-md animate-in zoom-in-95 duration-500">
            {/* Header: Engagement Status */}
            <div className="p-4 md:p-6 bg-red-950/40 border-b border-red-800/30 flex justify-between items-center shrink-0">
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-red-900/40 rounded-xl flex items-center justify-center border border-red-500/50 shadow-inner text-2xl animate-pulse">
                        <Skull className="text-red-500" />
                    </div>
                    <div>
                        <h2 className="text-white font-black uppercase text-xl md:text-2xl tracking-tighter">Combat Simulation</h2>
                        <div className="flex items-center gap-2">
                            <span className="text-red-500 font-bold text-[10px] uppercase tracking-widest">Target: {bossState.name}</span>
                            <span className="w-1.5 h-1.5 rounded-full bg-red-600 animate-ping"></span>
                        </div>
                    </div>
                </div>
                <button 
                    onClick={() => setRetreatRequested(!retreatRequested)}
                    className={`flex flex-col items-center px-8 py-2 border-2 rounded-xl transition-all active:scale-95 shadow-xl ${retreatRequested ? 'bg-red-600 border-white text-white animate-pulse shadow-red-900/50' : 'bg-stone-800 border-stone-700 text-stone-300 hover:bg-stone-700'}`}
                >
                    <LogOut className="w-4 h-4 mb-0.5" />
                    <span className="text-[10px] font-black uppercase tracking-widest">
                        {retreatRequested ? 'Escaping...' : `Try Escape (${fleeChance}%)`}
                    </span>
                </button>
            </div>

            <div className="flex-1 flex flex-col md:flex-row p-4 gap-4 overflow-hidden">
                {/* Party Side */}
                <div className="flex-1 flex flex-col gap-3 overflow-y-auto no-scrollbar justify-center">
                    {partyState.map(p => (
                        <div key={p.id} className={`bg-stone-900 border-2 rounded-2xl p-3 md:p-4 flex gap-3 md:gap-4 transition-all ${p.lastDamaged ? 'border-red-600 ring-4 ring-red-600/20' : 'border-stone-800'} ${p.currentHp <= 0 ? 'grayscale opacity-40' : ''}`}>
                            <div className="w-14 h-14 md:w-20 md:h-20 bg-stone-850 rounded-xl flex items-center justify-center text-3xl md:text-5xl shadow-inner shrink-0 relative overflow-hidden">
                                {p.icon}
                                <div className="absolute inset-0 bg-red-600/20 animate-pulse" style={{ opacity: p.lastDamaged ? 1 : 0 }} />
                            </div>
                            <div className="flex-1 min-w-0 flex flex-col justify-center">
                                <div className="flex justify-between items-end mb-2">
                                    <span className="font-black text-stone-100 text-xs md:text-lg uppercase truncate">{p.name}</span>
                                    <span className="font-mono font-black text-red-500 text-[10px] md:text-sm">{Math.floor(p.currentHp)}/{p.derived.maxHp}</span>
                                </div>
                                <div className="space-y-1.5">
                                    <div className="h-2 bg-stone-950 rounded-full overflow-hidden border border-white/5"><div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(p.currentHp/p.derived.maxHp)*100}%` }} /></div>
                                    <div className="h-1.5 bg-stone-950 rounded-full overflow-hidden border border-white/5 relative">
                                        <div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} />
                                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className="text-[6px] font-black text-white/40 uppercase tracking-tighter">AP Charge</span></div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

                {/* VS Center */}
                <div className="flex flex-col items-center justify-center shrink-0">
                    <div className="w-16 h-16 rounded-full bg-stone-900 border-4 border-red-900/50 flex items-center justify-center text-2xl font-black italic text-stone-600 shadow-2xl">VS</div>
                </div>

                {/* Boss Side */}
                <div className="flex-1 flex flex-col items-center justify-center p-4">
                    <div className={`relative flex flex-col items-center transition-all ${bossState.lastDamaged ? 'scale-110' : 'scale-100'}`}>
                        <div className={`w-32 h-32 md:w-56 md:h-56 bg-stone-900 rounded-3xl border-4 flex items-center justify-center text-6xl md:text-9xl shadow-2xl transition-all ${bossState.lastDamaged ? 'border-white brightness-150' : 'border-red-900/50'}`}>
                            {bossState.icon}
                        </div>
                        {bossState.lastDamaged && <div className="absolute inset-0 bg-white/20 animate-in fade-in duration-75 rounded-3xl" />}

                        <div className="mt-6 w-full max-w-xs space-y-3">
                            <div className="text-center">
                                <h3 className="text-xl md:text-3xl font-black text-red-100 uppercase font-serif tracking-tighter">{bossState.name}</h3>
                                <p className="text-red-500 font-bold text-[10px] md:text-xs uppercase tracking-[0.2em]">{bossState.stats.speed} SPD • BOSS UNIT</p>
                            </div>
                            <div className="space-y-2">
                                <div className="flex justify-between font-mono text-[10px] md:text-sm font-black text-red-400"><span>HP</span><span>{Math.floor(bossState.currentHp)}/{bossState.stats.maxHp}</span></div>
                                <div className="h-4 bg-stone-950 rounded-full overflow-hidden border-2 border-red-900/30 p-0.5 shadow-inner">
