import { DUNGEONS } from '../../data/dungeons';
import { handleClaimExpedition } from './expedition';
import { TILLY_FOOTLOOSE } from '../../data/mercenaries';
import { MONSTERS } from '../../data/monsters';

const generateManualGrid = (width: number, height: number, locked: boolean, dungeonId: string, knownMercs: any[]) => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));
    const visited: boolean[][] = Array.from({ length: height }, () => Array(width).fill(false));

    const startX = Math.floor(Math.random() * width);
    const startY = Math.floor(Math.random() * height);
    grid[startY][startX] = 'ENTRANCE';
    visited[startY][startX] = true;

    let bossX, bossY;
    do {
        bossX = Math.floor(Math.random() * width);
        bossY = Math.floor(Math.random() * height);
    } while (Math.abs(bossX - startX) + Math.abs(bossY - startY) < 2);
    grid[bossY][bossX] = 'BOSS';

    if (locked) {
        let keyX, keyY;
        do {
            keyX = Math.floor(Math.random() * width);
            keyY = Math.floor(Math.random() * height);
        } while (grid[keyY][keyX] !== 'EMPTY');
        grid[keyY][keyX] = 'KEY';
    }

    if (dungeonId === 'dungeon_t1_rats' && !knownMercs.some(m => m.id === 'tilly_footloose')) {
        let npcX, npcY;
        do {
            npcX = Math.floor(Math.random() * width);
            npcY = Math.floor(Math.random() * height);
        } while (grid[npcY][npcX] !== 'EMPTY');
        grid[npcY][npcX] = 'NPC';
    }

    const totalTiles = width * height;
    const goldSpawnChance = 1 / totalTiles;
    const trapSpawnChance = 1 / totalTiles;

    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const roll = Math.random();
                if (roll < goldSpawnChance) {
                    grid[y][x] = 'GOLD';
                } else if (roll < goldSpawnChance + trapSpawnChance) {
                    grid[y][x] = 'TRAP';
                }
            }
        }
    }

    return { grid, visited, playerPos: { x: startX, y: startY } };
};

export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string, partyIds: string[] }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const { grid, visited, playerPos } = generateManualGrid(
        dungeon.gridWidth, 
        dungeon.gridHeight, 
        !!dungeon.isBossLocked,
        dungeon.id,
        state.knownMercenaries
    );

    let bossEntity = undefined;
    if (dungeon.id === 'dungeon_t1_rats') {
        bossEntity = { ...MONSTERS.rat_man };
    }

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos,
        pathHistory: [{ ...playerPos }], // 초기 위치 저장
        hasKey: false,
        isBossLocked: !!dungeon.isBossLocked,
        isBossDefeated: false,
        bossEntity,
        goldCollected: 0,
        encounterStatus: 'NONE'
    };

    const updatedMercenaries = state.knownMercenaries.map(m => {
        if (payload.partyIds.includes(m.id)) {
            return { ...m, status: 'ON_EXPEDITION' as const };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercenaries,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`Squad has entered ${dungeon.name}. Tactical scanners active.`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus === 'ENCOUNTERED' || session.encounterStatus === 'BATTLE') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) return state;

    const targetRoom = session.grid[newY][newX];
    const isAlreadyVisited = session.visited[newY][newX];
    const cost = isAlreadyVisited ? -1 : (targetRoom === 'BOSS' ? dungeon.bossEnergy : dungeon.moveEnergy);

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    if (cost > 0 && party.some(m => (m.expeditionEnergy || 0) < cost)) {
        return { ...state, logs: [`Your squad is too exhausted to move further.`, ...state.logs] };
    }

    if (targetRoom === 'BOSS' && session.isBossLocked && !session.hasKey) {
        return { ...state, logs: [`The Boss chamber is sealed. You need a key.`, ...state.logs] };
    }

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextEnergy = Math.max(0, (m.expeditionEnergy || 0) - cost);
            let nextHp = m.currentHp;
            if (targetRoom === 'TRAP' && !isAlreadyVisited) nextHp = Math.max(0, m.currentHp - 25);
            return { ...m, expeditionEnergy: nextEnergy, currentHp: nextHp };
        }
        return m;
    });

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let logMsg = '';
    let encounterStatus: ManualDungeonSession['encounterStatus'] = 'NONE';

    if (targetRoom === 'GOLD' && !isAlreadyVisited) {
        extraGold = (dungeon.tier || 1) * 50;
        newGrid[newY][newX] = 'EMPTY';
        logMsg = `Treasury cache secured. (+${extraGold} G)`;
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        logMsg = `AMBUSH: Traps detected. Squad took heavy damage. (-25 HP)`;
    } else if (targetRoom === 'KEY' && !isAlreadyVisited) {
        logMsg = `Chamber key recovered.`;
        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'BOSS' && !session.isBossDefeated) {
        encounterStatus = 'ENCOUNTERED';
        logMsg = `CRITICAL ALERT: ${session.bossEntity?.name} identified. Defense systems active.`;
    }

    // 경로 역사 기록 (최대 50개 제한)
    const newPathHistory = [{ x: newX, y: newY }, ...session.pathHistory].slice(0, 50);

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: {
            ...session,
            grid: newGrid,
            playerPos: { x: newX, y: newY },
            pathHistory: newPathHistory,
            visited: newVisited,
            hasKey: targetRoom === 'KEY' ? true : session.hasKey,
            encounterStatus,
            goldCollected: session.goldCollected + extraGold
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const dummyExpId = `manual_clear_${Date.now()}`;
    const tempState: GameState = {
        ...state,
        activeExpeditions: [{
            id: dummyExpId, dungeonId: session.dungeonId, partyIds: session.partyIds,
            startTime: Date.now(), endTime: Date.now(), status: 'COMPLETED' as const
        }]
    };

    const finalState = handleClaimExpedition(tempState, { expeditionId: dummyExpId, rescuedNpcId: session.rescuedNpcId });
    const totalManualGold = session.goldCollected;

    return { 
        ...finalState, 
        stats: {
            ...finalState.stats,
            gold: finalState.stats.gold + totalManualGold,
            dailyFinancials: { ...finalState.stats.dailyFinancials, incomeDungeon: finalState.stats.dailyFinancials.incomeDungeon + totalManualGold }
        },
        activeManualDungeon: null, 
        showManualDungeonOverlay: false 
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const isDefeat = session.encounterStatus === 'DEFEAT';
    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);

    const mercResults: DungeonResult['mercenaryResults'] = [];
    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextStatus: any = 'HIRED';
            let statusChange: 'NONE' | 'INJURED' | 'DEAD' = 'NONE';

            if (isDefeat) {
                const roll = Math.random();
                if (roll < 0.15) { nextStatus = 'DEAD'; statusChange = 'DEAD'; }
                else if (roll < 0.60) { nextStatus = 'INJURED'; statusChange = 'INJURED'; }
            }

            mercResults.push({
                id: m.id, name: m.name, job: m.job, levelBefore: m.level, levelAfter: m.level,
                xpGained: 0, currentXp: m.currentXp, xpToNext: m.xpToNextLevel, statusChange
            });

            return { ...m, status: nextStatus, assignedExpeditionId: undefined };
        }
        return m;
    });

    if (isDefeat) {
        return {
            ...state,
            knownMercenaries: updatedMercs,
            dungeonResult: {
                dungeonName: dungeon?.name || 'Unknown',
                rewards: [],
                goldGained: 0,
                mercenaryResults: mercResults,
                isDefeat: true
            },
            activeManualDungeon: null,
            showManualDungeonOverlay: false,
            logs: ['CRITICAL FAILURE: The squad was overrun.', ...state.logs]
        };
    }

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: ['The squad retreated from the area.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    const currentSession = state.activeManualDungeon;
    if (!currentSession) return state;

    let newGrid = [...currentSession.grid.map(row => [...row])];
    newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';

    return {
        ...state,
        activeManualDungeon: { ...currentSession, grid: newGrid, npcFound: true, rescuedNpcId: payload.npcId },
        logs: [`Rescue initiated for survivor. Secure the area for extraction.`, ...state.logs]
    };
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Shield, Sword, Activity, Skull, Zap, LogOut, Play, Pause, ChevronRight, FastForward } from 'lucide-react';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';
import { ManualDungeonSession } from '../../../types/game-state';
import { calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, applyEquipmentBonuses, mergePrimaryStats } from '../../../models/Stats';
import { useGame } from '../../../context/GameContext';

const ACTION_THRESHOLD = 1000;

interface CombatLogEntry {
    msg: string;
    team: 'PLAYER' | 'ENEMY' | 'SYSTEM';
    isCrit?: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    boss: Monster;
    fleeChance: number;
    onFinish: (win: boolean) => void;
    onFlee: () => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ party, boss, fleeChance, onFinish, onFlee }) => {
    const { actions } = useGame();

    // 전투원 로컬 상태
    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), (Object.values(m.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, gauge: 0, lastAttacker: false, lastDamaged: false };
    }));

    const [bossState, setBossState] = useState({
        ...boss,
        gauge: 0,
        lastAttacker: false,
        lastDamaged: false
    });

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [isAuto, setIsAuto] = useState(true);
    const [isPaused, setIsPaused] = useState(false);
    const [activeActorId, setActiveActorId] = useState<string | null>(null); // 현재 턴인 아군 ID

    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);

    const addLog = (msg: string, team: 'PLAYER' | 'ENEMY' | 'SYSTEM', isCrit = false) => {
        setLogs(prev => [{ msg, team, isCrit }, ...prev].slice(0, 50));
    };

    // 실시간 HP 동기화 (전역 상태에 반영)
    useEffect(() => {
        partyState.forEach(p => {
            const original = party.find(m => m.id === p.id);
            if (original && Math.floor(original.currentHp) !== Math.floor(p.currentHp)) {
                // 이 부분은 잦은 렌더링을 방지하기 위해 필요한 경우만 dispatch하거나 
                // 전투 종료 시 한꺼번에 반영하도록 설계할 수 있습니다.
                // 여기서는 일단 로컬 상태로만 유지하고 종료 시점에 commit 합니다.
            }
        });
    }, [partyState, party]);

    const executeAttack = useCallback((attacker: any, target: any, isPlayerAttacker: boolean) => {
        const res = calculateCombatResult(
            isPlayerAttacker ? attacker.derived : attacker.stats,
            isPlayerAttacker ? target.stats : target.derived,
            isPlayerAttacker ? attacker.job : 'Fighter' as any,
            isPlayerAttacker ? (attacker.derived.magicalAttack > attacker.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL') : 'PHYSICAL'
        );

        if (isPlayerAttacker) {
            setBossState(prev => {
                const next = { ...prev, lastDamaged: res.isHit };
                if (res.isHit) next.currentHp = Math.max(0, next.currentHp - res.damage);
                setTimeout(() => setBossState(curr => ({ ...curr, lastDamaged: false })), 200);
                return next;
            });
            addLog(`${attacker.name.split(' ')[0]} ${res.isHit ? `hit for ${res.damage}${res.isCrit ? "!" : ""}` : 'missed.'}`, 'PLAYER', res.isCrit);
        } else {
            setPartyState(prev => prev.map(p => {
                if (p.id === target.id) {
                    const next = { ...p, lastDamaged: res.isHit };
                    if (res.isHit) next.currentHp = Math.max(0, next.currentHp - res.damage);
                    setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastDamaged: false } : c)), 200);
                    return next;
                }
                return p;
            }));
            addLog(`${attacker.name} ${res.isHit ? `struck ${target.name.split(' ')[0]} for ${res.damage}` : 'missed.'}`, 'ENEMY');
        }
    }, []);

    const processLoop = useCallback(() => {
        if (isPaused || activeActorId) return;

        setPartyState(prevParty => {
            const nextParty = [...prevParty];
            setBossState(prevBoss => {
                const nextBoss = { ...prevBoss };

                // 1. 게이지 충전
                nextParty.forEach(p => { if (p.currentHp > 0) p.gauge += p.derived.speed * 0.4; });
                nextBoss.gauge += nextBoss.stats.speed * 0.4;

                // 2. 아군 턴 체크
                const readyMerc = nextParty.find(p => p.currentHp > 0 && p.gauge >= ACTION_THRESHOLD);
                if (readyMerc) {
                    if (isAuto) {
                        readyMerc.gauge -= ACTION_THRESHOLD;
                        executeAttack(readyMerc, nextBoss, true);
                    } else {
                        // 수동 모드: 멈추고 명령 대기
                        setActiveActorId(readyMerc.id);
                        setIsPaused(true);
                    }
                }

                // 3. 적 턴 체크
                if (nextBoss.gauge >= ACTION_THRESHOLD && nextBoss.currentHp > 0 && !activeActorId) {
                    nextBoss.gauge -= ACTION_THRESHOLD;
                    const targets = nextParty.filter(p => p.currentHp > 0);
                    if (targets.length > 0) {
                        const target = targets[Math.floor(Math.random() * targets.length)];
                        executeAttack(nextBoss, target, false);
                    }
                }

                return nextBoss;
            });
            return nextParty;
        });
    }, [isPaused, isAuto, activeActorId, executeAttack]);

    useEffect(() => {
        battleInterval.current = setInterval(processLoop, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processLoop]);

    // 명령 처리
    const handleManualCommand = (type: 'ATTACK' | 'FLEE') => {
        if (!activeActorId) return;

        if (type === 'ATTACK') {
            const actor = partyState.find(p => p.id === activeActorId);
            if (actor) {
                setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
                executeAttack(actor, bossState, true);
            }
            setActiveActorId(null);
            setIsPaused(false);
        } else {
            // 도주 시도
            const roll = Math.random() * 100;
            if (roll < fleeChance) {
                onFlee();
            } else {
                addLog("Flee attempt failed! (1 AP Spent)", 'SYSTEM');
                setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
                setActiveActorId(null);
                setIsPaused(false);
            }
        }
    };

    // 전투 종료 감지
    useEffect(() => {
        if (bossState.currentHp <= 0) {
            setIsPaused(true);
            setTimeout(() => onFinish(true), 1000);
        } else if (partyState.every(p => p.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(false), 1000);
        }
    }, [bossState.currentHp, partyState, onFinish]);

    const currentActor = partyState.find(p => p.id === activeActorId);

    return (
        <div className="fixed inset-0 z-[110] flex flex-col bg-stone-950/90 backdrop-blur-xl animate-in zoom-in-95 duration-500">
            {/* Top Info */}
            <div className="p-4 md:p-6 bg-red-950/20 border-b border-red-900/30 flex justify-between items-center shrink-0">
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-red-900/40 rounded-xl flex items-center justify-center border border-red-500/50 shadow-inner animate-pulse">
                        <Skull className="text-red-500" />
                    </div>
                    <div>
                        <h2 className="text-white font-black uppercase text-xl md:text-2xl tracking-tighter">Engagement Protocol</h2>
                        <div className="flex items-center gap-2">
                            <span className="text-red-500 font-bold text-[10px] uppercase tracking-widest">Zone: {boss.name}</span>
                            <span className="w-1.5 h-1.5 rounded-full bg-red-600 animate-ping"></span>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    <button 
                        onClick={() => setIsAuto(!isAuto)}
                        className={`flex items-center gap-2 px-4 py-2 rounded-lg border-2 font-black text-[10px] uppercase tracking-widest transition-all ${isAuto ? 'bg-amber-600 border-amber-400 text-white' : 'bg-stone-800 border-stone-600 text-stone-400'}`}
                    >
                        {isAuto ? <FastForward className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />}
                        {isAuto ? 'AUTO-BATTLE' : 'MANUAL'}
                    </button>
                    <button 
                        onClick={() => handleManualCommand('FLEE')}
                        className="flex flex-col items-center px-6 py-2 bg-stone-800 hover:bg-red-900 border-2 border-stone-700 rounded-xl text-stone-300 transition-all active:scale-95"
                    >
                        <LogOut className="w-4 h-4 mb-0.5" />
                        <span className="text-[10px] font-black uppercase tracking-widest">Retreat ({fleeChance}%)</span>
                    </button>
                </div>
            </div>

            {/* Battle Arena */}
            <div className="flex-1 flex flex-col md:flex-row p-4 gap-4 overflow-hidden relative">

                {/* Command Overlay for Manual Mode */}
                {activeActorId && (
                    <div className="absolute inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm animate-in fade-in duration-300">
                        <div className="bg-stone-900 border-2 border-amber-500 p-8 rounded-3xl shadow-2xl flex flex-col items-center gap-6 animate-in zoom-in-95">
                            <div className="text-center">
                                <div className="text-4xl mb-2">{currentActor?.icon}</div>
                                <h3 className="text-white font-black text-xl uppercase">{currentActor?.name}'s TURN</h3>
                                <p className="text-amber-500 text-xs font-bold uppercase tracking-widest mt-1">Select Tactical Action</p>
                            </div>
                            <div className="flex gap-4">
                                <button onClick={() => handleManualCommand('ATTACK')} className="px-10 py-4 bg-amber-600 hover:bg-amber-500 text-white rounded-2xl font-black uppercase tracking-widest border-b-4 border-amber-800 active:translate-y-1 transition-all">Attack</button>
                                <button onClick={() => handleManualCommand('FLEE')} className="px-10 py-4 bg-stone-800 hover:bg-red-900 text-stone-200 rounded-2xl font-black uppercase tracking-widest border-b-4 border-stone-950 active:translate-y-1 transition-all">Flee</button>
                            </div>
                        </div>
                    </div>
                )}

                {/* Party Column */}
                <div className="flex-1 flex flex-col gap-3 justify-center">
                    {partyState.map(p => (
                        <div key={p.id} className={`bg-stone-900 border-2 rounded-2xl p-4 flex gap-4 transition-all relative overflow-hidden ${p.lastDamaged ? 'border-red-600 ring-4 ring-red-600/20' : 'border-stone-800'} ${p.currentHp <= 0 ? 'grayscale opacity-40' : ''}`}>
                            <div className="w-16 h-16 md:w-24 md:h-24 bg-stone-850 rounded-xl flex items-center justify-center text-4xl md:text-6xl shadow-inner shrink-0 relative">
                                {p.icon}
                                {activeActorId === p.id && <div className="absolute -top-2 -right-2 bg-amber-500 text-stone-900 font-black px-2 py-0.5 rounded-full text-[10px] animate-bounce shadow-xl">ACTING</div>}
                            </div>
                            <div className="flex-1 min-w-0 flex flex-col justify-center">
                                <div className="flex justify-between items-end mb-2">
                                    <span className="font-black text-stone-100 text-sm md:text-xl uppercase truncate">{p.name}</span>
                                    <span className="font-mono font-black text-red-500 text-[10px] md:text-sm">{Math.floor(p.currentHp)}/{p.derived.maxHp}</span>
                                </div>
                                <div className="space-y-1.5">
                                    <div className="h-2.5 bg-stone-950 rounded-full overflow-hidden border border-white/5"><div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(p.currentHp/p.derived.maxHp)*100}%` }} /></div>
                                    <div className="h-1.5 bg-stone-950 rounded-full overflow-hidden border border-white/5 relative">
                                        <div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} />
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

                <div className="flex flex-col items-center justify-center shrink-0">
                    <div className="w-16 h-16 rounded-full bg-stone-900 border-4 border-red-900/50 flex items-center justify-center text-2xl font-black italic text-stone-600 shadow-2xl">VS</div>
                </div>

                {/* Boss Column */}
                <div className="flex-1 flex flex-col items-center justify-center p-4">
                    <div className={`relative flex flex-col items-center transition-all ${bossState.lastDamaged ? 'scale-110' : 'scale-100'}`}>
                        <div className={`w-40 h-40 md:w-64 md:h-64 bg-stone-900 rounded-3xl border-4 flex items-center justify-center text-7xl md:text-9xl shadow-2xl transition-all ${bossState.lastDamaged ? 'border-white brightness-150' : 'border-red-900/50'}`}>
                            {bossState.icon}
                        </div>
                        <div className="mt-8 w-full max-w-sm space-y-3">
                            <div className="text-center">
                                <h3 className="text-2xl md:text-4xl font-black text-red-100 uppercase font-serif tracking-tighter">{bossState.name}</h3>
                                <p className="text-red-500 font-bold text-[10px] uppercase tracking-[0.3em]">{bossState.stats.speed} SPD • OVERLORD</p>
                            </div>
                            <div className="space-y-2">
                                <div className="flex justify-between font-mono text-xs font-black text-red-400"><span>HP</span><span>{Math.floor(bossState.currentHp)}/{bossState.stats.maxHp}</span></div>
                                <div className="h-5 bg-stone-950 rounded-full overflow-hidden border-2 border-red-900/30 p-0.5 shadow-inner">
                                    <div className="h-full bg-gradient-to-r from-red-900 to-red-600 transition-all duration-300" style={{ width: `${(bossState.currentHp/bossState.stats.maxHp)*100}%` }} />
                                </div>
                                <div className="h-2 bg-stone-950 rounded-full overflow-hidden border border-white/5"><div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(bossState.gauge/ACTION_THRESHOLD)*100}%` }} /></div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Tactical Logs */}
            <div className="h-24 md:h-48 bg-stone-900/90 border-t border-red-900/30 p-3 flex flex-col overflow-hidden shrink-0">
                <div className="flex items-center gap-2 mb-2 px-2">
                    <Activity className="w-3 h-3 text-red-500 animate-pulse" />
                    <span className="text-[10px] font-black text-stone-500 uppercase tracking-widest">Tactical Log Feed</span>
                </div>
                <div className="flex-1 overflow-y-auto custom-scrollbar space-y-1">
                    {logs.map((log, idx) => (
                        <div key={idx} className={`text-[10px] md:text-xs font-mono px-4 py-0.5 border-l-2 ${log.team === 'PLAYER' ? 'border-blue-500 text-blue-100' : log.team === 'ENEMY' ? 'border-red-500 text-red-100' : 'border-amber-500 text-amber-100'} ${log.isCrit ? 'bg-amber-900/20 font-black italic shadow-inner' : ''}`}>
                            <span className="opacity-50 mr-2">[{new Date().toLocaleTimeString([], { hour12: false, minute: '2-digit', second: '2-digit' })}]</span>
                            {log.msg}
                        </div>
                    ))}
                    {logs.length === 0 && <div className="h-full flex items-center justify-center text-stone-700 italic text-xs">Waiting for tactical engagement...</div>}
                </div>
            </div>
        </div>
    );
};

