    msg: string;
    team: 'PLAYER' | 'ENEMY' | 'SYSTEM';
    isCrit?: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    boss: Monster;
    fleeChance: number;
    onFinish: (win: boolean, finalParty: any[]) => void; // 최종 파티 스탯 전달 추가
    onFlee: (finalParty: any[]) => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ party, boss, fleeChance, onFinish, onFlee }) => {
    const { actions } = useGame();

    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), (Object.values(m.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, currentMp: m.currentMp, gauge: 0, lastAttacker: false, lastDamaged: false };
    }));

    const [bossState, setBossState] = useState({
        ...boss,
        gauge: 0,
        lastAttacker: false,
        lastDamaged: false
    });

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [isAuto, setIsAuto] = useState(true);
    const [isPaused, setIsPaused] = useState(false);
    const [activeActorId, setActiveActorId] = useState<string | null>(null); 
    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);

    const addLog = (msg: string, team: 'PLAYER' | 'ENEMY' | 'SYSTEM', isCrit = false) => {
        setLogs(prev => [{ msg, team, isCrit }, ...prev].slice(0, 50));
    };

    const executeAttack = useCallback((attacker: any, target: any, isPlayerAttacker: boolean) => {
        const res = calculateCombatResult(
            isPlayerAttacker ? attacker.derived : attacker.stats,
            isPlayerAttacker ? target.stats : target.derived,
            isPlayerAttacker ? attacker.job : 'Fighter' as any,
            isPlayerAttacker ? (attacker.derived.magicalAttack > attacker.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL') : 'PHYSICAL'
        );

        if (isPlayerAttacker) {
            setBossState(prev => {
                const next = { ...prev, lastDamaged: res.isHit };
                if (res.isHit) next.currentHp = Math.max(0, next.currentHp - res.damage);
                setTimeout(() => setBossState(curr => ({ ...curr, lastDamaged: false })), 200);
                return next;
            });
            addLog(`${attacker.name.split(' ')[0]} hit for ${res.damage}${res.isCrit ? "!" : ""}`, 'PLAYER', res.isCrit);
        } else {
            setPartyState(prev => prev.map(p => {
                if (p.id === target.id) {
                    const next = { ...p, lastDamaged: res.isHit };
                    if (res.isHit) next.currentHp = Math.max(0, next.currentHp - res.damage);
                    // 마나 소모 시뮬레이션 (피격 시 약간 소모)
                    next.currentMp = Math.max(0, next.currentMp - 1);
                    setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastDamaged: false } : c)), 200);
                    return next;
                }
                return p;
            }));
            addLog(`${attacker.name} struck ${target.name.split(' ')[0]} for ${res.damage}`, 'ENEMY');
        }
    }, []);

    const processLoop = useCallback(() => {
        if (isPaused || activeActorId) return;

        setPartyState(prevParty => {
            const nextParty = [...prevParty];
            setBossState(prevBoss => {
                const nextBoss = { ...prevBoss };

                // 1. 게이지 충전
                nextParty.forEach(p => { if (p.currentHp > 0) p.gauge += p.derived.speed * 0.4; });
                nextBoss.gauge += nextBoss.stats.speed * 0.4;

                // 2. 아군 턴 체크
                const readyMerc = nextParty.find(p => p.currentHp > 0 && p.gauge >= ACTION_THRESHOLD);
                if (readyMerc) {
                    if (isAuto) {
                        readyMerc.gauge -= ACTION_THRESHOLD; // 1 AP 소모
                        executeAttack(readyMerc, nextBoss, true);
                    } else {
                        // 수동 모드: 정지 후 명령 대기
                        setActiveActorId(readyMerc.id);
                        setIsPaused(true);
                    }
                }

                // 3. 적 턴 체크 (아군 명령 대기 중에는 적도 멈춤)
                if (nextBoss.gauge >= ACTION_THRESHOLD && nextBoss.currentHp > 0 && !activeActorId) {
                    nextBoss.gauge -= ACTION_THRESHOLD;
                    const targets = nextParty.filter(p => p.currentHp > 0);
                    if (targets.length > 0) {
                        const target = targets[Math.floor(Math.random() * targets.length)];
                        executeAttack(nextBoss, target, false);
                    }
                }

                return nextBoss;
            });
            return nextParty;
        });
    }, [isPaused, isAuto, activeActorId, executeAttack]);

    useEffect(() => {
        battleInterval.current = setInterval(processLoop, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processLoop]);

    const handleManualCommand = (type: 'ATTACK' | 'FLEE') => {
        if (!activeActorId) return;
        const actor = partyState.find(p => p.id === activeActorId);
        if (!actor) return;

        if (type === 'ATTACK') {
            setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
            executeAttack(actor, bossState, true);
            setActiveActorId(null);
            setIsPaused(false);
        } else {
            // 도주 시도 (1 AP 소모)
            const roll = Math.random() * 100;
            if (roll < fleeChance) {
                onFlee(partyState); // 도주 성공 시 현재 파티 상태 동기화하며 나감
            } else {
                addLog(`${actor.name.split(' ')[0]} failed to find escape route! (1 AP Spent)`, 'SYSTEM');
                setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
                setActiveActorId(null);
                setIsPaused(false);
            }
        }
    };

    useEffect(() => {
        if (bossState.currentHp <= 0) {
            setIsPaused(true);
            setTimeout(() => onFinish(true, partyState), 1000);
        } else if (partyState.every(p => p.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(false, partyState), 1000);
        }
    }, [bossState.currentHp, partyState, onFinish]);

    const currentActor = partyState.find(p => p.id === activeActorId);

    return (
        <div className="fixed inset-0 z-[110] flex flex-col bg-stone-950/90 backdrop-blur-xl animate-in zoom-in-95 duration-500">
            {/* Header */}
            <div className="p-4 md:p-6 bg-red-950/20 border-b border-red-900/30 flex justify-between items-center shrink-0">
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-red-900/40 rounded-xl flex items-center justify-center border border-red-500/50 shadow-inner animate-pulse">
                        <Skull className="text-red-500" />
                    </div>
                    <div>
                        <h2 className="text-white font-black uppercase text-xl md:text-2xl tracking-tighter">Combat Phase</h2>
                        <div className="flex items-center gap-2">
                            <span className="text-red-500 font-bold text-[10px] uppercase tracking-widest">Enemy: {boss.name}</span>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    <button 
                        onClick={() => setIsAuto(!isAuto)}
                        className={`flex items-center gap-2 px-6 py-2.5 rounded-xl border-2 font-black text-[10px] uppercase tracking-widest transition-all ${isAuto ? 'bg-amber-600 border-amber-400 text-white shadow-glow-sm' : 'bg-stone-800 border-stone-600 text-stone-400'}`}
                    >
                        {isAuto ? <FastForward className="w-4 h-4" /> : <Pause className="w-4 h-4" />}
                        {isAuto ? 'AUTO' : 'MANUAL'}
                    </button>
                </div>
            </div>

            <div className="flex-1 flex flex-col md:flex-row p-4 gap-4 overflow-hidden relative">

                {/* Manual Control UI Overlay */}
                {activeActorId && (
                    <div className="absolute inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm animate-in fade-in duration-300">
                        <div className="bg-stone-900 border-2 border-amber-500 p-8 rounded-3xl shadow-2xl flex flex-col items-center gap-6 animate-in zoom-in-95">
                            <div className="text-center">
                                <div className="text-5xl mb-3 drop-shadow-lg">{currentActor?.icon}</div>
                                <h3 className="text-white font-black text-2xl uppercase tracking-tighter">{currentActor?.name}'s TURN</h3>
                                <p className="text-amber-500 text-xs font-bold uppercase tracking-widest mt-1 opacity-80">Command Input Required</p>
                            </div>
                            <div className="flex gap-4">
                                <button 
                                    onClick={() => handleManualCommand('ATTACK')} 
                                    className="px-12 py-5 bg-amber-600 hover:bg-amber-500 text-white rounded-2xl font-black uppercase tracking-widest border-b-4 border-amber-800 active:translate-y-1 transition-all flex items-center gap-3"
                                >
                                    <Sword className="w-5 h-5" /> Attack
                                </button>
                                <button 
                                    onClick={() => handleManualCommand('FLEE')} 
                                    className="px-12 py-5 bg-stone-800 hover:bg-red-900 text-stone-200 rounded-2xl font-black uppercase tracking-widest border-b-4 border-stone-950 active:translate-y-1 transition-all flex items-center gap-3"
                                >
                                    <LogOut className="w-5 h-5" /> Escape
                                </button>
                            </div>
                        </div>
                    </div>
                )}

                {/* Party Side */}
                <div className="flex-1 flex flex-col gap-3 justify-center">
                    {partyState.map(p => (
                        <div key={p.id} className={`bg-stone-900 border-2 rounded-2xl p-4 flex gap-4 transition-all relative overflow-hidden ${p.lastDamaged ? 'border-red-600 ring-4 ring-red-600/20' : 'border-stone-800'} ${p.currentHp <= 0 ? 'grayscale opacity-40' : ''} ${activeActorId === p.id ? 'border-amber-500 shadow-glow-sm scale-105' : ''}`}>
                            <div className="w-16 h-16 md:w-24 md:h-24 bg-stone-850 rounded-xl flex items-center justify-center text-4xl md:text-6xl shadow-inner shrink-0 relative">
                                {p.icon}
                                {activeActorId === p.id && <div className="absolute -top-2 -right-2 bg-amber-500 text-stone-900 font-black px-3 py-1 rounded-full text-[10px] animate-bounce shadow-xl border border-white/20">READY</div>}
                            </div>
                            <div className="flex-1 min-w-0 flex flex-col justify-center">
                                <div className="flex justify-between items-end mb-2">
                                    <span className="font-black text-stone-100 text-sm md:text-xl uppercase truncate">{p.name}</span>
                                    <span className="font-mono font-black text-red-500 text-[10px] md:text-sm">{Math.floor(p.currentHp)}/{p.derived.maxHp}</span>
                                </div>
                                <div className="space-y-1.5">
                                    <div className="h-2.5 bg-stone-950 rounded-full overflow-hidden border border-white/5"><div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(p.currentHp/p.derived.maxHp)*100}%` }} /></div>
                                    <div className="h-1.5 bg-stone-950 rounded-full overflow-hidden border border-white/5 relative">
                                        <div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} />
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

                <div className="flex flex-col items-center justify-center shrink-0">
                    <div className="w-16 h-16 rounded-full bg-stone-900 border-4 border-red-900/50 flex items-center justify-center text-2xl font-black italic text-stone-600 shadow-2xl">VS</div>
                </div>

                {/* Boss Side */}
                <div className="flex-1 flex flex-col items-center justify-center p-4">
                    <div className={`relative flex flex-col items-center transition-all ${bossState.lastDamaged ? 'scale-110' : 'scale-100'}`}>
                        <div className={`w-40 h-40 md:w-64 md:h-64 bg-stone-900 rounded-3xl border-4 flex items-center justify-center text-7xl md:text-9xl shadow-2xl transition-all ${bossState.lastDamaged ? 'border-white brightness-150 shadow-[0_0_50px_rgba(255,255,255,0.2)]' : 'border-red-900/50'}`}>
                            {bossState.icon}
                        </div>
                        <div className="mt-8 w-full max-w-sm space-y-4">
                            <div className="text-center">
                                <h3 className="text-2xl md:text-4xl font-black text-red-100 uppercase font-serif tracking-tighter leading-none">{bossState.name}</h3>
                                <p className="text-red-500 font-bold text-[10px] uppercase tracking-[0.3em] mt-2">{bossState.stats.speed} SPD • ALPHA ENTITY</p>
                            </div>
                            <div className="space-y-2">
                                <div className="flex justify-between font-mono text-xs font-black text-red-400"><span>INTEGRITY</span><span>{Math.floor(bossState.currentHp)}/{bossState.stats.maxHp}</span></div>
                                <div className="h-5 bg-stone-950 rounded-full overflow-hidden border-2 border-red-900/30 p-0.5 shadow-inner">
                                    <div className="h-full bg-gradient-to-r from-red-900 via-red-600 to-red-500 transition-all duration-300" style={{ width: `${(bossState.currentHp/bossState.stats.maxHp)*100}%` }} />
                                </div>
                                <div className="h-2 bg-stone-950 rounded-full overflow-hidden border border-white/5"><div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(bossState.gauge/ACTION_THRESHOLD)*100}%` }} /></div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Tactical Logs */}
            <div className="h-24 md:h-48 bg-stone-900/90 border-t border-red-900/30 p-3 flex flex-col overflow-hidden shrink-0">
                <div className="flex items-center gap-2 mb-2 px-2">
                    <Activity className="w-3 h-3 text-red-500 animate-pulse" />
                    <span className="text-[10px] font-black text-stone-500 uppercase tracking-widest">Tactical Log Feed</span>
                </div>
                <div className="flex-1 overflow-y-auto custom-scrollbar space-y-1">
                    {logs.map((log, idx) => (
                        <div key={idx} className={`text-[10px] md:text-xs font-mono px-4 py-1 border-l-2 ${log.team === 'PLAYER' ? 'border-blue-500 text-blue-100' : log.team === 'ENEMY' ? 'border-red-500 text-red-100' : 'border-amber-500 text-amber-100'} ${log.isCrit ? 'bg-amber-900/20 font-black italic shadow-inner border-y border-amber-900/20' : ''}`}>
                            <span className="opacity-40 mr-3">[{new Date().toLocaleTimeString([], { hour12: false, minute: '2-digit', second: '2-digit' })}]</span>
                            {log.msg}
                        </div>
                    ))}
                    {logs.length === 0 && <div className="h-full flex items-center justify-center text-stone-700 italic text-xs uppercase tracking-widest opacity-50">Engaging combat subroutines...</div>}
                </div>
            </div>
        </div>
    );
};

export default DungeonCombatView;

import React, { useEffect, useRef, useState, useMemo } from 'react';
import Phaser from 'phaser';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import DungeonScene from '../../../game/DungeonScene';
import DialogueBox from '../../DialogueBox';
import { 
    Key, Zap, LogOut, X, ChevronUp, ChevronDown, ChevronLeft, ChevronRight, Lock, Unlock, Target, Shield, Sword, Skull
} from 'lucide-react';
import ConfirmationModal from '../../modals/ConfirmationModal';
import { calculateCombatPower, calculateMercenaryPower } from '../../../utils/combatLogic';
import DungeonCombatView from './DungeonCombatView';

type CameraMode = 'LOCKED' | 'ADAPTIVE' | 'FREE';

const AssaultNavigator = () => {
    const { state, actions } = useGame();
    const session = state.activeManualDungeon;
    const gameRef = useRef<Phaser.Game | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isReady, setIsReady] = useState(false);
    const [showRetreatConfirm, setShowRetreatConfirm] = useState(false);
    const [cameraMode, setCameraMode] = useState<CameraMode>('LOCKED');

    const [isSquadStatusExpanded, setIsSquadStatusExpanded] = useState(true);
    const [lastDiscoveryMessage, setLastDiscoveryMessage] = useState<string>('');

    const dungeon = session ? DUNGEONS.find(d => d.id === session.dungeonId) : null;
    const party = session ? state.knownMercenaries.filter(m => session.partyIds.includes(m.id)) : [];
    const avgEnergy = party.length > 0 ? party.reduce((sum, m) => sum + (m.expeditionEnergy || 0), 0) / (party.length || 1) : 0;

    const isEncountered = session?.encounterStatus === 'ENCOUNTERED';
    const isBattle = session?.encounterStatus === 'BATTLE';
    const isVictory = session?.encounterStatus === 'VICTORY';
    const isDefeat = session?.encounterStatus === 'DEFEAT';

    const bossPower = useMemo(() => {
        if (!session?.bossEntity) return 0;
        return calculateCombatPower(session.bossEntity.stats, 'Fighter' as any, 'PHYSICAL');
    }, [session?.bossEntity]);

    const fleeChance = useMemo(() => {
        if (!session || !session.bossEntity) return 0;
        const partyCP = party.reduce((sum, m) => sum + calculateMercenaryPower(m), 0);
        return Math.max(5, Math.min(95, Math.round(50 + (partyCP - bossPower) / 5)));
    }, [session, party, bossPower]);

    const handleDpadMove = (dx: number, dy: number) => {
        if (isEncountered || isBattle) return;

        // 이동 가능 여부 사전 체크 (토스트 피드백용)
        const nextX = (session?.playerPos.x || 0) + dx;
        const nextY = (session?.playerPos.y || 0) + dy;
        const gridW = dungeon?.gridWidth || 0;
        const gridH = dungeon?.gridHeight || 0;

        if (nextX < 0 || nextX >= gridW || nextY < 0 || nextY >= gridH) {
            actions.showToast("Cannot move in that direction.");
            return;
        }

        const targetRoom = session?.grid[nextY][nextX];
        if (targetRoom === 'WALL') {
            actions.showToast("Blocked by a solid wall.");
            return;
        }

        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.move(dx, dy);
    };

    const handleStartCombat = () => {
        if (!session) return;
        const newSession = { ...session, encounterStatus: 'BATTLE' as const };
        state.activeManualDungeon = newSession; 
        actions.moveInManualDungeon(0, 0); 
    };

    // 실시간 HP/MP 동기화 함수
    const syncPartyVitals = (finalParty: any[]) => {
        finalParty.forEach(p => {
            const original = state.knownMercenaries.find(m => m.id === p.id);
            if (original) {
                // 전역 상태의 용병 데이터 업데이트 (내부적으로 handleUpdateMercenaryStats 등 활용 가능하나 여기선 직접 주입 방식 선호)
                original.currentHp = p.currentHp;
                original.currentMp = p.currentMp;
            }
        });
    };

    // 도주 성공 시 이전 위치로 복귀 (Backtrack)
    const handleFleeSuccess = (finalParty: any[]) => {
        if (!session) return;
        syncPartyVitals(finalParty);

        const prevPos = session.pathHistory[1] || session.pathHistory[0]; 

        const newSession = { 
            ...session, 
            playerPos: prevPos, 
            encounterStatus: 'NONE' as const,
            pathHistory: session.pathHistory.slice(1) 
        };
        state.activeManualDungeon = newSession;
        actions.moveInManualDungeon(0, 0);
        actions.showToast("TACTICAL WITHDRAWAL: Back to safe zone.");
    };

    useEffect(() => {
        const checkSize = () => {
            if (containerRef.current && containerRef.current.clientWidth > 0) setIsReady(true);
            else requestAnimationFrame(checkSize);
        };
        checkSize();
    }, []);

    useEffect(() => {
        if (!session || !dungeon) return;
        const room = session.grid[session.playerPos.y][session.playerPos.x];
        if (isEncountered) setLastDiscoveryMessage(`CRITICAL ALERT: ${session.bossEntity?.name} identified. Power Level: ${bossPower} CP. Probability of escape: ${fleeChance}%.`);
        else if (room === 'NPC' && !session.npcFound) setLastDiscoveryMessage("Life-sign confirmed. Survivor identified. Initializing rescue protocols.");
        else if (room === 'BOSS' && session.isBossDefeated) setLastDiscoveryMessage("High-Value Target neutralized. The area is now secure.");
        else if (room === 'ENTRANCE' && lastDiscoveryMessage === '') setLastDiscoveryMessage(`Infiltration of ${dungeon.name} complete.`);
        else setLastDiscoveryMessage("Sector clear. No immediate hostiles detected.");
    }, [session?.playerPos, session?.encounterStatus, dungeon?.name]);

    useEffect(() => {
        if (!isReady || !containerRef.current || !session || !dungeon) return;
        if (!gameRef.current) {
            const config: Phaser.Types.Core.GameConfig = {
                type: Phaser.AUTO, parent: containerRef.current, width: containerRef.current.clientWidth, height: containerRef.current.clientHeight, backgroundColor: 'transparent', transparent: true, scene: [DungeonScene],
                scale: { mode: Phaser.Scale.RESIZE, autoCenter: Phaser.Scale.CENTER_BOTH }
            };
            const game = new Phaser.Game(config);
            gameRef.current = game;
            game.scene.start('DungeonScene', { session, moveEnergy: dungeon.moveEnergy, bossEnergy: dungeon.bossEnergy, onMove: (dx, dy) => actions.moveInManualDungeon(dx, dy), cameraMode: cameraMode });
        } else {
            const scene = gameRef.current.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) { scene.updateSession(session); scene.setCameraMode(cameraMode); }
        }
    }, [isReady, session, actions, dungeon, cameraMode]);

    if (!session || !dungeon) return null;

    return (
        <div className="absolute inset-0 z-[100] bg-stone-950 flex flex-col animate-in fade-in duration-500 overflow-hidden">
            <div ref={containerRef} className={`absolute inset-0 z-0 transition-all duration-700 ${isBattle ? 'opacity-20 blur-lg scale-110' : 'opacity-100 scale-100'}`} />

            {isBattle && (
                <DungeonCombatView 
                    session={session} 
                    party={party} 
                    boss={session.bossEntity!} 
                    fleeChance={fleeChance}
                    onFinish={(win, finalParty) => {
                        syncPartyVitals(finalParty);
                        const nextStatus = win ? 'VICTORY' : 'DEFEAT';
                        const newSession = { ...session, encounterStatus: nextStatus as any, isBossDefeated: win };
                        state.activeManualDungeon = newSession;
                        actions.moveInManualDungeon(0, 0);
                        if (!win) {
                            setTimeout(() => actions.retreatFromManualDungeon(), 1000);
                        }
                    }}
                    onFlee={handleFleeSuccess}
                />
            )}

            {/* Squad HUD */}
            {!isBattle && (
                <div className="absolute top-20 left-4 z-50 flex flex-col gap-2 w-48 md:w-56 pointer-events-none">
                    <button onClick={() => setIsSquadStatusExpanded(!isSquadStatusExpanded)} className="bg-stone-950/40 backdrop-blur-md border border-white/10 rounded-lg p-2.5 flex items-center justify-between pointer-events-auto hover:bg-stone-900/60 transition-colors shadow-2xl">
                        <div className="flex items-center gap-2"><Shield className="w-4 h-4 text-blue-400" /><span className="text-[10px] font-black text-blue-100 uppercase tracking-widest">Squad Status</span></div>
                        {isSquadStatusExpanded ? <ChevronUp className="w-3.5 h-3.5 text-stone-500" /> : <ChevronDown className="w-3.5 h-3.5 text-stone-500" />}
                    </button>
                    {isSquadStatusExpanded && party.map(merc => {
                        const hpPer = (merc.currentHp / merc.maxHp) * 100;
                        const mpPer = (merc.currentMp / (merc.maxMp || 1)) * 100;
                        return (
