import { GameState, ManualDungeonSession, RoomType, DungeonResult } from '../../types/game-state';
import { DUNGEONS } from '../../data/dungeons';
import { handleClaimExpedition } from './expedition';
import { TILLY_FOOTLOOSE } from '../../data/mercenaries';
import { MONSTERS } from '../../data/monsters';
import { calculateMaxHp, calculateMaxMp, mergePrimaryStats } from '../../models/Stats';

const generateManualGrid = (width: number, height: number, locked: boolean, dungeonId: string, knownMercs: any[]) => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));
    const visited: boolean[][] = Array.from({ length: height }, () => Array(width).fill(false));

    const startX = Math.floor(Math.random() * width);
    const startY = Math.floor(Math.random() * height);
    grid[startY][startX] = 'ENTRANCE';
    visited[startY][startX] = true;

    let bossX, bossY;
    do {
        bossX = Math.floor(Math.random() * width);
        bossY = Math.floor(Math.random() * height);
    } while (Math.abs(bossX - startX) + Math.abs(bossY - startY) < 2);
    grid[bossY][bossX] = 'BOSS';

    if (locked) {
        let keyX, keyY;
        do {
            keyX = Math.floor(Math.random() * width);
            keyY = Math.floor(Math.random() * height);
        } while (grid[keyY][keyX] !== 'EMPTY');
        grid[keyY][keyX] = 'KEY';
    }

    if (dungeonId === 'dungeon_t1_rats' && !knownMercs.some(m => m.id === 'tilly_footloose')) {
        let npcX, npcY;
        do {
            npcX = Math.floor(Math.random() * width);
            npcY = Math.floor(Math.random() * height);
        } while (grid[npcY][npcX] !== 'EMPTY');
        grid[npcY][npcX] = 'NPC';
    }

    const totalTiles = width * height;
    const goldSpawnChance = 1 / totalTiles;
    const trapSpawnChance = 1 / totalTiles;

    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const roll = Math.random();
                if (roll < goldSpawnChance) {
                    grid[y][x] = 'GOLD';
                } else if (roll < goldSpawnChance + trapSpawnChance) {
                    grid[y][x] = 'TRAP';
                }
            }
        }
    }

    return { grid, visited, playerPos: { x: startX, y: startY } };
};

export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string, partyIds: string[] }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const { grid, visited, playerPos } = generateManualGrid(
        dungeon.gridWidth, 
        dungeon.gridHeight, 
        !!dungeon.isBossLocked,
        dungeon.id,
        state.knownMercenaries
    );

    let bossEntity = undefined;
    if (dungeon.id === 'dungeon_t1_rats') {
        bossEntity = { ...MONSTERS.rat_man };
    }

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos,
        pathHistory: [{ ...playerPos }], 
        hasKey: false,
        isBossLocked: !!dungeon.isBossLocked,
        isBossDefeated: false,
        bossEntity,
        goldCollected: 0,
        encounterStatus: 'NONE'
    };

    const updatedMercenaries = state.knownMercenaries.map(m => {
        if (payload.partyIds.includes(m.id)) {
            return { ...m, status: 'ON_EXPEDITION' as const };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercenaries,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`Squad has entered ${dungeon.name}. Tactical scanners active.`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus === 'ENCOUNTERED' || session.encounterStatus === 'BATTLE') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) {
        return {
            ...state,
            toastQueue: [...state.toastQueue, "Reached area boundary. Navigation impossible."]
        };
    }

    const targetRoom = session.grid[newY][newX];
    if (targetRoom === 'WALL') {
        return {
            ...state,
            toastQueue: [...state.toastQueue, "A massive obstruction blocks the path."]
        };
    }

    const isAlreadyVisited = session.visited[newY][newX];
    const cost = isAlreadyVisited ? -1 : (targetRoom === 'BOSS' ? dungeon.bossEnergy : dungeon.moveEnergy);

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    if (cost > 0 && party.some(m => (m.expeditionEnergy || 0) < cost)) {
        return { ...state, logs: [`Your squad is too exhausted to move further.`, ...state.logs] };
    }

    if (targetRoom === 'BOSS' && session.isBossLocked && !session.hasKey) {
        return { ...state, logs: [`The Boss chamber is sealed. You need a key.`, ...state.logs] };
    }

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextEnergy = Math.max(0, (m.expeditionEnergy || 0) - cost);
            let nextHp = m.currentHp;
            if (targetRoom === 'TRAP' && !isAlreadyVisited) nextHp = Math.max(0, m.currentHp - 25);
            return { ...m, expeditionEnergy: nextEnergy, currentHp: nextHp };
        }
        return m;
    });

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let logMsg = '';
    let encounterStatus: ManualDungeonSession['encounterStatus'] = 'NONE';

    if (targetRoom === 'GOLD' && !isAlreadyVisited) {
        extraGold = (dungeon.tier || 1) * 50;
        newGrid[newY][newX] = 'EMPTY';
        logMsg = `Treasury cache secured. (+${extraGold} G)`;
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        logMsg = `AMBUSH: Traps detected. Squad took heavy damage. (-25 HP)`;
    } else if (targetRoom === 'KEY' && !isAlreadyVisited) {
        logMsg = `Chamber key recovered.`;
        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'BOSS' && !session.isBossDefeated) {
        encounterStatus = 'ENCOUNTERED';
        logMsg = `CRITICAL ALERT: ${session.bossEntity?.name} identified. Defense systems active.`;
    }

    const newPathHistory = [{ x: newX, y: newY }, ...session.pathHistory].slice(0, 50);

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: {
            ...session,
            grid: newGrid,
            playerPos: { x: newX, y: newY },
            pathHistory: newPathHistory,
            visited: newVisited,
            hasKey: targetRoom === 'KEY' ? true : session.hasKey,
            encounterStatus,
            goldCollected: session.goldCollected + extraGold
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleStartCombatManual = (state: GameState): GameState => {
    if (!state.activeManualDungeon) return state;
    return {
        ...state,
        activeManualDungeon: {
            ...state.activeManualDungeon,
            encounterStatus: 'BATTLE'
        }
    };
};

export const handleResolveCombatManual = (state: GameState, payload: { win: boolean, flee: boolean, finalParty: any[] }): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    // 용병 스탯 동기화
    const newKnownMercenaries = state.knownMercenaries.map(m => {
        const combatant = payload.finalParty.find(p => p.id === m.id);
        if (combatant) {
            return { ...m, currentHp: combatant.currentHp, currentMp: combatant.currentMp };
        }
        return m;
    });

    let nextStatus: ManualDungeonSession['encounterStatus'] = payload.win ? 'VICTORY' : (payload.flee ? 'NONE' : 'DEFEAT');
    let nextPos = session.playerPos;
    let nextHistory = session.pathHistory;

    // 도주 시 전술적 후퇴
    if (payload.flee) {
        nextPos = session.pathHistory[1] || session.playerPos;
        nextHistory = session.pathHistory.slice(1);
    }

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        activeManualDungeon: {
            ...session,
            playerPos: nextPos,
            pathHistory: nextHistory,
            encounterStatus: nextStatus,
            isBossDefeated: payload.win || session.isBossDefeated
        },
        logs: payload.flee ? ['TACTICAL WITHDRAWAL: Back to safe zone.', ...state.logs] : state.logs
    };
};

export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const dummyExpId = `manual_clear_${Date.now()}`;
    const tempState: GameState = {
        ...state,
        activeExpeditions: [{
            id: dummyExpId, dungeonId: session.dungeonId, partyIds: session.partyIds,
            startTime: Date.now(), endTime: Date.now(), status: 'COMPLETED' as const
        }]
    };

    const finalState = handleClaimExpedition(tempState, { expeditionId: dummyExpId, rescuedNpcId: session.rescuedNpcId });
    const totalManualGold = session.goldCollected;

    return { 
        ...finalState, 
        stats: {
            ...finalState.stats,
            gold: finalState.stats.gold + totalManualGold,
            dailyFinancials: { ...finalState.stats.dailyFinancials, incomeDungeon: finalState.stats.dailyFinancials.incomeDungeon + totalManualGold }
        },
        activeManualDungeon: null, 
        showManualDungeonOverlay: false 
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const isDefeat = session.encounterStatus === 'DEFEAT';
    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);

    const mercResults: DungeonResult['mercenaryResults'] = [];
    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextStatus: any = 'HIRED';
            let statusChange: 'NONE' | 'INJURED' | 'DEAD' = 'NONE';

            if (isDefeat) {
                const roll = Math.random();
                if (roll < 0.10) { nextStatus = 'DEAD'; statusChange = 'DEAD'; }
                else if (roll < 0.50) { nextStatus = 'INJURED'; statusChange = 'INJURED'; }
            }

            mercResults.push({
                id: m.id, name: m.name, job: m.job, levelBefore: m.level, levelAfter: m.level,
                xpGained: 0, currentXp: m.currentXp, xpToNext: m.xpToNextLevel, statusChange
            });

            return { ...m, status: nextStatus, assignedExpeditionId: undefined };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        dungeonResult: isDefeat ? {
            dungeonName: dungeon?.name || 'Unknown',
            rewards: [],
            goldGained: 0,
            mercenaryResults: mercResults,
            isDefeat: true
        } : state.dungeonResult,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: [isDefeat ? 'CRITICAL FAILURE: The squad has been wiped out.' : 'The squad retreated to safety.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    const currentSession = state.activeManualDungeon;
    if (!currentSession) return state;

    let newGrid = [...currentSession.grid.map(row => [...row])];
    newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';

    return {
        ...state,
        activeManualDungeon: { ...currentSession, grid: newGrid, npcFound: true, rescuedNpcId: payload.npcId },
        logs: [`Rescue initiated for survivor. Secure the area for extraction.`, ...state.logs]
    };
};

import { GameState } from '../types/index';
import { GameAction } from './actions';

// Import Handlers
import { handleRepairWork } from './reducer/repair';
import { handleSleep, handleConfirmSleep } from './reducer/sleep';
import { handleTriggerEvent, handleCloseEvent, handleToggleJournal } from './reducer/events';
import { handleAcquireItem, handlePayCost, handleBuyMarketItems, handleInstallFurnace, handleSellItem, handleUseItem, handleToggleLockItem } from './reducer/inventory';
import { handleStartCrafting, handleCancelCrafting, handleFinishCrafting, handleSetCrafting, handleUpdateForgeStatus } from './reducer/crafting';
import { handleToggleShop, handleEnqueueCustomer, handleNextCustomer, handleDismissCustomer, handleRefuseCustomer } from './reducer/shop';
import { handleAddKnownMercenary, handleScoutMercenary, handleHireMercenary, handleFireMercenary, handleAllocateStat, handleUpdateMercenaryStats, handleGiveGift, handleTalkMercenary } from './reducer/mercenary';
import { handleStartExpedition, handleCompleteExpedition, handleClaimExpedition, handleAbortExpedition, handleDismissDungeonResult } from './reducer/expedition';
import { handleEquipItem, handleUnequipItem } from './reducer/equipment';
import { handleStartManualDungeon, handleMoveManualDungeon, handleFinishManualDungeon, handleRescueNPC, handleRetreatManualDungeon, handleStartCombatManual, handleResolveCombatManual } from './reducer/manualDungeon';
import { handleTalkGarrick, handleGiftGarrick } from './reducer/market-affinity';

export const gameReducer = (state: GameState, action: GameAction): GameState => {
  switch (action.type) {
    // Save & Load
    case 'LOAD_GAME': return action.payload;

    // Repair
    case 'REPAIR_WORK': return handleRepairWork(state);

    // Sleep
    case 'SLEEP': return handleSleep(state);
    case 'CONFIRM_SLEEP': return handleConfirmSleep(state);
    case 'CLOSE_SLEEP_MODAL': return { ...state, showSleepModal: false };

    // Events
    case 'TRIGGER_EVENT': return handleTriggerEvent(state, action.payload);
    case 'CLOSE_EVENT': return handleCloseEvent(state);
    case 'TOGGLE_JOURNAL': return handleToggleJournal(state);

    // Inventory & Market
    case 'ACQUIRE_ITEM': return handleAcquireItem(state, action.payload);
    case 'PAY_COST': return handlePayCost(state, action.payload);
    case 'BUY_MARKET_ITEMS': return handleBuyMarketItems(state, action.payload);
    case 'INSTALL_FURNACE': return handleInstallFurnace(state);
    case 'SELL_ITEM': return handleSellItem(state, action.payload);
    case 'USE_ITEM': return handleUseItem(state, action.payload);
    case 'TOGGLE_LOCK_ITEM': return handleToggleLockItem(state, action.payload);

    // Crafting
    case 'START_CRAFTING': return handleStartCrafting(state, action.payload);
    case 'CANCEL_CRAFTING': return handleCancelCrafting(state, action.payload);
    case 'FINISH_CRAFTING': return handleFinishCrafting(state, action.payload);
    case 'DISMISS_CRAFTING_RESULT': return { ...state, lastCraftedItem: null };
    case 'DISMISS_TIER_UNLOCK': return { ...state, unlockedTierPopup: null };
    case 'SET_CRAFTING': return handleSetCrafting(state, action.payload);
    case 'UPDATE_FORGE_STATUS': return handleUpdateForgeStatus(state, action.payload);

    // Shop
    case 'TOGGLE_SHOP': return handleToggleShop(state);
    case 'ENQUEUE_CUSTOMER': return handleEnqueueCustomer(state, action.payload);
    case 'NEXT_CUSTOMER': return handleNextCustomer(state);
    case 'DISMISS_CUSTOMER': return handleDismissCustomer(state);
    case 'REFUSE_CUSTOMER': return handleRefuseCustomer(state, action.payload);

    // Mercenaries
    case 'ADD_KNOWN_MERCENARY': return handleAddKnownMercenary(state, action.payload);
    case 'SCOUT_MERCENARY': return handleScoutMercenary(state, action.payload);
    case 'HIRE_MERCENARY': return handleHireMercenary(state, action.payload);
    case 'FIRE_MERCENARY': return handleFireMercenary(state, action.payload);
    case 'GIVE_GIFT': return handleGiveGift(state, action.payload);
    case 'TALK_MERCENARY': return handleTalkMercenary(state, action.payload);
    case 'ALLOCATE_STAT': return handleAllocateStat(state, action.payload);
    case 'UPDATE_MERCENARY_STATS': return handleUpdateMercenaryStats(state, action.payload);

    // Garrick Market
    case 'TALK_GARRICK': return handleTalkGarrick(state);
    case 'GIFT_GARRICK': return handleGiftGarrick(state, action.payload);

    // Expedition
    case 'START_EXPEDITION': return handleStartExpedition(state, action.payload);
    case 'COMPLETE_EXPEDITION': return handleCompleteExpedition(state, action.payload);
    case 'CLAIM_EXPEDITION': return handleClaimExpedition(state, action.payload);
    case 'ABORT_EXPEDITION': return handleAbortExpedition(state, action.payload);
    case 'DISMISS_DUNGEON_RESULT': return handleDismissDungeonResult(state);

    // Equipment
    case 'EQUIP_ITEM': return handleEquipItem(state, action.payload);
    case 'UNEQUIP_ITEM': return handleUnequipItem(state, action.payload);

    // Manual Dungeon
    case 'START_MANUAL_DUNGEON': return handleStartManualDungeon(state, action.payload);
    case 'MOVE_MANUAL_DUNGEON': return handleMoveManualDungeon(state, action.payload);
    case 'FINISH_MANUAL_DUNGEON': return handleFinishManualDungeon(state);
    case 'RETREAT_MANUAL_DUNGEON': return handleRetreatManualDungeon(state);
    case 'TOGGLE_MANUAL_DUNGEON_OVERLAY': return { ...state, showManualDungeonOverlay: action.payload };
    case 'RESCUE_NPC': return handleRescueNPC(state, action.payload);
    case 'START_COMBAT_MANUAL': return handleStartCombatManual(state);
    case 'RESOLVE_COMBAT_MANUAL': return handleResolveCombatManual(state, action.payload);

    // Tutorial & Prologue
    case 'SET_TUTORIAL_STEP': return { ...state, tutorialStep: action.payload };
    case 'SET_ACTIVE_TUTORIAL_SCENE': return { ...state, activeTutorialScene: action.payload };
    case 'COMPLETE_PROLOGUE': 
        return { 
            ...state, 
            hasCompletedPrologue: true,
            activeTutorialScene: null,
            tutorialStep: 'MARKET_GUIDE' 
        };
    case 'COMPLETE_TUTORIAL':
        const finalTabs = ['FORGE', 'MARKET', 'INVENTORY', 'SHOP', 'TAVERN', 'DUNGEON', 'SIMULATION'];
        return {
            ...state,
            tutorialStep: null,
            activeTutorialScene: null,
            unlockedTabs: finalTabs,
            stats: {
                ...state.stats,
                tierLevel: Math.max(state.stats.tierLevel, 1) 
            },
            forge: { ...state.forge, hasFurnace: true }, 
            showTutorialCompleteModal: true,
            logs: ["Tutorial completed. Lockhart's Forge is fully operational.", ...state.logs]
        };
    case 'DISMISS_TUTORIAL_COMPLETE':
        return { ...state, showTutorialCompleteModal: false };

    // User Preferences
    case 'UPDATE_SETTINGS':
        return {
            ...state,
            settings: { ...state.settings, ...action.payload }
        };

    // Toast Notifications
    case 'SHOW_TOAST':
        if (state.toast?.visible && state.toast.message === action.payload) {
            return state;
        }
        return {
            ...state,
            toastQueue: [...state.toastQueue, action.payload]
        };

    case 'POP_NEXT_TOAST':
        if (state.toastQueue.length === 0) return state;
        const [nextMessage, ...remainingQueue] = state.toastQueue;
        return {
            ...state,
            toast: { message: nextMessage, visible: true },
            toastQueue: remainingQueue
        };

    case 'HIDE_TOAST':
        return {
            ...state,
            toast: state.toast ? { ...state.toast, visible: false } : null
        };

    // UI Effects
    case 'SET_UI_EFFECT':
        return {
            ...state,
            uiEffects: {
                ...state.uiEffects,
                [action.payload.effect]: action.payload.value
            }
        };

    default:
      return state;
  }
};

