const MercenaryStatsPanel = ({ 
    mercenary, 
    baseStats,
    finalStats, 
    localAllocated, 
    onSetLocalAllocated,
    isReadOnly
}: { 
    mercenary: Mercenary; 
    baseStats: DerivedStats;
    finalStats: DerivedStats; 
    localAllocated: PrimaryStats;
    onSetLocalAllocated: (stats: PrimaryStats) => void;
    isReadOnly?: boolean;
}) => {
    const { actions } = useGame();
    const xpPercent = mercenary.xpToNextLevel > 0 ? Math.min(100, Math.max(0, (mercenary.currentXp / mercenary.xpToNextLevel) * 100)) : 0;
    const hpPercent = finalStats.maxHp > 0 ? (mercenary.currentHp / finalStats.maxHp) * 100 : 0;
    const mpPercent = finalStats.maxMp > 0 ? (mercenary.currentMp / finalStats.maxMp) * 100 : 0;

    const totalUsedLocal = Object.values(localAllocated).reduce((a, b) => a + b, 0);
    const totalPoints = (mercenary.level - 1) * 3;
    const availablePoints = Math.max(0, totalPoints - totalUsedLocal);
    const hasChanges = JSON.stringify(localAllocated) !== JSON.stringify(mercenary.allocatedStats);

    const renderStatRow = (icon: React.ReactNode, label: string, baseValue: number, nextValue: number, isPercent = false) => {
        const diff = nextValue - baseValue;
        const colorClass = diff > 0 ? 'text-emerald-400' : diff < 0 ? 'text-red-400' : 'text-stone-300';
        return (
            <div className="bg-stone-950/40 p-1.5 md:p-3 rounded-lg border border-white/5 flex justify-between items-center h-8 md:h-12">
                <span className="text-[7px] md:text-xs text-stone-500 font-black uppercase flex items-center gap-1.5 md:gap-2">
                    {icon} 
                    <span className="hidden md:inline">{label}</span>
                    <span className="md:hidden">
                        {label === 'Physical Atk' ? 'P.Atk' : 
                         label === 'Physical Def' ? 'P.Def' : 
                         label === 'Magical Atk' ? 'M.Atk' : 
                         label === 'Magical Def' ? 'M.Def' : 
                         label === 'Crit Rate' ? 'Crit' : 
                         label === 'Evasion' ? 'Eva' : label}
                    </span>
                </span>
                <div className="flex items-center gap-1 md:gap-2">
                    <span className={`font-mono text-[9px] md:text-base font-black ${colorClass}`}>
                        {isPercent ? nextValue.toFixed(1) : Math.round(nextValue)}{isPercent ? '%' : ''}
                    </span>
                    <StatDiff current={baseValue} next={nextValue} isPercent={isPercent} />
                </div>
            </div>
        );
    };

    const updateLocalStat = (key: keyof PrimaryStats, delta: number) => {
        const newVal = localAllocated[key] + delta;
        if (delta > 0 && availablePoints <= 0) return;
        if (delta < 0 && newVal < mercenary.allocatedStats[key]) return;
        onSetLocalAllocated({ ...localAllocated, [key]: newVal });
    };

    return (
        <div className="flex-1 overflow-y-auto custom-scrollbar p-3 md:p-6 flex flex-col gap-4 md:gap-6 min-h-0 bg-stone-900/10">
            <div className="bg-stone-950/40 p-2 md:p-5 rounded-xl border border-white/5 shadow-inner shrink-0">
                <div className="flex justify-between items-end mb-1 md:mb-2 leading-none">
                    <span className="text-amber-500 font-black font-mono text-[10px] md:text-lg uppercase tracking-tight">LV {mercenary.level}</span>
                    <span className="text-stone-500 text-[8px] md:text-sm font-mono font-bold">{mercenary.currentXp} / {mercenary.xpToNextLevel} XP</span>
                </div>
                <div className="w-full h-1 md:h-2 bg-stone-900 rounded-full overflow-hidden border border-white/5">
                    <div className="h-full bg-gradient-to-r from-amber-800 to-amber-500 transition-all duration-700" style={{ width: `${xpPercent}%` }}></div>
                </div>
            </div>

            <div className="bg-stone-950/60 rounded-xl border border-stone-800 p-3 md:p-6 shrink-0 relative overflow-hidden">
                <div className="flex justify-between items-center mb-3 md:mb-4 px-1">
                    <h4 className="text-[8px] md:text-xs font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5 md:gap-2"><Star className="w-3 h-3 text-amber-600" /> Attributes</h4>
                    {!isReadOnly && availablePoints > 0 && (
                         <span className="text-[8px] md:text-xs font-black text-amber-400 px-2 md:px-3 py-0.5 md:py-1 bg-amber-900/30 border border-amber-500/30 rounded-full animate-pulse">POINTS: {availablePoints}</span>
                    )}
                </div>
                <div className="grid grid-cols-5 gap-1.5 md:gap-4">
                    {[
                        { label: 'STR', key: 'str' as const, color: 'text-orange-400' },
                        { label: 'INT', key: 'int' as const, color: 'text-blue-400' },
                        { label: 'DEX', key: 'dex' as const, color: 'text-emerald-400' },
                        { label: 'VIT', key: 'vit' as const, color: 'text-red-400' },
                        { label: 'LUK', key: 'luk' as const, color: 'text-pink-400' }
                    ].map((stat) => {
                        const currentValue = mercenary.stats[stat.key] + localAllocated[stat.key];
                        const isModified = localAllocated[stat.key] > mercenary.allocatedStats[stat.key];
                        return (
                            <div key={stat.key} className="flex flex-col gap-1 md:gap-1.5">
                                <div className={`bg-stone-900/80 border ${isModified ? 'border-amber-500 shadow-glow-sm' : 'border-stone-800'} p-1 md:p-2 rounded-lg flex flex-col items-center justify-center h-12 md:h-20 transition-all`}>
                                    <span className={`text-[6px] md:text-[10px] font-black ${stat.color} mb-0.5`}>{stat.label}</span>
                                    <span className={`text-[10px] md:text-xl font-mono font-black ${isModified ? 'text-amber-400' : 'text-stone-400'}`}>{currentValue}</span>
                                </div>
                                {!isReadOnly && (
                                    <div className="flex flex-col gap-0.5 md:gap-1">
                                        <button onClick={() => updateLocalStat(stat.key, 1)} disabled={availablePoints <= 0} className="w-full h-4 md:h-8 bg-stone-800 hover:bg-amber-600 text-stone-500 hover:text-white rounded transition-all disabled:opacity-0 flex items-center justify-center shadow-sm"><Plus className="w-3 h-3" /></button>
                                        <button onClick={() => updateLocalStat(stat.key, -1)} disabled={localAllocated[stat.key] <= mercenary.allocatedStats[stat.key]} className="w-full h-3 md:h-6 bg-stone-950 hover:bg-red-700 text-stone-700 hover:text-white rounded transition-all disabled:opacity-0 flex items-center justify-center"><Minus className="w-2.5 h-2.5" /></button>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
                {!isReadOnly && hasChanges && (
                    <div className="mt-4 md:mt-6 flex gap-2 md:gap-3 animate-in slide-in-from-top-2">
                        <button onClick={() => onSetLocalAllocated({ ...mercenary.allocatedStats })} className="flex-1 py-2 bg-stone-800 text-stone-500 text-[10px] font-black rounded-lg transition-all uppercase">Discard</button>
                        <button onClick={() => actions.updateMercenaryStats(mercenary.id, localAllocated)} className="flex-[2] py-2 bg-amber-700 text-white text-[10px] font-black rounded-lg shadow-lg transition-all uppercase">Confirm</button>
                    </div>
                )}
            </div>

            <div className="grid grid-cols-2 gap-2 md:gap-6 shrink-0">
                <div className="bg-stone-950/40 p-2 md:p-5 rounded-xl border border-white/5 flex items-center gap-2 md:gap-4 shadow-sm">
                    <div className="p-1.5 md:p-3 bg-red-950/40 rounded-lg text-red-500 border border-red-900/30"><Heart className="w-4 h-4 md:w-7 md:h-7" /></div>
                    <div className="flex-1 min-w-0">
                        <div className="flex justify-between text-[7px] md:text-xs text-stone-500 font-black mb-0.5 md:mb-1"><span>HP</span><span className="text-stone-300 font-mono">{mercenary.currentHp}/{finalStats.maxHp}</span></div>
                        <div className="w-full h-1 md:h-2 bg-stone-900 rounded-full overflow-hidden shadow-inner"><div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${hpPercent}%` }}></div></div>
                    </div>
                </div>
                <div className="bg-stone-950/40 p-2 md:p-5 rounded-xl border border-white/5 flex items-center gap-2 md:gap-4 shadow-sm">
                    <div className="p-1.5 md:p-3 bg-blue-950/40 rounded-lg text-blue-500 border border-blue-900/30"><Activity className="w-4 h-4 md:w-7 md:h-7" /></div>
                    <div className="flex-1 min-w-0">
                        <div className="flex justify-between text-[7px] md:text-xs text-stone-500 font-black mb-0.5 md:mb-1"><span>MP</span><span className="text-stone-300 font-mono">{mercenary.currentMp}/{finalStats.maxMp}</span></div>
                        <div className="w-full h-1 md:h-2 bg-stone-900 rounded-full overflow-hidden shadow-inner"><div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPercent}%` }}></div></div>
                    </div>
                </div>
            </div>

            <div className="space-y-2 md:space-y-3 pb-6 shrink-0">
                <h4 className="text-[8px] md:text-xs font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5 px-1"><Sword className="w-3 h-3" /> Battle Performance</h4>
                <div className="grid grid-cols-2 gap-1.5 md:gap-4">
                    {renderStatRow(<Sword className="w-3 h-3 md:w-4 md:h-4 text-orange-500" />, 'Physical Atk', baseStats.physicalAttack, finalStats.physicalAttack)}
                    {renderStatRow(<Shield className="w-3 h-3 md:w-4 md:h-4 text-blue-500" />, 'Physical Def', baseStats.physicalDefense, finalStats.physicalDefense)}
                    {renderStatRow(<Zap className="w-3 h-3 md:w-4 md:h-4 text-blue-400" />, 'Magical Atk', baseStats.magicalAttack, finalStats.magicalAttack)}
                    {renderStatRow(<Brain className="w-3 h-3 md:w-4 md:h-4 text-purple-400" />, 'Magical Def', baseStats.magicalDefense, finalStats.magicalDefense)}
                    {renderStatRow(<Target className="w-3 h-3 md:w-4 md:h-4 text-red-500" />, 'Crit Rate', baseStats.critChance, finalStats.critChance, true)}
                    {renderStatRow(<Wind className="w-3 h-3 md:w-4 md:h-4 text-emerald-400" />, 'Evasion', baseStats.evasion, finalStats.evasion)}
                </div>
            </div>
        </div>
    );
};

const EquipmentInventoryList = ({ 
    inventory, 
    selectedItemId,
    onSelect,
    onEquip,
    selectedSlotFilter,
    mercenary,
    isReadOnly
}: { 
    inventory: InventoryItem[]; 
    selectedItemId: string | null;
    onSelect: (itemId: string) => void;
    onEquip: (itemId: string) => void;
    selectedSlotFilter: EquipmentSlotType | null;
    mercenary: Mercenary;
    isReadOnly?: boolean;
}) => {
    // Current primary stats INCLUDING equipment bonuses for guide verification
    const totalMercStats = useMemo(() => {
        const eqPrimaryStats = Object.values(mercenary.equipment).filter(Boolean).reduce((acc, eq) => ({
            str: acc.str + (eq!.stats.str || 0),
            vit: acc.vit + (eq!.stats.vit || 0),
            dex: acc.dex + (eq!.stats.dex || 0),
            int: acc.int + (eq!.stats.int || 0),
            luk: acc.luk + (eq!.stats.luk || 0),
        }), { str: 0, vit: 0, dex: 0, int: 0, luk: 0 });
        return mergePrimaryStats(mercenary.stats, mercenary.allocatedStats, eqPrimaryStats);
    }, [mercenary]);

    const displayInventory = useMemo(() => {
        return selectedSlotFilter 
            ? inventory.filter(item => item.equipmentData?.slotType === selectedSlotFilter)
            : inventory;
    }, [inventory, selectedSlotFilter]);

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return 'MASTERWORK';
        if (q >= 100) return 'PRISTINE';
        if (q >= 90) return 'SUPERIOR';
        if (q >= 80) return 'FINE';
        if (q >= 70) return 'STANDARD';
        if (q >= 60) return 'RUSTIC';
        return 'CRUDE';
    };

    return (
        <div className="flex-1 flex flex-col min-h-0 bg-stone-950/40">
            <div className="p-3 md:p-6 bg-stone-900/60 border-b border-white/5 flex justify-between items-center shrink-0 z-10 backdrop-blur-md">
                <h3 className="text-[9px] md:text-xs font-black text-stone-400 uppercase tracking-widest flex items-center gap-2">
                    <Box className="w-4 h-4 text-amber-600" /> 
                    <span>{selectedSlotFilter ? `Filtering: ${selectedSlotFilter}` : 'Available Gear'}</span>
                </h3>
                <span className="text-[8px] md:text-xs text-stone-600 font-mono">{displayInventory.length} ITEMS</span>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-3 md:p-6 space-y-2 md:space-y-3">
                {displayInventory.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-stone-800 italic p-12 text-center">
                        <Box className="w-12 h-12 opacity-10 mb-2" />
                        <p className="text-xs">No suitable gear found.</p>
                    </div>
                ) : (
                    displayInventory.map(item => {
                        if (!item.equipmentData) return null;
                        const isSelected = selectedItemId === item.id;
                        const reqs = item.equipmentData.equipRequirements || {};
                        const failedStats = Object.entries(reqs).filter(([stat, val]) => totalMercStats[stat as keyof PrimaryStats] < (val as number));
                        const canEquip = failedStats.length === 0;
                        const rarityClasses = getRarityClasses(item.equipmentData.rarity);
                        let imageUrl = item.equipmentData.image ? getAssetUrl(item.equipmentData.image) : (item.equipmentData.recipeId ? getAssetUrl(`${item.equipmentData.recipeId}.png`) : getAssetUrl(`${item.id.split('_')[0]}.png`));

                        return (
                            <div 
                                key={item.id}
                                onClick={() => !isSelected && onSelect(item.id)}
                                className={`flex flex-col gap-2 p-3 md:p-5 rounded-xl border transition-all ${isSelected ? 'border-amber-500 bg-stone-900/80 shadow-inner' : 'border-stone-800 bg-stone-900/30'} cursor-pointer group ${!canEquip ? 'opacity-60' : ''}`}
                            >
                                <div className="flex items-center gap-3 md:gap-4">
                                    <div className={`w-10 h-10 md:w-16 md:h-16 bg-stone-950 rounded-lg border-2 flex items-center justify-center shrink-0 ${rarityClasses}`}>
                                        <img src={imageUrl} className="w-8 h-8 md:w-12 md:h-12 object-contain" />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className="text-[11px] md:text-lg font-black truncate text-stone-200">{item.name}</div>
                                        <div className="flex flex-wrap items-center gap-2 mt-1">
                                            <span className={`text-[7px] md:text-[9px] px-1.5 py-0.5 rounded font-black uppercase border leading-none ${rarityClasses}`}>
                                                {item.equipmentData.rarity}
                                            </span>
                                            <span className="text-[7px] md:text-[9px] text-stone-600 font-mono font-bold">LV.{item.equipmentData.quality >= 100 ? 'EX' : 'ST'}</span>
                                        </div>
                                    </div>
                                    {!isReadOnly && isSelected && canEquip && (
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); onEquip(item.id); }}
                                            className="shrink-0 px-3 md:px-8 py-1.5 md:py-3 bg-amber-700 hover:bg-amber-600 text-white text-[9px] md:text-xs font-black uppercase rounded shadow-lg transition-all"
                                        >
                                            Equip
                                        </button>
                                    )}
                                </div>
                                <div className="flex justify-between items-center border-t border-white/5 pt-2">
                                    <div className="flex items-center gap-2 text-[8px] md:text-xs text-stone-600 font-bold">
                                        <ShieldAlert className="w-3 h-3" />
                                        DUR: {item.equipmentData.durability}/{item.equipmentData.maxDurability}
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <span className="text-[7px] md:text-[9px] text-amber-600 font-black uppercase tracking-tighter bg-amber-950/20 px-1.5 py-0.5 rounded border border-amber-900/20">
                                            {getQualityLabel(item.equipmentData.quality)}
                                        </span>
                                    </div>
                                </div>
                            </div>
                        );
                    })
                )}
            </div>
        </div>
    );
};

const MercenaryDetailModal: React.FC<MercenaryDetailModalProps> = ({ mercenary, onClose, onUnequip, isReadOnly = false }) => {
    const { state, actions } = useGame();
    const [selectedSlot, setSelectedSlot] = useState<EquipmentSlotType | null>(null);
    const [selectedInventoryItemId, setSelectedInventoryItemId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'STATS' | 'STORAGE'>('STATS');
    const [localAllocated, setLocalAllocated] = useState<PrimaryStats>({ str: 0, vit: 0, dex: 0, int: 0, luk: 0 });

    useEffect(() => {
        if (mercenary) {
            setSelectedSlot(null);
            setSelectedInventoryItemId(null);
            setLocalAllocated({ ...mercenary.allocatedStats });
            setActiveTab('STATS');
        }
    }, [mercenary?.id]);

    if (!mercenary) return null;

    // --- Core Stat Logic Sync ---
    const currentEqPrimaryStats = useMemo(() => {
        return Object.values(mercenary.equipment).filter(Boolean).reduce((acc, eq) => ({
            str: acc.str + (eq!.stats.str || 0),
            vit: acc.vit + (eq!.stats.vit || 0),
            dex: acc.dex + (eq!.stats.dex || 0),
            int: acc.int + (eq!.stats.int || 0),
            luk: acc.luk + (eq!.stats.luk || 0),
        }), { str: 0, vit: 0, dex: 0, int: 0, luk: 0 });
    }, [mercenary.equipment]);

    const mergedPrimary = mergePrimaryStats(mercenary.stats, localAllocated, currentEqPrimaryStats);
    const baseDerived = calculateDerivedStats(mergedPrimary, mercenary.level);
    const currentEquipmentStats = (Object.values(mercenary.equipment) as (Equipment | null)[]).map(eq => eq?.stats).filter(Boolean);
    const currentStats = applyEquipmentBonuses(baseDerived, currentEquipmentStats as any);
    const currentAttackType = mergedPrimary.int > mergedPrimary.str ? 'MAGICAL' : 'PHYSICAL';
    const currentCombatPower = calculateCombatPower(currentStats, mercenary.job, currentAttackType);

    // --- Preview Logic Sync ---
    let previewStats: DerivedStats | null = null;
    let previewCombatPower: number | null = null;
    if (selectedInventoryItemId) {
        const item = state.inventory.find(i => i.id === selectedInventoryItemId)?.equipmentData;
        if (item) {
            const previewEq = { ...mercenary.equipment };
            if (item.slotType === 'MAIN_HAND' && item.isTwoHanded) previewEq.OFF_HAND = null;
            else if (item.slotType === 'OFF_HAND' && previewEq.MAIN_HAND?.isTwoHanded) previewEq.MAIN_HAND = null;
            previewEq[item.slotType] = item;

            const previewEqPrimary = Object.values(previewEq).filter(Boolean).reduce((acc, eq) => ({
                str: acc.str + (eq!.stats.str || 0),
                vit: acc.vit + (eq!.stats.vit || 0),
                dex: acc.dex + (eq!.stats.dex || 0),
                int: acc.int + (eq!.stats.int || 0),
                luk: acc.luk + (eq!.stats.luk || 0),
            }), { str: 0, vit: 0, dex: 0, int: 0, luk: 0 });

            const previewMerged = mergePrimaryStats(mercenary.stats, localAllocated, previewEqPrimary);
            const previewBase = calculateDerivedStats(previewMerged, mercenary.level);
            previewStats = applyEquipmentBonuses(previewBase, (Object.values(previewEq) as (Equipment | null)[]).map(e => e?.stats).filter(Boolean) as any);
            previewCombatPower = calculateCombatPower(previewStats, mercenary.job, previewMerged.int > previewMerged.str ? 'MAGICAL' : 'PHYSICAL');
        }
    }

    const effectiveFinalStats = previewStats || currentStats;
    const effectiveCombatPower = previewCombatPower !== null ? previewCombatPower : currentCombatPower;

    return (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-2 md:p-6 py-[15dvh] md:py-6 animate-in fade-in duration-300 overflow-hidden">
            <button 
                onClick={onClose} 
                className="fixed top-4 right-4 z-[1050] p-1.5 md:p-3 bg-red-900/30 hover:bg-red-600 rounded-full text-red-500 hover:text-white border border-red-500/30 transition-all shadow-2xl backdrop-blur-md active:scale-90"
            >
                <X className="w-4 h-4 md:w-6 md:h-6" />
            </button>

            <div className="w-full h-full md:max-w-7xl md:h-[90dvh] bg-stone-950 border border-white/10 rounded-2xl md:rounded-[2rem] shadow-2xl flex flex-row overflow-hidden relative ring-1 ring-white/10">
                <MercenaryPaperDoll 
                    mercenary={mercenary} 
                    baseCombatPower={currentCombatPower}
                    nextCombatPower={effectiveCombatPower} 
                    showAffinityGain={false} 
                    onUnequip={(slot) => onUnequip(mercenary.id, slot)} 
                    onSlotClick={(s) => { setSelectedSlot(s); if(s) setActiveTab('STORAGE'); }} 
                    selectedSlot={selectedSlot} 
                    isReadOnly={isReadOnly}
                />

                <div className="flex-1 bg-stone-900/30 flex flex-col h-full overflow-hidden">
                    <div className="flex border-b border-white/5 bg-stone-950/80 shrink-0 z-20 backdrop-blur-3xl pr-16 md:pr-0">
                        <button 
                            onClick={() => setActiveTab('STATS')}
                            className={`flex-1 py-3 md:py-6 text-[10px] md:text-sm font-black uppercase tracking-widest flex items-center justify-center gap-1.5 md:gap-3 transition-all whitespace-nowrap ${activeTab === 'STATS' ? 'text-amber-400 bg-stone-900/60 border-b-2 border-amber-500' : 'text-stone-600 hover:text-stone-300'}`}
                        >
                            <Activity className="w-3.5 h-3.5 md:w-5 md:h-5" /> <span>Stats</span>
                        </button>
                        <button 
                            onClick={() => setActiveTab('STORAGE')}
                            className={`flex-1 py-3 md:py-6 text-[10px] md:text-sm font-black uppercase tracking-widest flex items-center justify-center gap-1.5 md:gap-3 transition-all whitespace-nowrap ${activeTab === 'STORAGE' ? 'text-amber-400 bg-stone-900/60 border-b-2 border-amber-500' : 'text-stone-600 hover:text-stone-300'}`}
                        >
                            <Box className="w-3.5 h-3.5 md:w-5 md:h-5" /> <span>Storage</span>
                        </button>
                    </div>

                    <div className="flex-1 flex flex-col min-h-0 overflow-hidden px-safe pb-safe">
                        {activeTab === 'STATS' ? (
                            <MercenaryStatsPanel 
                                mercenary={mercenary} 
                                baseStats={currentStats}
                                finalStats={effectiveFinalStats} 
                                localAllocated={localAllocated}
                                onSetLocalAllocated={setLocalAllocated}
                                isReadOnly={isReadOnly}
                            />
                        ) : (
                            <EquipmentInventoryList 
                                inventory={state.inventory.filter(i => i.type === 'EQUIPMENT')} 
                                selectedItemId={selectedInventoryItemId} 
                                onSelect={setSelectedInventoryItemId} 
                                onEquip={(id) => { actions.equipItem(mercenary.id, id); setSelectedInventoryItemId(null); }} 
                                selectedSlotFilter={selectedSlot}
                                mercenary={mercenary}
                                isReadOnly={isReadOnly}
                            />
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default MercenaryDetailModal;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { EQUIPMENT_SUBCATEGORIES, EQUIPMENT_ITEMS } from '../../../data/equipment';
import { EquipmentCategory, EquipmentItem } from '../../../types/index';
import SmithingMinigame from './SmithingMinigame';
import WorkbenchMinigame from './WorkbenchMinigame';
import { Hammer, Shield, Sword, ChevronRight, Info, ChevronLeft, Lock, Check, X as XIcon, Box, Flame, ChevronDown, ChevronUp, Heart, Star, Zap, Award, Wrench, X, ShoppingCart, Brain, AlertCircle, TrendingUp, Sparkles, FastForward, Activity, Loader2 } from 'lucide-react';
import { useGame } from '../../../context/GameContext';
import { GAME_CONFIG } from '../../../config/game-config';
import { MASTERY_THRESHOLDS } from '../../../config/mastery-config';
import { MATERIALS } from '../../../data/materials';
import { getAssetUrl } from '../../../utils';
import { getSmithingLevel, getUnlockedTier, LEVEL_EXP_TABLE } from '../../../utils/craftingLogic';

interface ForgeTabProps {
    onNavigate: (tab: any) => void;
}

const SkillHeader = ({ exp, label, icon: Icon }: { exp: number, label: string, icon: any }) => {
    const level = getSmithingLevel(exp);
    const tier = getUnlockedTier(level);
    const currentExpInLevel = exp - (LEVEL_EXP_TABLE[level - 1] || 0);
    const nextLevelExpThreshold = (LEVEL_EXP_TABLE[level] || LEVEL_EXP_TABLE[level-1]) - (LEVEL_EXP_TABLE[level-1] || 0);
    const progress = Math.min(100, (currentExpInLevel / (nextLevelExpThreshold || 1)) * 100);

    return (
        <div className="bg-stone-900/60 border border-stone-800 rounded-xl p-2 md:p-3 flex items-center gap-3 md:gap-4 shadow-inner min-w-[150px] md:min-w-[220px]">
            <div className="p-1.5 md:p-2 bg-stone-950 rounded-lg border border-stone-800 shadow-md flex flex-col items-center gap-1">
                <Icon className="w-3.5 h-3.5 md:w-5 md:h-5 text-amber-50" />
                <span className="text-[6px] md:text-[8px] font-black text-amber-50 uppercase">Tier {tier}</span>
            </div>
            <div className="flex-1 min-w-0">
                <div className="flex justify-between items-end mb-1">
                    <span className="text-[8px] md:text-[10px] font-black uppercase text-stone-500 tracking-widest">{label}</span>
                    <span className="text-stone-400 font-mono text-[10px] md:text-xs">LV.{level}</span>
                </div>
                <div className="w-full h-1 md:h-1.5 bg-stone-950 rounded-full overflow-hidden border border-white/5">
                    <div className="h-full bg-amber-600 transition-all duration-700" style={{ width: `${progress}%` }}></div>
                </div>
            </div>
        </div>
    );
};

const ForgeTab: React.FC<ForgeTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const { inventory, stats, isCrafting, craftingMastery, activeEvent, unlockedRecipes, tutorialStep } = state;
  const { hasFurnace, hasWorkbench } = state.forge;

  const [activeCategory, setActiveCategory] = useState<EquipmentCategory>('WEAPON');
  const [selectedItem, setSelectedItem] = useState<EquipmentItem | null>(null);
  const [isPanelOpen, setIsPanelOpen] = useState(true);
  const [isSkillsExpanded, setIsSkillsExpanded] = useState(false);

  const [expandedSubCat, setExpandedSubCat] = useState<string | null>(null);
  const [favorites, setFavorites] = useState<string[]>([]);

  const [hoveredItem, setHoveredItem] = useState<EquipmentItem | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });

  // Quick Craft Animation State
  const [quickCraftProgress, setQuickCraftProgress] = useState<number | null>(null);

  const smithingLevel = getSmithingLevel(stats.smithingExp);
  const workbenchLevel = getSmithingLevel(stats.workbenchExp);
  const unlockedSmithingTier = getUnlockedTier(smithingLevel);
  const unlockedWorkbenchTier = getUnlockedTier(workbenchLevel);

  const getInventoryCount = useCallback((id: string) => {
      return inventory.find(i => i.id === id)?.quantity || 0;
  }, [inventory]);

  const getItemImageUrl = (item: EquipmentItem) => {
    if (item.image) return getAssetUrl(item.image);
    return getAssetUrl(`${item.id}.png`);
  };

  const GLOBAL_COOLING_RATE_PER_SEC = 5; 
  const timeDiffSec = (Date.now() - (state.lastForgeTime || 0)) / 1000;
  const coolingAmount = timeDiffSec * GLOBAL_COOLING_RATE_PER_SEC;
  const currentResidualTemp = Math.max(0, (state.forgeTemperature || 0) - coolingAmount);

  const hasHeat = currentResidualTemp > 0;
  const charcoalCount = getInventoryCount('charcoal');
  const hasFuel = charcoalCount > 0;

  const isTutorialForging = tutorialStep === 'START_FORGING_GUIDE';

  const isRequirementMet = useMemo(() => {
    if (!selectedItem) return true;
    if (selectedItem.craftingType === 'FORGE') return hasFurnace;
    if (selectedItem.craftingType === 'WORKBENCH') return hasWorkbench;
    return true;
  }, [selectedItem, hasFurnace, hasWorkbench]);

  const canEnterForge = useMemo(() => {
      if (!selectedItem) return false;
      if (!isRequirementMet) return false;
      if (selectedItem.craftingType === 'WORKBENCH') return true;
      if (isTutorialForging) return true; 
      return hasFuel || hasHeat;
  }, [selectedItem, isRequirementMet, hasFuel, hasHeat, isTutorialForging]);

  const requiredEnergy = useMemo(() => {
      if (!selectedItem) return GAME_CONFIG.ENERGY_COST.CRAFT;
      const count = craftingMastery[selectedItem.id] || 0;
      if (count >= MASTERY_THRESHOLDS.ARTISAN) {
          return GAME_CONFIG.ENERGY_COST.CRAFT - MASTERY_THRESHOLDS.ARTISAN_BONUS.energyDiscount;
      }
      return GAME_CONFIG.ENERGY_COST.CRAFT;
  }, [selectedItem, craftingMastery]);

  const hasEnergy = stats.energy >= requiredEnergy;

  const canAffordResources = useCallback((item: EquipmentItem) => {
      return item.requirements.every(req => getInventoryCount(req.id) >= req.count);
  }, [getInventoryCount]);

  const visibleItems = useMemo(() => {
      return EQUIPMENT_ITEMS.filter(item => {
          const isUnlocked = item.unlockedByDefault !== false || unlockedRecipes?.includes(item.id);
          if (!isUnlocked) return false;

          const myTier = item.craftingType === 'FORGE' ? unlockedSmithingTier : unlockedWorkbenchTier;
          if (item.tier > myTier) return false;

          const subCatDef = EQUIPMENT_SUBCATEGORIES.find(sc => sc.id === item.subCategoryId);
          return subCatDef?.categoryId === activeCategory;
      });
  }, [activeCategory, unlockedSmithingTier, unlockedWorkbenchTier, unlockedRecipes]);

  const groupedItems = useMemo(() => {
      const groups: Record<string, EquipmentItem[]> = {};
      visibleItems.forEach(item => {
          if (!groups[item.subCategoryId]) groups[item.subCategoryId] = [];
          groups[item.subCategoryId].push(item);
      });
      return groups;
  }, [visibleItems]);

  const visibleSubCats = useMemo(() => {
      return EQUIPMENT_SUBCATEGORIES.filter(sc => 
          sc.categoryId === activeCategory && groupedItems[sc.id] && groupedItems[sc.id].length > 0
      );
  }, [activeCategory, groupedItems]);

  useEffect(() => {
      if (visibleSubCats.length > 0) {
          const isCurrentValid = visibleSubCats.some(sc => sc.id === expandedSubCat);
          if (!isCurrentValid) {
              setExpandedSubCat(visibleSubCats[0].id);
          }
      } else {
          setExpandedSubCat(null);
      }
  }, [activeCategory, visibleSubCats, expandedSubCat]);

  const handleCategoryChange = useCallback((cat: EquipmentCategory) => {
    setActiveCategory(cat);
    setSelectedItem(null);   
  }, []);

  const toggleSubCategory = useCallback((subCatId: string) => {
      setExpandedSubCat(prev => (prev === subCatId ? null : subCatId));
  }, []);

  const toggleFavorite = useCallback((e: React.MouseEvent, itemId: string) => {
      e.stopPropagation(); 
      setFavorites(prev => prev.includes(itemId) ? prev.filter(id => id !== itemId) : [...prev, itemId]);
  }, []);

  const quickCraftFuelCost = useMemo(() => {
      if (!selectedItem || selectedItem.craftingType !== 'FORGE') return 0;
      const d = selectedItem.maxDurability;
      if (d < 80) return 2;
      if (d < 150) return 3;
      if (d < 300) return 4;
      return 5;
  }, [selectedItem]);

  const startCrafting = useCallback(() => {
      if (!selectedItem) return;

      if (!isRequirementMet) {
          const facility = selectedItem.craftingType === 'FORGE' ? 'Furnace' : 'Workbench';
          actions.triggerEvent({
              id: 'NONE',
              title: 'Installation Required',
              description: `You are attempting to craft equipment that requires a ${facility}. This essential unit is currently missing from your forge. Visit the Market to acquire the necessary infrastructure.`,
              options: [
                  { label: 'Visit Market', action: () => onNavigate('MARKET') },
                  { label: 'Stay here', action: () => {} }
              ]
          });
          return;
      }

      const missing = selectedItem.requirements.filter(req => getInventoryCount(req.id) < req.count);
      if (missing.length > 0) {
          const names = missing.map(m => {
              const def = Object.values(MATERIALS).find(mat => mat.id === m.id);
              const needed = m.count - getInventoryCount(m.id);
              return `${def ? def.name : m.id} x${needed}`;
          }).join(', ');
          actions.showToast(`Insufficient: ${names}`);
          return;
      }

      if (!hasEnergy) {
          actions.triggerEnergyHighlight();
          actions.showToast("Not enough energy.");
          return;
      }
      if (selectedItem.craftingType === 'FORGE' && !canEnterForge) {
          actions.showToast("Forge is cold! Add fuel first.");
          return;
      }

      actions.startCrafting(selectedItem);
      setIsPanelOpen(false); 
  }, [actions, selectedItem, isRequirementMet, getInventoryCount, hasEnergy, canEnterForge, onNavigate]);

  const cancelCrafting = useCallback(() => {
      if (selectedItem) actions.cancelCrafting(selectedItem);
      else actions.setCrafting(false); 
      setIsPanelOpen(true);
  }, [actions, selectedItem]);

  const handleMinigameComplete = useCallback((score: number, bonus?: number) => {
    if (selectedItem) {
        const wasTutorialStep = tutorialStep === 'START_FORGING_GUIDE' && selectedItem.id === 'sword_bronze_t1';
        actions.finishCrafting(selectedItem, score, bonus);
        if (wasTutorialStep) {
            actions.setTutorialStep('CRAFT_RESULT_PROMPT');
        }
    }
    setIsPanelOpen(true);
  }, [selectedItem, actions, tutorialStep]);

  const handleMouseEnter = useCallback((item: EquipmentItem, e: React.MouseEvent) => {
      setHoveredItem(item);
      updateTooltipPosition(e.clientX, e.clientY);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
      if (hoveredItem) updateTooltipPosition(e.clientX, e.clientY);
  }, [hoveredItem]);

  const updateTooltipPosition = (x: number, y: number) => {
      const viewportW = window.innerWidth;
      const viewportH = window.innerHeight;
      let finalX = x + 20;
      let finalY = y + 20;
      const tooltipW = viewportW < 768 ? Math.max(160, viewportW * 0.4) : 256; 
      if (finalX + tooltipW > viewportW) finalX = x - tooltipW - 20;
      if (finalY + 160 > viewportH) finalY = y - 180;
      setTooltipPos({ x: finalX, y: finalY });
  };

  const handleMouseLeave = useCallback(() => setHoveredItem(null), []);

  const handleSelectItem = (item: EquipmentItem) => {
      setSelectedItem(item);
      if (state.tutorialStep === 'SELECT_SWORD_GUIDE' && item.id === 'sword_bronze_t1') {
          actions.setTutorialStep('START_FORGING_GUIDE');
      }
  };

  const renderStats = (item: EquipmentItem) => {
    if (!item.baseStats) return null;
    const s = item.baseStats;
    return (
        <div className="grid grid-cols-2 gap-1.5 md:gap-3 w-full max-w-xs mb-4 md:mb-6 animate-in slide-in-from-bottom-2 duration-500 mx-auto">
            {s.physicalAttack > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Sword className="w-2.5 h-2.5" /> P.Atk</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.physicalAttack}</span>
                </div>
            )}
            {s.magicalAttack > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Zap className="w-2.5 h-2.5" /> M.Atk</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.magicalAttack}</span>
                </div>
            )}
            {s.physicalDefense > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Shield className="w-2.5 h-2.5" /> P.Def</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.physicalDefense}</span>
                </div>
            )}
            {s.magicalDefense > 0 && (
            <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Brain className="w-2.5 h-2.5" /> M.Def</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.magicalDefense}</span>
                </div>
            )}
        </div>
    );
  };

  const renderItemCard = (item: EquipmentItem) => {
      const isSelected = selectedItem?.id === item.id;
      const isFav = favorites.includes(item.id);
      const count = inventory.filter(i => i.name === item.name).length;
      return (
        <div 
            key={item.id} 
            onClick={() => handleSelectItem(item)}
            data-tutorial-id={item.id === 'sword_bronze_t1' ? 'SWORD_RECIPE' : undefined}
            onMouseEnter={(e) => handleMouseEnter(item, e)} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave}
            className={`relative flex flex-col items-center rounded-lg border transition-all cursor-pointer group text-left h-[115px] md:h-[130px] overflow-hidden ${isSelected ? 'bg-amber-900/20 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.2)]' : 'bg-stone-800 border-stone-700 hover:border-stone-500 hover:bg-stone-750'}`}
        >
            <div className="w-full flex justify-between items-start p-1.5 md:p-2 z-10">
                 <span className={`text-[8px] md:text-[10px] font-bold tracking-wider font-mono ${isSelected ? 'text-amber-400' : 'text-stone-600'}`}>T{item.tier}</span>
                 <button onClick={(e) => toggleFavorite(e, item.id)} className="p-1 rounded-full hover:bg-stone-700 transition-colors"><Heart className={`w-3 h-3 md:w-3.5 md:h-3.5 ${isFav ? 'fill-red-500 text-red-500' : 'text-stone-600 hover:text-stone-400'}`} /></button>
            </div>
            <div className="flex-1 flex items-center justify-center group-hover:scale-110 transition-transform -mt-2"><img src={getItemImageUrl(item)} className="w-8 h-8 md:w-10 md:h-10 object-contain drop-shadow-md" /></div>
            <div className="w-full text-center pb-1.5 px-1 flex flex-col items-center gap-0.5"><div className={`text-[10px] md:text-xs font-bold leading-tight truncate w-full ${isSelected ? 'text-amber-200' : 'text-stone-300'}`}>{item.name}</div>{count > 0 && <div className="inline-flex items-center gap-0.5 bg-stone-950/50 px-1.5 py-0.5 rounded text-[8px] font-mono text-stone-500 border border-stone-800/50"><Box className="w-2 h-2" /> {count}</div>}</div>
        </div>
      );
  };

  const masteryInfo = useMemo(() => {
    if (!selectedItem) return null;
    const count = craftingMastery[selectedItem.id] || 0;
    let label = "Novice";
    let colorClass = "stroke-stone-500";
    let glowClass = "shadow-[0_0_20px_rgba(120,113,108,0.2)]";
    let progress = 0;

    if (count >= MASTERY_THRESHOLDS.ARTISAN) {
      label = "Artisan";
      colorClass = "stroke-amber-500";
      glowClass = "shadow-[0_0_40px_rgba(245,158,11,0.3)]";
      progress = Math.min(100, ((count - MASTERY_THRESHOLDS.ARTISAN) / 20) * 100);
    } else if (count >= MASTERY_THRESHOLDS.ADEPT) {
      label = "Adept";
      colorClass = "stroke-emerald-500";
      glowClass = "shadow-[0_0_30px_rgba(16,185,129,0.2)]";
      progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
    } else {
      label = "Novice";
      colorClass = "stroke-stone-400";
      glowClass = "shadow-[0_0_20px_rgba(168,162,158,0.15)]";
      progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
    }

    const radius = 46;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    return { label, colorClass, glowClass, progress, circumference, offset, count };
  }, [selectedItem, craftingMastery]);

  const handleQuickCraft = useCallback(() => {
      if (!selectedItem || !masteryInfo) return;

      if (!isRequirementMet) {
          const facility = selectedItem.craftingType === 'FORGE' ? 'Furnace' : 'Workbench';
          actions.triggerEvent({
              id: 'NONE',
              title: 'Installation Required',
              description: `High-speed production requires the specific ${facility} unit. Please install the facility via Market before attempting advanced crafting techniques.`,
              options: [
                  { label: 'Visit Market', action: () => onNavigate('MARKET') },
                  { label: 'Return', action: () => {} }
              ]
          });
          return;
      }

      const missing = selectedItem.requirements.filter(req => getInventoryCount(req.id) < req.count);
      if (missing.length > 0) {
          const names = missing.map(m => {
              const def = Object.values(MATERIALS).find(mat => mat.id === m.id);
              const needed = m.count - getInventoryCount(m.id);
              return `${def ? def.name : m.id} x${needed}`;
          }).join(', ');
          actions.showToast(`Insufficient: ${names}`);
          return;
      }

      if (!hasEnergy) {
          actions.triggerEnergyHighlight();
          actions.showToast("Not enough energy.");
          return;
      }

      if (selectedItem.craftingType === 'FORGE') {
          if (charcoalCount < quickCraftFuelCost) {
              actions.showToast(`Insufficient charcoal! Need ${quickCraftFuelCost} fuel.`);
              return;
          }
      }

      // Start Animation
      setQuickCraftProgress(0);
      const duration = 1500;
      const interval = 30;
      const step = (interval / duration) * 100;

      const timer = setInterval(() => {
          setQuickCraftProgress(prev => {
              if (prev === null || prev >= 100) {
                  clearInterval(timer);

                  // Perform Actual Crafting after animation
                  if (selectedItem.craftingType === 'FORGE') {
                      actions.consumeItem('charcoal', quickCraftFuelCost);
                  }

                  let quality = 50;
                  let masteryGain = 0.5;

                  if (masteryInfo.count >= MASTERY_THRESHOLDS.ARTISAN) {
                      quality = 95;
                      masteryGain = 1.0;
                  } else if (masteryInfo.count >= MASTERY_THRESHOLDS.ADEPT) {
                      quality = 75;
                      masteryGain = 0.7;
                  }

                  actions.startCrafting(selectedItem);
                  actions.finishCrafting(selectedItem, quality, 0, masteryGain);
                  return null;
              }
              return Math.min(100, prev + step);
          });
      }, interval);

  }, [selectedItem, masteryInfo, isRequirementMet, getInventoryCount, hasEnergy, actions, charcoalCount, quickCraftFuelCost, onNavigate]);

  const isQuickCraftAvailable = useMemo(() => {
    if (!selectedItem) return false;
    return (craftingMastery[selectedItem.id] || 0) > 0;
  }, [selectedItem, craftingMastery]);

  return (
    <div className="relative h-full w-full bg-stone-950 overflow-hidden" style={{ backgroundImage: `url(${getAssetUrl('tile_forge.png')})`, backgroundRepeat: 'repeat', backgroundBlendMode: 'multiply' }}>

        {isCrafting && selectedItem && (
            <div className="absolute inset-0 z-[100] bg-stone-950">
                {selectedItem.craftingType === 'FORGE' ? (
                    <SmithingMinigame 
                        onComplete={handleMinigameComplete}
                        onClose={cancelCrafting}
                        difficulty={selectedItem.tier}
                        isTutorial={tutorialStep === 'START_FORGING_GUIDE'}
                    />
                ) : (
                    <WorkbenchMinigame 
                        onComplete={handleMinigameComplete}
                        onClose={cancelCrafting}
                        difficulty={selectedItem.tier}
                        subCategoryId={selectedItem.subCategoryId}
                        itemImage={selectedItem.image}
                    />
                )}
            </div>
        )}

        {/* Quick Craft Progress Popup */}
        {quickCraftProgress !== null && (
