    baseCombatPower,
    nextCombatPower,
    showAffinityGain, 
    onUnequip, 
    onSlotClick,
    selectedSlot,
    isReadOnly
}: { 
    mercenary: Mercenary; 
    baseCombatPower: number; 
    nextCombatPower: number;
